-- Poems batch 326
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('fafe4e70-daf3-4cad-a538-b2f9ff2fc057','寄龔深父給事','陸佃','宋','宋诗','song-poetry','','[]','往歲手曾携，穿雲路欲迷。',48,'全唐诗/poet.song.52000.json','["往歲手曾携，穿雲路欲迷。", "蓬萊風引近，靈鷲月飛低。", "晝永棋相對，春深鳥自啼。", "別來真約在，何事少書題。"]'),
('e8aedc96-2ddd-44bf-9ccc-c2c65c9fe0fe','蘇丞相挽歌詞二首  其一','陸佃','宋','宋诗','song-poetry','','[]','樂易雖難老，艱難亦備更。',48,'全唐诗/poet.song.52000.json','["樂易雖難老，艱難亦備更。", "高官誰不死，厚德是平生。", "曾負阿衡鼎，仍調傅說羹。", "須知夷險異，高臥看南行。"]'),
('f117610c-ce16-4024-802b-16212514682c','蘇丞相挽歌詞二首  其二','陸佃','宋','宋诗','song-poetry','','[]','世德層層外，年齡九九餘。',48,'全唐诗/poet.song.52000.json','["世德層層外，年齡九九餘。", "浪傳千歲字，真記五車書。", "帳冷閒金鴨，泉深暗玉魚。", "前時傅巖像，今得幾分如。"]'),
('4933c34e-215a-48d8-a096-d2b25f01d428','鍾評事挽歌詞','陸佃','宋','宋诗','song-poetry','','[]','銀餠當年遇，金鉤幾代收。',48,'全唐诗/poet.song.52000.json','["銀餠當年遇，金鉤幾代收。", "一經知教子，千橘等封侯。", "瘴雨松門夕，悲風桂嶺秋。", "江深人不見，依舊水東流。"]'),
('6ef9b12b-9c85-4c62-b092-693514c8c269','馮朝奉挽歌詞','陸佃','宋','宋诗','song-poetry','','[]','仕宦惟遭遇，神仙信杳冥。',48,'全唐诗/poet.song.52000.json','["仕宦惟遭遇，神仙信杳冥。", "老年多感慨，同牓半凋零。", "附葬銘旌暗，平生信史青。", "須知玉川子，傳後有添丁。"]'),
('3c6939d2-4e49-4f60-b06a-af05d2fffff3','公議郎中挽歌詞','陸佃','宋','宋诗','song-poetry','','[]','愷悌雖平進，艱難亦備更。',48,'全唐诗/poet.song.52000.json','["愷悌雖平進，艱難亦備更。", "冰廳諳冷宦，夢境過浮生。", "雲海仙舟隔，風旌粉字橫。", "莫埋言行錄，留著後人行。"]'),
('87224f7e-91e1-4f5d-8952-7e633aefc82d','劉大卿挽歌詞','陸佃','宋','宋诗','song-poetry','','[]','許國丹心壯，傳家素節清。',48,'全唐诗/poet.song.52000.json','["許國丹心壯，傳家素節清。", "葬無金椀送，庭有玉棺迎。", "紅幕賓朋散，青囊宅兆成。", "惟餘原上月，猶是舊時明。"]'),
('8b175571-d195-4cfd-97a4-2a88bb1e23ad','陳夫人挽歌詞','陸佃','宋','宋诗','song-poetry','','[]','鄰與鄒人卜，門歸太史評。',48,'全唐诗/poet.song.52000.json','["鄰與鄒人卜，門歸太史評。", "忽隨雙佩失，不見一珠成。", "夢入清都杳，船維彼岸輕。", "空餘江上月，依舊度窗明。"]'),
('65a782f2-4a40-4848-baab-9aa128420bb9','魏國太夫人陳氏挽歌詞','陸佃','宋','宋诗','song-poetry','','[]','漏逐晨鐘盡，舟隨暮壑移。',48,'全唐诗/poet.song.52000.json','["漏逐晨鐘盡，舟隨暮壑移。", "文歸大家傳，行在小星詩。", "珠珮臨江失，金丹渡海遲。", "侍郎頭已白，兒慕不勝悲。"]'),
('1f9b93d6-f156-47a4-9ae2-905579d71291','贈慈覺大師','陸佃','宋','宋诗','song-poetry','','[]','講花天散墜，醉草客爭收。',48,'全唐诗/poet.song.52000.json','["講花天散墜，醉草客爭收。", "明月來相識，孤雲學自由。", "隙曛穿薄暮，簷溜滴高秋。", "不鎖西窗夢，名山有舊遊。"]'),
('f84f39f3-cfe5-423f-9266-297926d75053','贈李柔得道士','陸佃','宋','宋诗','song-poetry','','[]','傳得真人性，長安久卜居。',48,'全唐诗/poet.song.52000.json','["傳得真人性，長安久卜居。", "噀成西蜀雨，換得右軍書。", "酒散顛狂極，香消寂寞餘。", "更能盤礴畫，傳寫十分如。"]'),
('c4eb5705-1b83-4a3e-be4d-d8d025fe4258','再用前韵呈毅夫','陸佃','宋','宋诗','song-poetry','','[]','洛陽曾識面，穰下竟論交。',288,'全唐诗/poet.song.52000.json','["洛陽曾識面，穰下竟論交。", "久若居蘭室，初如食蔗梢。", "故非偷姓孔，誰敢僭名郊。", "作事常師古，當官肯代庖。", "匪躬期蹇蹇，夷行笑嘐嘐。", "稷也真堯力，參乎豈桀髇。", "金樓傳寶構，雜俎當珍肴。", "講舍推攸止，賓筵絕載呶。", "孫窗餘臘雪，徐榻臥寒茭。", "反舌宵鳴蟈，長踦暖挂蛸。", "即今除戶墐，那得曝簷茅。", "遠夢方隨蝶，輕綃擬換鮫。", "歷來雙鳳闕，律動半山坳。", "草色揉藍染，花名篆字鈔。", "膘肥熊自撲，香滿麝爭跑。", "乳雉翔仍集，鳴禽語漸勦。", "柳將金自比，楮與玉相淆。", "節應豳三日，陽添泰一爻。", "碧圓牽翠荇，紅蕾破香苞。", "鶑出求同志，鴻歸學共胞。", "形容當舞籥，音韵中笙匏。", "麗苑聞亡是，熙臺亞有巢。", "不材真是櫟，何算信如筲。", "交淡非同醴，流清豈爲膠。"]'),
('0023d856-d2cb-472f-9b61-c75835448b49','閒居示王君儀','陸佃','宋','宋诗','song-poetry','','[]','五色文章爛錦開，謾勞天女翦刀裁。',64,'全唐诗/poet.song.52000.json','["五色文章爛錦開，謾勞天女翦刀裁。", "黄鶑窺水亭亭立，白鳥投空遠遠來。", "清晝光陰輸靜客，碧雲岐路屬多才。", "羨君直入文滄海，探盡驪珠始肯迴。"]'),
('24ef26e3-fff4-4341-91a6-4020fd0b53bc','送諸張','陸佃','宋','宋诗','song-poetry','','[]','就學經年客會稽，父兄應久怪歸遲。',64,'全唐诗/poet.song.52000.json','["就學經年客會稽，父兄應久怪歸遲。", "故知子學優來日，想得人看勝舊時。", "食蔗已甘佳境近，爲山纔止素功虧。", "少年況有修身志，莫爲區區應舉移。"]'),
('cec588ee-5f82-480c-8d8c-f0cdda9e52ad','依韵和尚用之秀才梅花二首  其一','陸佃','宋','宋诗','song-poetry','','[]','假借鉛華素不曾，肯將桃李較衰榮。',64,'全唐诗/poet.song.52000.json','["假借鉛華素不曾，肯將桃李較衰榮。", "向人有意如相識，混雪無言恥自明。", "青帝信音元苦遠，素娥風調不勝清。", "愛君詩思誠高古，睥睨玄尊與太羹。"]'),
('13b71218-2dbf-4f4d-b121-b474fbe55fbc','依韵和尚用之秀才梅花二首  其二','陸佃','宋','宋诗','song-poetry','','[]','年年先發更誰曾，憔悴中間獨自榮。',64,'全唐诗/poet.song.52000.json','["年年先發更誰曾，憔悴中間獨自榮。", "素艷得如人淡佇，暗香能共雪分明。", "銀河魄轉霜風耐，青冢魂歸月夜清。", "莫與將軍輕止渴，須知丞相要調羹。"]'),
('865a1be7-91fb-45e1-8811-8a972ffca2bb','送能協','陸佃','宋','宋诗','song-poetry','','[]','禹門千尺晚登龍，稽古從來緩見功。',64,'全唐诗/poet.song.52000.json','["禹門千尺晚登龍，稽古從來緩見功。", "清節藴珠函柱白，高文浮蜃吐樓紅。", "落花正值行時盡，圓月還成別後同。", "寄字好憑魚上下，汴渠流水洛新通。"]'),
('ee0f894e-eee1-4648-b180-b412afedb0cd','呈越州程給事','陸佃','宋','宋诗','song-poetry','','[]','南海歸來請會稽，錦衣新過浙江西。',64,'全唐诗/poet.song.52000.json','["南海歸來請會稽，錦衣新過浙江西。", "暫違香案蓬萊小，久擅詩名太華低。", "花影欲重公事退，鳥聲初鬧吏衙齊。", "雲衢已怪朝天晚，乘興無因訪剡溪。"]'),
('7919690a-b55f-48b4-8853-fbd085da3c47','依韵和程給事留題法雲寺方丈','陸佃','宋','宋诗','song-poetry','','[]','浄室兼容海衆臨，維摩憔悴病仍侵。',64,'全唐诗/poet.song.52000.json','["浄室兼容海衆臨，維摩憔悴病仍侵。", "且將燈續光明藏，時見珠隨咳唾音。", "素壁短碑深掐玉，畫簷新牓大書金。", "故溪曾指桃花記，乘月何時更一尋。"]'),
('4ff5ed71-2bcb-4e98-8136-f4db58b8ddb6','題適南亭呈程給事二首  其一','陸佃','宋','宋诗','song-poetry','','[]','子真仙去學喬松，華宇經營得我公。',64,'全唐诗/poet.song.52000.json','["子真仙去學喬松，華宇經營得我公。", "海近蓬瀛全彷彿，山經樓閣半虛空。", "一千里地簷前月，九萬程天座上風。", "從此鑑中登望好，却應渾勝水晶宮。"]'),
('45d2bce9-6a8e-4798-92d2-bfe4b12d8b51','題適南亭呈程給事二首  其二','陸佃','宋','宋诗','song-poetry','','[]','參陪初見翦蒿萊，頃刻疏紅戶牖開。',64,'全唐诗/poet.song.52000.json','["參陪初見翦蒿萊，頃刻疏紅戶牖開。", "賀老湖光浮枕簟，梅家山色染樓臺。", "翠微已借雲根築，青瑣仍供月影來。", "聞說紫泥追詔近，使星躔次傍三台。"]'),
('e0a3097e-7d33-4f73-bf4f-3d0862633526','依韵重和再住法雲寺','陸佃','宋','宋诗','song-poetry','','[]','聞說重來住法雲，舊緣香火一番新。',64,'全唐诗/poet.song.52000.json','["聞說重來住法雲，舊緣香火一番新。", "桃花可認曾移主，鷗鳥還應不避人。", "腦玉幾陵虹氣勢，頷珠長借月精神。", "何時乞得東南守，共禮黄金丈六身。"]'),
('c620d99b-1df0-4746-87ff-3e6e91210511','贈真戒大師','陸佃','宋','宋诗','song-poetry','','[]','時訪城西長者家，欲將無定友烟霞。',64,'全唐诗/poet.song.52000.json','["時訪城西長者家，欲將無定友烟霞。", "百函貝葉聽揮麈，一炷爐香看點茶。", "猿立砌臺偷落果，鳥穿簷柏獻新花。", "舊曾題處煩師護，肯學常流旋碧紗。"]'),
('f85bfaf5-0390-4e51-82d3-d31c4f05388a','登塔望太行','陸佃','宋','宋诗','song-poetry','','[]','浮圖千尺俯樓臺，天地晴無一點埃。',64,'全唐诗/poet.song.52000.json','["浮圖千尺俯樓臺，天地晴無一點埃。", "日薄馬初經具次，風輕船稍近蓬萊。", "遷移曾費愚公力，分擘寧煩巨掌開。", "東北若無丘壟礙，好同靈鷲却飛來。"]'),
('bcc52b7d-e2eb-40f9-be41-c850e2950b77','依韵和彭器資直講二首  其一','陸佃','宋','宋诗','song-poetry','','[]','三年清苦下書帷，諸子專門盛一時。',64,'全唐诗/poet.song.52000.json','["三年清苦下書帷，諸子專門盛一時。", "研盡錦砂重注易，草殘饒紙謾箋詩。", "鼓催閩越茶應早，線引昭陽日漸遲。", "侍講會須拌共醉，狀元新約未差池。"]'),
('7e75cac1-e069-4780-bddf-b109ea20cdb1','依韵和彭器資直講二首  其二','陸佃','宋','宋诗','song-poetry','','[]','歸盡春風未得歸，相逢還是落花時。',64,'全唐诗/poet.song.52000.json','["歸盡春風未得歸，相逢還是落花時。", "文衡仔細誇程石，飲量粗豪笑滿巵。", "安穩鴛鴦多左翼，低回烏鵲尚南枝。", "稍尋前度曾遊處，更覺新懷慰舊思。"]'),
('52a111c3-e445-496f-bbe9-67f9e057245e','依韵和蕭惟申檢法同年','陸佃','宋','宋诗','song-poetry','','[]','老驥如龍久屈盤，追風消得用金鞍。',64,'全唐诗/poet.song.52000.json','["老驥如龍久屈盤，追風消得用金鞍。", "即今將相多同牓，自古神仙有法官。", "病起縱驚秋鬢改，詩成猶伴夜珠寒。", "他時直上三千里，願看雲天一整翰。"]'),
('90836f2e-7e59-40aa-95e1-36dcd746021b','門下王相公南郊謝雪子敏甫學士監禮楊傑有詩次其韵','陸佃','宋','宋诗','song-poetry','','[]','雪擁平田萬頃寬，一郊和氣屬天官。',64,'全唐诗/poet.song.52000.json','["雪擁平田萬頃寬，一郊和氣屬天官。", "撒鹽久欲資調鼎，成璧初疑捧上壇。", "雀带玉飛金屋煖，龍和珠睡錦窗寒。", "他年祠罷親陪燕，應得屏風隔坐觀。"]'),
('454ef839-c395-4131-8bb8-cf2c30429f84','依韵和元參政祈雨','陸佃','宋','宋诗','song-poetry','','[]','翦爪七年矜久旱，齋心三月愧疏雲。',64,'全唐诗/poet.song.52000.json','["翦爪七年矜久旱，齋心三月愧疏雲。", "地鍾潤澤來耕壠，天借清凉入繡紋。", "常膳鼎寒摇萐莆，正衙爐煖和蘭薰。", "越裳會見朝丹闕，共識中原有聖君。"]'),
('db176359-e34b-40c2-b3ef-9796326aca80','次韵和曾子固舍人二首  其一','陸佃','宋','宋诗','song-poetry','','[]','閶闔晨開玉殿浮，靈鼇不動海波柔。',64,'全唐诗/poet.song.52000.json','["閶闔晨開玉殿浮，靈鼇不動海波柔。", "是般仙果三千歲，一樣春風四百州。", "鸞扇影寒裁就月，蜃爐香煖結成樓。", "從今不顧瑶池宴，閒却西巡八駿騮。"]'),
('2a49d87a-d03a-4e62-9372-8bad939ded21','次韵和曾子固舍人二首  其二','陸佃','宋','宋诗','song-poetry','','[]','平明下馬錦蒙鞍，暫向飛廊一整冠。',64,'全唐诗/poet.song.52000.json','["平明下馬錦蒙鞍，暫向飛廊一整冠。", "行近柳陰移晝寂，坐來花氣辟春寒。", "別張翠幄黏絲絮，更想金人捧鏌干。", "洛下少年今亦老，宴遊無復似前歡。"]'),
('c5fc1dcc-0b0c-435d-ba91-3752ddd70245','資善堂御筵奉詔送陳資政出守邢州','陸佃','宋','宋诗','song-poetry','','[]','共輔龍飛與五蛇，一時恩禮有誰加。',64,'全唐诗/poet.song.52000.json','["共輔龍飛與五蛇，一時恩禮有誰加。", "華堂玉椀更傳酒，便殿金瓶獨賜茶。", "寶带光芒腰下印，繡衣形影幕中花。", "平生自與韓公合，名德應歸太史誇。"]'),
('c8b81d31-8201-4072-9e4b-7626d6e9395c','呈王聖美','陸佃','宋','宋诗','song-poetry','','[]','少談奇字客長安，妙斲無人得郢墁。',64,'全唐诗/poet.song.52000.json','["少談奇字客長安，妙斲無人得郢墁。", "兩鬢已秋陪後進，十年如夢守前官。", "竹延西角東須徧，梅發南枝北尚寒。", "從古晚成終大用，扶摇行見海鵬摶。"]'),
('9d608530-e953-486d-a768-cbd292742f5a','依韵和章樞密景靈宮奉安列聖神御','陸佃','宋','宋诗','song-poetry','','[]','綵輿同日會仙山，金鎖晨開玉殿關。',64,'全唐诗/poet.song.52000.json','["綵輿同日會仙山，金鎖晨開玉殿關。", "駕象法王趨側畔，騎龍真祖護中間。", "紫浮渭北衣冠氣，紅壓終南衮繡顔。", "更祝聖孫千萬壽，奉祠長御景靈班。"]'),
('c9f2dcc4-c879-44c2-9eac-6bbd1ac2ca95','依韵和曾子開舍人從駕孟饗景靈宮四首  其一','陸佃','宋','宋诗','song-poetry','','[]','汎灑從誇雨點勻，九天宮闕自無塵。',64,'全唐诗/poet.song.52000.json','["汎灑從誇雨點勻，九天宮闕自無塵。", "五更玉勒爭門入，十里珠簾夾道陳。", "薄宦即今雙鬢改，從官還是一番新。", "須知鸞駕重涓日，不似春秋四卜辛。"]'),
('99416844-8efb-47c5-8b23-6a184007543e','依韵和曾子開舍人從駕孟饗景靈宮四首  其二','陸佃','宋','宋诗','song-poetry','','[]','夏木陰清氣候勻，平明鸞仗簇芳塵。',64,'全唐诗/poet.song.52000.json','["夏木陰清氣候勻，平明鸞仗簇芳塵。", "百年禮樂傳宮注，萬國衣冠拱廟陳。", "紅芍藥開迎晝永，紫櫻桃熟奉時新。", "天街自不容生草，布屑由來枉用辛。"]'),
('304fdd4d-9d86-4f49-b432-70f401d635dd','依韵和曾子開舍人從駕孟饗景靈宮四首  其三','陸佃','宋','宋诗','song-poetry','','[]','三宮同日下雲萊，带曉千門萬戶開。',64,'全唐诗/poet.song.52000.json','["三宮同日下雲萊，带曉千門萬戶開。", "黄傘日隨清景駐，玉爐風度暗香來。", "眠當道路驅除柳，守得宮庭委付槐。", "亭午扇還新廟閟，紫雲重複護周迴。"]'),
('fd245a9f-0751-4f2b-9d48-12b16018aa9b','依韵和曾子開舍人從駕孟饗景靈宮四首  其四','陸佃','宋','宋诗','song-poetry','','[]','修廊圖畫列伊萊，金碧旁看啟佑開。',64,'全唐诗/poet.song.52000.json','["修廊圖畫列伊萊，金碧旁看啟佑開。", "山壓巨鼇初踴出，宮隨靈鷲忽飛來。", "瀟湘佇泣空留竹，海岳遙趨想畏槐。", "聞說都人爭擁道，鳳輿纔見第三迴。"]'),
('ea8d4c7e-6c68-4fe0-a2d7-074c14343c00','瓊林苑御筵奉詔送文太師致政歸西都四首  其一','陸佃','宋','宋诗','song-poetry','','[]','車後鵷鸞隨劍履，帳前貔虎擁旌旄。',64,'全唐诗/poet.song.52000.json','["車後鵷鸞隨劍履，帳前貔虎擁旌旄。", "星環紫極三階正，鼇立青天一柱高。", "上苑金杯新錫餞，下都銀鑰舊均勞。", "重來更捧宸章爛，華衮何如玉字褒。"]'),
('b5ca2854-0c06-4a33-9afe-97addaa44df0','瓊林苑御筵奉詔送文太師致政歸西都四首  其二','陸佃','宋','宋诗','song-poetry','','[]','黄鉞新兼兩鎮雄，至和前已冠三公。',64,'全唐诗/poet.song.52000.json','["黄鉞新兼兩鎮雄，至和前已冠三公。", "傳將名德蠻夷外，老却年華將相中。", "十雨燮成堯壤厚，五雲飛盡傅巖空。", "更聞定策刊彝鼎，千古英雄伏下風。"]'),
('be192723-695b-4c53-9362-4bd5b40c72c8','瓊林苑御筵奉詔送文太師致政歸西都四首  其三','陸佃','宋','宋诗','song-poetry','','[]','太師勳業在丹書，乞得身歸主眷殊。',64,'全唐诗/poet.song.52000.json','["太師勳業在丹書，乞得身歸主眷殊。", "五色詔容瞻鳳闕，白雲篇不換蛇珠。", "閒應物外神仙有，健復人間將相無。", "明夜畫船回首處，汴隄烟月柳千株。"]'),
('6fe25c96-586b-4a28-a776-7138d874775d','瓊林苑御筵奉詔送文太師致政歸西都四首  其四','陸佃','宋','宋诗','song-poetry','','[]','黄金曾酌御尊餘，恩禮何人更得如。',64,'全唐诗/poet.song.52000.json','["黄金曾酌御尊餘，恩禮何人更得如。", "北極星辰趨觀闕，西京花木臥田廬。", "手持宸翰春羅馥，身入仙壺晝景舒。", "八十爲師精力在，太公應愧齒先疏。"]'),
('2dd1ec75-0baf-40c5-9aed-3f77d6a0156c','興龍節口號  其一','陸佃','宋','宋诗','song-poetry','','[]','祥雲好色近蓬萊，列辟稱觴廣殿開。',64,'全唐诗/poet.song.52000.json','["祥雲好色近蓬萊，列辟稱觴廣殿開。", "樂奏九成丹鳳降，香焚百和玉龍來。", "三農臘雪方呈瑞，萬國春風已暗迴。", "共祝聖君千萬壽，年年長奉白雲杯。"]'),
('7f96b270-a870-479d-a096-628d266bddf2','興龍節口號  其二','陸佃','宋','宋诗','song-poetry','','[]','興龍嘉節會簪纓，步武蹌蹌鷺集庭。',64,'全唐诗/poet.song.52000.json','["興龍嘉節會簪纓，步武蹌蹌鷺集庭。", "拜笏競從花外見，仙歌疑是夢中聽。", "升平聖世真難遇，醉飽君恩敢獨醒。", "同望闕庭稱萬壽，慶雲中見老人星。"]'),
('6078582f-bcf9-4705-874b-db5413af4573','依韵和王微之學士','陸佃','宋','宋诗','song-poetry','','[]','坐籌國事尚才堪，屈指同年祇二三。',64,'全唐诗/poet.song.52000.json','["坐籌國事尚才堪，屈指同年祇二三。", "平昔醉鄉營別業，如今仙籍換頭銜。", "光陰老去猶能惜，世事閒來不更談。", "聞說進書歸祕閣，絕勝流落在山巖。"]'),
('afec6579-6583-47e1-9cc0-8c94a921caab','爾雅新義成查許國以詩見惠依韵答之二首  其一','陸佃','宋','宋诗','song-poetry','','[]','背未成鮐齒未鯢，暫時來放五雲低。',64,'全唐诗/poet.song.52000.json','["背未成鮐齒未鯢，暫時來放五雲低。", "初從荆國猶年少，久侍神皇見日躋。", "近正鉛黄新眼目，指南塵土舊輪蹄。", "愛君文采真難敵，他日橫空是紫霓。"]'),
('c263acc2-e665-4acf-b77b-5a85b444f075','爾雅新義成查許國以詩見惠依韵答之二首  其二','陸佃','宋','宋诗','song-poetry','','[]','探盡驪龍鑿盡鯢，明珠未出價猶低。',64,'全唐诗/poet.song.52000.json','["探盡驪龍鑿盡鯢，明珠未出價猶低。", "晉人已覺蟛蜞誤，漢客仍從豹鼠躋。", "到底錯薪須刈楚，從來得兔要忘蹄。", "他時若綴三經後，五色雲中有紫霓。"]'),
('a6244fb6-4c8e-444b-80f4-8b393f4fef07','戲和鄭通叔仲春晨起','陸佃','宋','宋诗','song-poetry','','[]','春來燕姹復鶑嬌，不飲喉咽頓覺焦。',64,'全唐诗/poet.song.52000.json','["春來燕姹復鶑嬌，不飲喉咽頓覺焦。", "桃被臉深將露洗，柳綠腰細得風饒。", "船中載酒猶嫌少，席上看花每恨遙。", "可惜襄王今老矣，不堪雲雨夢朝朝。"]'),
('b58efc1b-d207-49a8-9bfc-096f5a80bca3','送文太師再致政歸西都二首  其一','陸佃','宋','宋诗','song-poetry','','[]','太師天賦與人殊，除却汾陽盡不如。',64,'全唐诗/poet.song.52000.json','["太師天賦與人殊，除却汾陽盡不如。", "萬乘有時前膝席，百官隨處避肩輿。", "鉅公多出陶鎔後，重事仍歸議論餘。", "聞說挂冠恩寵厚，恨無官職可教除。"]'),
('3467aa24-0fc9-4bda-b8fb-db17e9f3b7d0','送文太師再致政歸西都二首  其二','陸佃','宋','宋诗','song-poetry','','[]','乞身章疏竟難移，雙鎮辭來亦重違。',64,'全唐诗/poet.song.52000.json','["乞身章疏竟難移，雙鎮辭來亦重違。", "絕域共驚吾父在，別都今喜我公歸。", "渭川士宦相先後，遼海人民半是非。", "誰念昔曾陪祖帳，同時賓客坐中稀。"]'),
('fe0833f4-05d0-4baf-b1e3-7a52015c9144','依韵和呈劉貢父舍人三首  其一','陸佃','宋','宋诗','song-poetry','','[]','鵷鷺朝來又集西，聯鑣初卸錦障泥。',64,'全唐诗/poet.song.52000.json','["鵷鷺朝來又集西，聯鑣初卸錦障泥。", "奪袍况有詩先捷，倒玉何妨酒屢携。", "詔下競看花作判，賦成曾借柳爲題。", "衣冠異日傳圖畫，惟有三家盛事齊。"]'),
('8b408ac9-d8f9-45a8-90cf-ed2d2f367041','依韵和呈劉貢父舍人三首  其二','陸佃','宋','宋诗','song-poetry','','[]','酒半詩成日轉西，驪珠纔抵一丸泥。',64,'全唐诗/poet.song.52000.json','["酒半詩成日轉西，驪珠纔抵一丸泥。", "未饒白雪無人和，不忿東山有妓携。", "班綴定應連玉筍，姓名還得夢金題。", "飛騰便見新官上，傳語花開慎莫齊。"]'),
('d0adee28-d74d-4bf2-a5db-133af064adaf','依韵和呈劉貢父舍人三首  其三','陸佃','宋','宋诗','song-poetry','','[]','三家成佛本來西，共坐蓮胎出淤泥。',64,'全唐诗/poet.song.52000.json','["三家成佛本來西，共坐蓮胎出淤泥。", "歸侍玉除還似約，去腰金印定如携。", "慇懃鳥勸花前醉，邂逅人逢葉上題。", "縱有鳳毛傳序遠，未應能似雁行齊。"]'),
('70b2bd39-aaa5-4aee-ac86-b3c691b0217f','用前韵呈蘇子容尚書','陸佃','宋','宋诗','song-poetry','','[]','顰里從來敢效西，龍門登日尚雲泥。',64,'全唐诗/poet.song.52000.json','["顰里從來敢效西，龍門登日尚雲泥。", "紫垣正掌絲綸美，絳帳初將杖屨携。", "紅錦未酬青玉案，黄金應護碧紗題。", "正堂若許曹參避，願更虛心問相齊。"]'),
('9e642724-e5d4-4f2d-a290-e969639e5de1','依韵和頓起郎中瓊林苑奉迎神主追懷同年兼呈座主蘇丞相','陸佃','宋','宋诗','song-poetry','','[]','清風明月本閒人，鳳闕初來一幅巾。',64,'全唐诗/poet.song.52000.json','["清風明月本閒人，鳳闕初來一幅巾。", "淡墨姓名才烜赫，橫金班綴偶叨塵。", "鼎湖龍去池臺古，遼海人歸冢墓新。", "惟有蘇家老仙樹，能將五百歲爲春。"]'),
('ec665f14-c79c-4009-8cd2-848562ac7eed','送楊損赴黄陂主簿','陸佃','宋','宋诗','song-poetry','','[]','詩酒相從祇歲餘，雲樓鳳閣在空虛。',64,'全唐诗/poet.song.52000.json','["詩酒相從祇歲餘，雲樓鳳閣在空虛。", "驪龍光燄隨尊俎，鸞鳳精神入簿書。", "內翰風流知有後，狀元門閥是當初。", "恨無一物堪持贈，梅未全開柳尚疏。"]'),
('484fa601-3baf-4796-94ac-70725957a101','送虞太熙學士知太平州','陸佃','宋','宋诗','song-poetry','','[]','黄塵初出國門東，楊柳青青畫隼紅。',64,'全唐诗/poet.song.52000.json','["黄塵初出國門東，楊柳青青畫隼紅。", "占得度關雲色異，想知登望月明同。", "曾傳嚼蠟風情外，更悟烹鮮政事中。", "聞說太平迎候遠，安排騎竹有兒童。"]'),
('97741804-4db7-40f8-9580-a553ba95b01f','送致政邢定國通判','陸佃','宋','宋诗','song-poetry','','[]','七十平頭便拂衣，舞雩風月有光輝。',64,'全唐诗/poet.song.52000.json','["七十平頭便拂衣，舞雩風月有光輝。", "尋常薄飯猶能足，多少高官未肯歸。", "鷗鳥等閒還自樂，杜鵑容易重相違。", "想知遼鶴歸來早，城郭人民未盡非。"]'),
('07cbee1a-4d21-4fc5-95cc-579bc29eebae','圓石','陸佃','宋','宋诗','song-poetry','','[]','蒼仞千尋畫不如，信知韞玉勝懷珠。',64,'全唐诗/poet.song.52000.json','["蒼仞千尋畫不如，信知韞玉勝懷珠。", "一卷會使民瞻峻，三品何妨主眷殊。", "看日謬煩鞭氣力，補天真待鍊工夫。", "寄聲欲取黄金印，雨後還曾墮鵲無。"]'),
('8acce998-9f66-41f7-a267-5b7b54caa69c','送張頡待制帥瀛州','陸佃','宋','宋诗','song-poetry','','[]','食貨方艱不忍籠，長才宜有濟時功。',64,'全唐诗/poet.song.52000.json','["食貨方艱不忍籠，長才宜有濟時功。", "閣當龍馬圖書後，錢入紅牙算子中。", "音信定應隨朔雁，夢魂多擬託南風。", "如何更講黄河策，定取橫流副兩宮。"]'),
('dbc766b6-4929-4fc9-b59c-a28ced187e2a','送許遵少卿知潤州','陸佃','宋','宋诗','song-poetry','','[]','丹陽太守舊名卿，騎竹兒童夾道迎。',64,'全唐诗/poet.song.52000.json','["丹陽太守舊名卿，騎竹兒童夾道迎。", "醉尹笙歌甘酒病，謫仙風月苦詩情。", "江湖天氣農桑早，水竹人家枕簟清。", "白首愛君心未已，夢魂猶遶鳳凰城。"]'),
('2ae5b157-c3db-4fe1-9fea-36faecf8dda3','題海岳樓贈米元章','陸佃','宋','宋诗','song-poetry','','[]','千級仙梯第一層，闌干常爲水雲凭。',64,'全唐诗/poet.song.52000.json','["千級仙梯第一層，闌干常爲水雲凭。", "起爲霖雨從膚寸，活得魚龍用斗升。", "鵬有程途知可到，鼇非番次信難勝。", "即今姓米仙人住，雲母中間一片冰。"]'),
('4357b4a7-f295-4d45-8c64-b34523be0eb8','依韵和青州程給事見寄','陸佃','宋','宋诗','song-poetry','','[]','出守東州異故園，臨岐花鳥共無言。',64,'全唐诗/poet.song.52000.json','["出守東州異故園，臨岐花鳥共無言。", "度關有客占雲氣，夐野何人肖夢魂。", "蘭辟白蟫書殿祕，茅分青土社壝尊。", "相望幾直蓬萊宿，燈影寒籠月滿軒。"]'),
('4573c38a-a8f0-4bfc-b525-d3f687100fca','送王柄教授','陸佃','宋','宋诗','song-poetry','','[]','場屋論才昔議魁，教庠官冷尚低徊。',64,'全唐诗/poet.song.52000.json','["場屋論才昔議魁，教庠官冷尚低徊。", "靈龜縮甲專藏六，老雉斜冠怯應媒。", "半醉珠璣隨咳唾，一方桃李待栽培。", "塞垣錯莫風沙晚，南北相望首重回。"]'),
('78ecc150-34dc-4b1a-a0da-bc6eb9173d88','和巖老','陸佃','宋','宋诗','song-poetry','','[]','遭遇何人更得如，同時幾許待公車。',64,'全唐诗/poet.song.52000.json','["遭遇何人更得如，同時幾許待公車。", "官清自可看奇字，俸薄猶能寫異書。", "千里水雲藏舊隠，一番雷雨報新除。", "自憐霄漢華塗穩，鴻雁橫飛序尚疏。"]'),
('7977cfa1-a4cf-4c98-9f26-b0111736d596','依韵和查應辰朝散雪二首  其一','陸佃','宋','宋诗','song-poetry','','[]','三陽新已換三陰，潤澤才踰一寸深。',64,'全唐诗/poet.song.52000.json','["三陽新已換三陰，潤澤才踰一寸深。", "無地得施調國手，惟天知有愛民心。", "霜毛一半渾如雪，玉貌諸餘少似今。", "且向尊前盡情醉，不須辛苦問爲霖。"]'),
('e66d28b1-e9a5-426e-8752-d0c927ced947','依韵和查應辰朝散雪二首  其二','陸佃','宋','宋诗','song-poetry','','[]','抱甕何人似漢陰，一番膏潤及根深。',64,'全唐诗/poet.song.52000.json','["抱甕何人似漢陰，一番膏潤及根深。", "稍蘇南畝耕耘力，甫逼東君造化心。", "堪畫不應須到晚，可收除是趁如今。", "寶陀若更施餘力，豈獨坊名揭望霖。"]'),
('7fa967f3-948c-4524-a9a9-840e46155211','依韵和蔣津雪中見寄','陸佃','宋','宋诗','song-poetry','','[]','蓬萊宮闕鎖崔嵬，書史頻看祇亂堆。',64,'全唐诗/poet.song.52000.json','["蓬萊宮闕鎖崔嵬，書史頻看祇亂堆。", "華蓋稍瞻天北極，紫雲曾識道東來。", "功名方與英豪共，懷抱仍逢故舊開。", "造物爲君如有意，一番風雪洗浮埃。"]'),
('42a661ed-72f0-4018-977d-0d9ae0b8f134','答張朝奉二首  其一','陸佃','宋','宋诗','song-poetry','','[]','太公年甲伯夷清，早早休官樂盛明。',64,'全唐诗/poet.song.52000.json','["太公年甲伯夷清，早早休官樂盛明。", "西子橫陳花一徑，北窗高臥稻千城。", "喜聞客去如多病，老見春歸似薄情。", "曾向先師得門戶，不知何日煉丹成。"]'),
('d1748252-9d70-4b36-b55c-33582b89ec43','答張朝奉二首  其二','陸佃','宋','宋诗','song-poetry','','[]','一番相見一番清，坐久精神轉更明。',64,'全唐诗/poet.song.52000.json','["一番相見一番清，坐久精神轉更明。", "詩裏欲投亡命社，酒邊甘在受降城。", "此身到處堪乘興，萬事由來枉用情。", "試問仙翁多少壽，定應三度見桃成。"]'),
('1f8b9061-0cbe-4fb8-9702-34e24ca954e4','依韵和羅畸學錄','陸佃','宋','宋诗','song-poetry','','[]','一番驚雷一番風，巨魚看得化爲龍。',64,'全唐诗/poet.song.52000.json','["一番驚雷一番風，巨魚看得化爲龍。", "銷殘白日書千卷，付與浮雲祿萬鍾。", "珠玉貫穿成把握，星辰羅絡在心胸。", "怪來佳句清人骨，正值溪寒雪滿峰。"]'),
('90adc257-da71-4b9e-b805-80e717c92869','呈周承議兼簡通判簽判二首  其一','陸佃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','政事相傳舊有經，爲州前後半台星。',64,'全唐诗/poet.song.52000.json','["政事相傳舊有經，爲州前後半台星。", "歲教諸縣無公事，雨使佳人上使廳。", "太守未甘雙鬢白，西湖惟欠遠山青。", "經過況有風騷將，乞取篇章作畫屏。"]'),
('140c4046-e55d-40f7-a1b2-c3fc00cc489c','呈周承議兼簡通判簽判二首  其二','陸佃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','下車明日燕西湖，醉倚高花不用扶。',64,'全唐诗/poet.song.52000.json','["下車明日燕西湖，醉倚高花不用扶。", "鷗鳥便應知我意，海棠今復恨公無。", "佳人舞罷頭纏錦，座客詩成咳有珠。", "聖主若容長守此，不妨生就白髭鬚。"]'),
('cfd0e1d2-7793-4b3f-897b-14e77093b95d','呈幕府諸公','陸佃','宋','宋诗','song-poetry','','[]','十年騎馬困京塵，乞得州來潁水濱。',64,'全唐诗/poet.song.52000.json','["十年騎馬困京塵，乞得州來潁水濱。", "苔蘚滿庭無字押，蓮花全幕是詩人。", "樓臺雪後如聞雨，歌舞尊前祇看春。", "半刺會須拌共醉，銀條方共德爭醇。"]'),
('e772e003-f4bf-4e19-9300-3eb62481eac0','宴西湖用前韵呈諸公','陸佃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','十頃湖光辟盡塵，女郎臺榭占沙濱。',64,'全唐诗/poet.song.52000.json','["十頃湖光辟盡塵，女郎臺榭占沙濱。", "杜鵑言語瞋爲客，楊柳腰肢瘦似人。", "便擬曲留今夜月，已知虛度去年春。", "憑君爲伴花前醉，況復香醪特地醇。"]'),
('e95d87e2-c2d2-43b4-966a-f8fdf92a785b','依韵和再開芍藥十六首  其一','陸佃','宋','宋诗','song-poetry','','[]','同時幾許已成空，回首榮枯是夢中。',64,'全唐诗/poet.song.52000.json','["同時幾許已成空，回首榮枯是夢中。", "自昔一般稱國艷，而今兩度嫁春風。", "誰人與刻三年葉，何事惟開十日紅。", "試倚玉梯丹漢外，爲渠方便問元功。"]'),
('46f43fa9-2e08-4090-b3d6-258fbf013ada','依韵和再開芍藥十六首  其二','陸佃','宋','宋诗','song-poetry','','[]','百花羞縮敢爭先，雨露仍隨愛惜偏。',64,'全唐诗/poet.song.52000.json','["百花羞縮敢爭先，雨露仍隨愛惜偏。", "青帝擬教春一見，素娥留待月重圓。", "相逢可惜非三月，自歎無因更少年。", "終日倚闌看不足，直須風雨送歸天。"]'),
('ea188f08-049d-45d7-8000-ee2e19c3273d','依韵和再開芍藥十六首  其三','陸佃','宋','宋诗','song-poetry','','[]','前來樓子妙凌空，若比今生是下中。',64,'全唐诗/poet.song.52000.json','["前來樓子妙凌空，若比今生是下中。", "曾與阿衡調鼎鉉，擬教周昉畫屏風。", "再生檜老無多綠，四季花凡一餉紅。", "認得洛陽人未識，信知天地有奇功。"]'),
('6a55e4bc-ab78-4b48-b469-948279183fa2','依韵和再開芍藥十六首  其四','陸佃','宋','宋诗','song-poetry','','[]','祇受姚黄一著先，兒家元在郡西偏。',64,'全唐诗/poet.song.52000.json','["祇受姚黄一著先，兒家元在郡西偏。", "解殘珠佩迎新見，尋得金鐶依舊圓。", "一過馨香猶半日，再來期約本明年。", "向人自有凌雲意，不羨城南尺五天。"]'),
('43644d27-d1d6-4c07-9680-eafab1345cd4','依韵和再開芍藥十六首  其五','陸佃','宋','宋诗','song-poetry','','[]','市井初傳爲一空，直疑伊洛謾當中。',64,'全唐诗/poet.song.52000.json','["市井初傳爲一空，直疑伊洛謾當中。", "別承仙掌非時露，剩占薰弦幾日風。", "自愧霜髭難更黑，誰憐粉面不長紅。", "豈惟畫史愁傳貌，兼使詩人費盡功。"]'),
('4fe742f5-1486-47e9-a0f4-b9b7ef5ed0b3','依韵和再開芍藥十六首  其六','陸佃','宋','宋诗','song-poetry','','[]','一番風信作花先，未必春工會黨偏。',64,'全唐诗/poet.song.52000.json','["一番風信作花先，未必春工會黨偏。", "玉杵買來容再睹，金釵分與却重圓。", "幾回衆裏知誰似，一墮人間有幾年。", "我是玉皇香案吏，可能相與便朝天。"]'),
('ad23c56a-187d-4291-b446-4b0f1e157633','依韵和再開芍藥十六首  其七','陸佃','宋','宋诗','song-poetry','','[]','十方生滅盡虛空，往往看花似醉中。',64,'全唐诗/poet.song.52000.json','["十方生滅盡虛空，往往看花似醉中。", "再見傾城彌愛日，一聞絕代競趨風。", "不知世逐仙棋換，未免身歸爝火紅。", "自斷此生真夢幻，直須成佛是殊功。"]'),
('361882b9-132f-4204-a8bb-89de6e2fed10','依韵和再開芍藥十六首  其八','陸佃','宋','宋诗','song-poetry','','[]','牡丹猶自欲推先，傳語諸花莫恨偏。',64,'全唐诗/poet.song.52000.json','["牡丹猶自欲推先，傳語諸花莫恨偏。", "淚眼始看金谷墜，指環尋伴玉簫圓。", "此身那復思前事，半面猶應記往年。", "畢竟得歸歸甚處，玉樓深在九重天。"]'),
('9442be61-34d7-4a33-9f77-51a205368068','依韵和再開芍藥十六首  其九','陸佃','宋','宋诗','song-poetry','','[]','誰言見慣是司空，舊說揚州未必中。',64,'全唐诗/poet.song.52000.json','["誰言見慣是司空，舊說揚州未必中。", "可是兩三千處月，能如二十五般風。", "依稀仙帳魂今返，遭遇神針肉更紅。", "却得蓬蒿遮蔽力，便教重見太平功。"]'),
('72037cd7-c1ef-4843-bbb6-c8f0c1669ed5','依韵和再開芍藥十六首  其一○','陸佃','宋','宋诗','song-poetry','','[]','詩成贏得錦袍先，自是高才遣將偏。',64,'全唐诗/poet.song.52000.json','["詩成贏得錦袍先，自是高才遣將偏。", "稀遇仙丹時下熟，荐驚神女夢中圓。", "丹梯直上三千級，間氣于今五百年。", "爲報百花休暗恨，便開三度也由天。"]'),
('0c6a0bc2-f745-4fc1-9207-05c570f95696','依韵和再開芍藥十六首  其一一','陸佃','宋','宋诗','song-poetry','','[]','春歸岑寂厭書空，頼爾相陪酒屢中。',64,'全唐诗/poet.song.52000.json','["春歸岑寂厭書空，頼爾相陪酒屢中。", "未必前身非叔子，不應後至似防風。", "賭留坐客排雙陸，借與都人畫二紅。", "須信年芳有虛發，莫教楊柳誤前功。"]'),
('ba0e54b3-dec3-48e9-afb5-0471edcc69d9','依韵和再開芍藥十六首  其一二','陸佃','宋','宋诗','song-poetry','','[]','阿誰蓮步擬攙先，相見從他次數偏。',64,'全唐诗/poet.song.52000.json','["阿誰蓮步擬攙先，相見從他次數偏。", "曾學駐顔知藥喜，免教渝約問蓍圓。", "春風省識非平日，昏霧中看類老年。", "聞說上林今更好，一如堯禹舊時天。"]'),
('f1ff8fe9-3296-43ce-b415-7409c52fc26d','依韵和再開芍藥十六首  其一三','陸佃','宋','宋诗','song-poetry','','[]','來時賓客正談空，更值僧齋飯一中。',64,'全唐诗/poet.song.52000.json','["來時賓客正談空，更值僧齋飯一中。", "便擬商量歸慧日，豫傳消息與香風。", "夏蠶三葉空餘綠，秋木重花祇浪紅。", "惟有此花花與子，兩曾相見是神功。"]'),
('290c84da-274c-4b6d-88d6-ffe0cae7f2cb','依韵和再開芍藥十六首  其一四','陸佃','宋','宋诗','song-poetry','','[]','姿貌新來勝日先，託根何事得州偏。',64,'全唐诗/poet.song.52000.json','["姿貌新來勝日先，託根何事得州偏。", "起將玉骨靈符異，分出金身覺性圓。", "如不能言常竟日，似曾相識是今年。", "也應解笑山茶晚，長占東南小雪天。"]'),
('ae31e0b1-ac84-4e56-a0b7-cd18bab5e462','依韵和再開芍藥十六首  其一五','陸佃','宋','宋诗','song-poetry','','[]','諸縣豐登獄屢空，珍祥如欲助升中。',64,'全唐诗/poet.song.52000.json','["諸縣豐登獄屢空，珍祥如欲助升中。", "不妨故故留連月，未到頻頻惱亂風。", "向上鬰葱佳氣紫，現前圓滿報身紅。", "自今長許汾陽醉，內外曾無緦少功。"]'),
('57d64df0-515d-4b52-bac8-ba1a5e26fae1','依韵和再開芍藥十六首  其一六','陸佃','宋','宋诗','song-poetry','','[]','發居衆後摘居先，玉色無端稟賦偏。',64,'全唐诗/poet.song.52000.json','["發居衆後摘居先，玉色無端稟賦偏。", "華表却歸仙夢遠，寶陀重現瑞光圓。", "少師花譜三千字，吏部春詩二百年。", "兩處偶然渾忘却，不須惆悵對炎天。"]'),
('c4796bf7-e8af-4511-8552-d8f732314810','依韵和雙頭芍藥十六首  其一','陸佃','宋','宋诗','song-poetry','','[]','品格由來自出羣，就中相並轉驚人。',64,'全唐诗/poet.song.52000.json','["品格由來自出羣，就中相並轉驚人。", "且同藥使求民瘼，終與花王秉國均。", "李廣無雙空自老，崔徽有兩竟誰真。", "因君翦寄和詩看，始信人間別有春。"]'),
('84b50e31-26fd-43c7-b558-3b09c4ef0ea5','依韵和雙頭芍藥十六首  其二','陸佃','宋','宋诗','song-poetry','','[]','怕草侵陵爲翦除，新詩應笑病尚書。',64,'全唐诗/poet.song.52000.json','["怕草侵陵爲翦除，新詩應笑病尚書。", "瀟湘烟水愁相對，巫峽雲山欲獨居。", "有客彈冠連茹進，誰家高髻合歡梳。", "年來太守雖加老，爲爾情懷亦自如。"]'),
('f4a0c3e9-1fea-47d5-91f8-4e88897215b2','依韵和雙頭芍藥十六首  其三','陸佃','宋','宋诗','song-poetry','','[]','不與尋常草木羣，看來端的好予人。',64,'全唐诗/poet.song.52000.json','["不與尋常草木羣，看來端的好予人。", "神仙比並容顔似，姊妹推排次第均。", "浮薄未應隨世態，靚妝渾似任天真。", "得他和氣知多少，占盡河陽一縣春。"]'),
('a8cc7f24-124f-479e-ba28-ac58480a5106','依韵和雙頭芍藥十六首  其四','陸佃','宋','宋诗','song-poetry','','[]','曾與宮花傍玉除，芳名消得用金書。',64,'全唐诗/poet.song.52000.json','["曾與宮花傍玉除，芳名消得用金書。", "已教莊蝶雙雙引，更伴台星兩兩居。", "官樣自應能笑語，家常誰欲傚妝梳。", "大都好物難摹寫，未信屏風畫得如。"]'),
('e4c40e41-0f50-4577-b0ab-e37ce115a264','依韵和雙頭芍藥十六首  其五','陸佃','宋','宋诗','song-poetry','','[]','白也雖云思不羣，賦君猶有調高人。',64,'全唐诗/poet.song.52000.json','["白也雖云思不羣，賦君猶有調高人。", "更相汲引風流在，各自芳菲雨露均。", "因藥封王誰是假，與花爲后自應真。", "思量消得黄金屋，回首戎葵也是春。"]'),
('31a83baa-4d72-4c5b-bf17-b10f63f101fc','依韵和雙頭芍藥十六首  其六','陸佃','宋','宋诗','song-poetry','','[]','誰捋花譜更刪除，妙品須教末上書。',64,'全唐诗/poet.song.52000.json','["誰捋花譜更刪除，妙品須教末上書。", "未必楚王曾夢見，祇應青女解孀居。", "行雲莫向中問度，新月纔成一半梳。", "若使覺王今識汝，蓮花寧復並真如。"]'),
('b38c37b1-4503-43b9-b581-f6866050fe32','依韵和雙頭芍藥十六首  其七','陸佃','宋','宋诗','song-poetry','','[]','並驂鸞鶴下珍羣，爲愛詩人不避人。',64,'全唐诗/poet.song.52000.json','["並驂鸞鶴下珍羣，爲愛詩人不避人。", "半醉奈何非李白，獨醒愁殺是靈均。", "空花在處黏成妄，草木何時鍊得真。", "顧我無心爭彼此，即今開落任青春。"]'),
('a3c4ffd2-1d29-47f2-ad1f-07270d442b0b','依韵和雙頭芍藥十六首  其八','陸佃','宋','宋诗','song-poetry','','[]','盡日經營對廣除，旁邊奴婢亦詩書。',64,'全唐诗/poet.song.52000.json','["盡日經營對廣除，旁邊奴婢亦詩書。", "俱飛蛺蜨渾相學，共戲鞦韆祇並居。", "說著定應成膾炙，買栽真是置篦梳。", "更嫌病眼無憑據，細看元來玉不如。"]'),
('d0dcd936-0f80-40c7-bf2d-73ac3fc01058','依韵和雙頭芍藥十六首  其九','陸佃','宋','宋诗','song-poetry','','[]','一經瞻顧遂空羣，疑是同時解佩人。',64,'全唐诗/poet.song.52000.json','["一經瞻顧遂空羣，疑是同時解佩人。", "曾對絲綸當禁掖，終隨弦誦到成均。", "有如一夢邯鄲假，未始相離渾沌真。", "可怪滿城尋國艷，不知花在此中春。"]'),
('e0bc3499-c6b4-4377-93d3-38c387debfc2','依韵和雙頭芍藥十六首  其一○','陸佃','宋','宋诗','song-poetry','','[]','玉顔高並向階除，靜笑寒藤學草書。',64,'全唐诗/poet.song.52000.json','["玉顔高並向階除，靜笑寒藤學草書。", "未信東君無職事，不慚西子是鄰居。", "曾教王母藏青鳥，擬問嫦娥借玉梳。", "尊得花王威勢重，也應知慕藺相如。"]'),
('fbfa14ff-f8ce-45d9-867a-655360e45fc2','依韵和雙頭芍藥十六首  其一一','陸佃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','共拋花縣暫離羣，聊伴西湖地主人。',64,'全唐诗/poet.song.52000.json','["共拋花縣暫離羣，聊伴西湖地主人。", "艷粉兩應歸藻繪，香泥俱合在陶均。", "雄風爲借吹噓力，雌霓叨蒙激賞真。", "移在洞天深處種，與誰同見八千春。"]'),
('2b5a66ea-b3fb-49d6-9b6d-cd16c860d41b','依韵和雙頭芍藥十六首  其一二','陸佃','宋','宋诗','song-poetry','','[]','幾時詩債許蠲除，直待金雞放赦書。',64,'全唐诗/poet.song.52000.json','["幾時詩債許蠲除，直待金雞放赦書。", "神峽自來雲一片，仙山多是玉羣居。", "祇緣貌類欣臨鏡，却爲情親忘見梳。", "不怕飛泥侵妙質，吾家斤斧正風如。"]'),
('e93eb781-05e6-495d-b345-7312a81d1f1b','依韵和雙頭芍藥十六首  其一三','陸佃','宋','宋诗','song-poetry','','[]','神仙流品信難羣，絕似人間兩麗人。',64,'全唐诗/poet.song.52000.json','["神仙流品信難羣，絕似人間兩麗人。", "暫得借觀猶占久，便教偷戴也分均。", "祇邀竹葉相爲伴，更對菱花自寫真。", "開向夏天緣底事，算來多是不宜春。"]'),
('738b2140-0357-403f-ae55-11bfbd338c65','依韵和雙頭芍藥十六首  其一四','陸佃','宋','宋诗','song-poetry','','[]','桃茢無堪謾祓除，芭蕉何事倒抽書。',64,'全唐诗/poet.song.52000.json','["桃茢無堪謾祓除，芭蕉何事倒抽書。", "鳳凰騎罷猶輕舉，烏鵲橋成得燕居。", "抵死勸持雕玉盞，象生描在鏤金梳。", "當時若使閼氏見，未怕平城刻得如。"]'),
('ff817f69-33da-4c56-8148-9cad6c1c1980','依韵和雙頭芍藥十六首  其一五','陸佃','宋','宋诗','song-poetry','','[]','晚菘早韭謾連羣，過眼終無愛惜人。',64,'全唐诗/poet.song.52000.json','["晚菘早韭謾連羣，過眼終無愛惜人。", "照日舞鸞情款曲，趁風飛燕勢停均。", "名歸本草千方祕，職在司花一命真。", "回首鳳凰城闕下，倩誰移與後園春。"]'),
('d5fae7c7-d76d-4534-b396-1afa6cadb5ef','依韵和雙頭芍藥十六首  其一六','陸佃','宋','宋诗','song-poetry','','[]','曾伴長楊草詔除，信知長合在中書。',64,'全唐诗/poet.song.52000.json','["曾伴長楊草詔除，信知長合在中書。", "暫違紫袖雙瞻立，聊伴紅裙一餉居。", "小子正狂心已醉，老奴猶愛髮方梳。", "故應此戰今須解，兵法曾教避不如。"]'),
('a431ec83-9eff-4737-8d2d-32ef59e3f08f','依韵和門下呂相公從駕視學','陸佃','宋','宋诗','song-poetry','','[]','纁帛升龍日月章，平明鸞輅幸膠庠。',64,'全唐诗/poet.song.52000.json','["纁帛升龍日月章，平明鸞輅幸膠庠。", "侍臣獨恨身千里，邸報空看字數行。", "故事一遵皇考廟，餘波仍及武成王。", "誰知玉尺橫經處，猶是當時舊講堂。"]'),
('e2a1a736-fdde-461b-afb3-1f84fba26ad5','依韵和趙令畤三首  其一','陸佃','宋','宋诗','song-poetry','','[]','百步廳邊放兩衙，夜深燈火見人家。',64,'全唐诗/poet.song.52000.json','["百步廳邊放兩衙，夜深燈火見人家。", "提壺勸我教沽酒，鸜鵒逢君要點茶。", "舞得六幺除是柳，啼消紅粉奈何花。", "使君被爾牽詩思，可是無心憶浣紗。"]'),
('45a2ab6a-6421-47e4-9ccc-2920ff13f267','依韵和趙令畤三首  其二','陸佃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','鳥排行陣樹排衙，且喜西湖屬當家。',64,'全唐诗/poet.song.52000.json','["鳥排行陣樹排衙，且喜西湖屬當家。", "揚子已無騎鶴事，會稽惟有臥龍茶。", "未妨春帝常爲帝，須信名花始是花。", "更住一年方五十，不應情味薄于紗。"]'),
('967aa445-5b4e-497e-b91c-d834712c1fd7','依韵和趙令畤三首  其三','陸佃','宋','宋诗','song-poetry','','[]','方朔無端溺殿衙，得州仍是地仙家。',64,'全唐诗/poet.song.52000.json','["方朔無端溺殿衙，得州仍是地仙家。", "海紅謾與陪尊酒，淮白猶堪當分茶。", "夜靜青天十分月，春深平地尺餘花。", "誰將園裏新蜂蜨，織就佳人護項紗。"]'),
('efb51268-6e4c-4c0b-a2c6-a04994bc6f56','依韵和趙令畤','陸佃','宋','宋诗','song-poetry','','[]','爭標才氣兩相高，不獨詩豪酒亦豪。',64,'全唐诗/poet.song.52000.json','["爭標才氣兩相高，不獨詩豪酒亦豪。", "戰得蟻酣成後殿，探知龍睡遇先逃。", "曾于寶月求斤斧，欲以春風代翦刀。", "他日若稱詩宰相，定應先後秉鈞陶。"]'),
('b64acdb8-8c2f-4215-a04c-188b4c84c3e3','依韵和田虎通判兼呈品防簽判四首  其一','陸佃','宋','宋诗','song-poetry','','[]','楚尾秦頭俗久移，豐穰仍值太平時。',64,'全唐诗/poet.song.52000.json','["楚尾秦頭俗久移，豐穰仍值太平時。", "渚花盡日臨書幌，潭菊如今在酒巵。", "十里麝香行驛近，三竿紅日坐廳遲。", "愛君古錦囊中句，不負文忠國士知。"]'),
('7f7073d2-6387-46fc-b1ae-e15ef068639f','依韵和田虎通判兼呈品防簽判四首  其二','陸佃','宋','宋诗','song-poetry','','[]','冉冉年光逐閏移，廳閒賓客坐多時。',64,'全唐诗/poet.song.52000.json','["冉冉年光逐閏移，廳閒賓客坐多時。", "主恩未報空持橐，軍政無妨數舉巵。", "潘鬢雪霜何太早，傅巖霖雨不應遲。", "頷珠竟被君探得，正值驪龍睡不知。"]'),
('b9ee65a9-c5fd-4d65-8e28-ac1b2a3ea1ba','依韵和田虎通判兼呈品防簽判四首  其三','陸佃','宋','宋诗','song-poetry','','[]','劇談終日少文移，幕府新開盛一時。',64,'全唐诗/poet.song.52000.json','["劇談終日少文移，幕府新開盛一時。", "羊酪未妨留灌頂，蟹螯何苦負操巵。", "詩成醉裏遺忘易，思發花前屬和遲。", "更許此生剛節在，祇應惟有歲寒知。"]'),
('bbc41e8b-d885-4d45-8558-cfadee7df16d','依韵和田虎通判兼呈品防簽判四首  其四','陸佃','宋','宋诗','song-poetry','','[]','春花秋葉兩推移，未有涓塵補聖時。',64,'全唐诗/poet.song.52000.json','["春花秋葉兩推移，未有涓塵補聖時。", "新識豹胎休負鼎，舊成蛇足謾持巵。", "山如水墨屏間見，日向棋盤子上遲。", "便使北歸應念此，白鷗黄鳥盡相知。"]'),
('d046fac0-893a-4163-9fd5-680634674620','用田倅韵答孫勉教授二首  其一','陸佃','宋','宋诗','song-poetry','','[]','淺紅深紫旋教移，直待開無空闕時。',64,'全唐诗/poet.song.52000.json','["淺紅深紫旋教移，直待開無空闕時。", "花十八中看蹋鞠，玉東西外聽揚巵。", "笙歌船舫天圍合，燈火樓臺月上遲。", "顧我若非鄉曲遠，定應長占此州知。"]'),
('71383212-1981-46fd-8e89-a05fb3c2a4fd','用田倅韵答孫勉教授二首  其二','陸佃','宋','宋诗','song-poetry','','[]','造化從他密密移，聰明非復似前時。',64,'全唐诗/poet.song.52000.json','["造化從他密密移，聰明非復似前時。", "暫披金甲爲儒將，曾燕珠宮對玉巵。", "一日看回花恨疾，三年生就葉嫌遲。", "慇懃爲訪春消息，頼有羹梅探得知。"]'),
('de81daaa-b9ce-4968-a2b1-b1b85e7c3e56','用前韵答謝推官','陸佃','宋','宋诗','song-poetry','','[]','小立桑陰尚未移，便如相識已多時。',64,'全唐诗/poet.song.52000.json','["小立桑陰尚未移，便如相識已多時。", "鋸沙我就玉界尺，點礫君成金屈巵。", "靈運自應爲佛早，退之今恨學仙遲。", "當年江左堂前燕，却又飛來未可知。"]'),
('0aa6d470-cf10-482d-99fe-b5239dce6504','依韵和趙令畤','陸佃','宋','宋诗','song-poetry','','[]','無事何妨數命賓，一湖清境是西鄰。',64,'全唐诗/poet.song.52000.json','["無事何妨數命賓，一湖清境是西鄰。", "栽花要與春爲主，對酒瞋將目借人。", "詩就彩牋斜卷玉，舞餘花碗倒垂銀。", "由來景物常無價，謾道錢多會有神。"]'),
('7f7bbfd7-7be8-4a4f-b971-5127d3a3371c','和朱昇朝奉','陸佃','宋','宋诗','song-poetry','','[]','湖上尋常日一臨，年華無用苦相侵。',64,'全唐诗/poet.song.52000.json','["湖上尋常日一臨，年華無用苦相侵。", "夢隨蝴蝶悠悠覺，日待蟾蜍款款沈。", "醉裏笙歌傳盞疾，壺中天地著花深。", "回瞻象闕恩難報，願盡平生一寸心。"]'),
('758d372b-3044-4b26-bc09-75c7203b476f','答張朝奉四首  其一','陸佃','宋','宋诗','song-poetry','','[]','赤松居處近州衙，況復詩情是作家。',64,'全唐诗/poet.song.52000.json','["赤松居處近州衙，況復詩情是作家。", "收得夕陽歸老境，破除春睡有新茶。", "年華一任隨流水，世事多應似落花。", "却笑宦游閒不得，塵埃昏盡幞頭紗。"]'),
('2f234d7d-4793-4ed6-bc13-c407b8fd5125','答張朝奉四首  其二','陸佃','宋','宋诗','song-poetry','','[]','誰將兩制比三衙，千騎猶如布素家。',64,'全唐诗/poet.song.52000.json','["誰將兩制比三衙，千騎猶如布素家。", "何日龍巾容吐酒，而今紗帽自煎茶。", "十年膠柱空調瑟，三月羹梅始見花。", "醉裏不知身在此，夢魂猶傍御袍紗。"]'),
('0b09b3c2-3f53-4cb7-ac2b-f477688ef6f0','答張朝奉四首  其三','陸佃','宋','宋诗','song-poetry','','[]','押了文書坐了衙，尋常行過祇如家。',64,'全唐诗/poet.song.52000.json','["押了文書坐了衙，尋常行過祇如家。", "苦無公事妨携酒，頼有詩情得試茶。", "便到五更猶有月，算來一日可無花。", "垂綸更作輕鷗伴，坐看寒汀學縐紗。"]'),
('60f38424-979e-4626-b05b-2669c7d997ae','答張朝奉四首  其四','陸佃','宋','宋诗','song-poetry','','[]','門鎖尋常付守衙，穿湖曾不礙民家。',64,'全唐诗/poet.song.52000.json','["門鎖尋常付守衙，穿湖曾不礙民家。", "慣看妙舞資豪飲，生怕清歌送好茶。", "山盍飛來圍著水，春休歸去带將花。", "從教魏紫姚黄下，也合翬衣裏素紗。"]'),
('4eca5621-fbfd-4b80-ae56-ecfcc88955ee','依韵和孫勉教授菊花','陸佃','宋','宋诗','song-poetry','','[]','芳叢宜密不宜疏，何事瓊花祇一株。',64,'全唐诗/poet.song.52000.json','["芳叢宜密不宜疏，何事瓊花祇一株。", "苦勸白衣成酩酊，儘饒紅粉插茱萸。", "定應青帝稀曾見，端的黄金似得無。", "便擬栽培伴桃李，盡移春色入洪爐。"]'),
('6d7c95fa-edec-4e52-bade-8367480d1198','依韵和李元中兼寄伯時二首  其一','陸佃','宋','宋诗','song-poetry','','[]','龍眠三李晦聲塵，長望淮壖與海濱。',64,'全唐诗/poet.song.52000.json','["龍眠三李晦聲塵，長望淮壖與海濱。", "自古市朝成底事，即今猿鶴伴他人。", "細思南陌東阡月，大勝千門萬戶春。", "可惜欲歸歸未得，不知家釀爲誰醇。"]'),
('7db8f2e1-1851-4265-8b23-3324863a6ac0','依韵和李元中兼寄伯時二首  其二','陸佃','宋','宋诗','song-poetry','','[]','五丈河邊避俗塵，閉門情味似漳濱。',64,'全唐诗/poet.song.52000.json','["五丈河邊避俗塵，閉門情味似漳濱。", "拋離鵲渚今三歲，成就華嚴祇兩人。", "貧裏有時求得玉，老來無可奈何春。", "平生共學王丞相，更覺荀揚未盡醇。"]'),
('f336b2a7-c425-4107-95e6-1b6b9b3a8b70','依韵和毅夫即事五首  其一','陸佃','宋','宋诗','song-poetry','','[]','昨日紅裳伴燕游，渚花爭好草爭柔。',64,'全唐诗/poet.song.52000.json','["昨日紅裳伴燕游，渚花爭好草爭柔。", "依稀黄鳥渾相識，期刻青山卒未休。", "風似去年搴翠幕，雨分明日與芳洲。", "即今太守無佳句，空愧當時宋采侯。"]'),
('3c242170-f5ff-4c7b-a36d-bd311280675e','依韵和毅夫即事五首  其二','陸佃','宋','宋诗','song-poetry','','[]','却笑元宵是夜游，金針穿石綵絲柔。',64,'全唐诗/poet.song.52000.json','["却笑元宵是夜游，金針穿石綵絲柔。", "萱堂帳幄閒仍出，幕府文書了即休。", "顧我寶珠連合浦，愛君仙果滿瀛洲。", "誰知並轡聊同俗，拜後如今有魯侯。"]'),
('2990005e-8325-4770-9d80-2314230f7b04','依韵和毅夫即事五首  其三','陸佃','宋','宋诗','song-poetry','','[]','平明一雨阻重游，風縐前溪綠謾柔。',64,'全唐诗/poet.song.52000.json','["平明一雨阻重游，風縐前溪綠謾柔。", "况已上元連夜出，不如寒食看春休。", "弄珠灘漲平侵岸，摸石江深抹盡洲。", "自是苦陰無意思，莫將潮信枉陽侯。"]'),
('b19dc1d9-6a03-4ce4-9c88-dffbab07f633','依韵和毅夫即事五首  其四','陸佃','宋','宋诗','song-poetry','','[]','十年京洛從宸游，得郡終難繞指柔。',64,'全唐诗/poet.song.52000.json','["十年京洛從宸游，得郡終難繞指柔。", "廬舍昔希三肯顧，亭臺今負四宜休。", "何人正在芙蓉島，有客空吟杜若洲。", "爲問西街孔君子，設監那得似諸侯。"]'),
('a85b8e3d-154b-4d55-ab4f-df7100c9285b','依韵和毅夫即事五首  其五','陸佃','宋','宋诗','song-poetry','','[]','謝安携妓是清游，玉瑩金尊十指柔。',64,'全唐诗/poet.song.52000.json','["謝安携妓是清游，玉瑩金尊十指柔。", "桃自三千年結子，鼇于六萬歲更休。", "猿啼謾想黄牛峽，鳳去空傳白鷺洲。", "我若他年封萬戶，祇來穰下作穰侯。"]'),
('8d1fff6d-fcbf-4827-a198-9586ed8254c0','依韵和毅夫百花洲新橋','陸佃','宋','宋诗','song-poetry','','[]','省中何必就尚書，且向新橋一振裾。',64,'全唐诗/poet.song.52000.json','["省中何必就尚書，且向新橋一振裾。", "嬌女頃嫌撐小艇，偏親今喜度安輿。", "假饒跨鯉終難學，除却垂虹盡不如。", "從此使衙烏亦好，豈無遺愛在胥餘。"]'),
('05177d37-3e67-429b-b9bd-3ada887a6a8a','答毅夫遺橘株之什三首  其一','陸佃','宋','宋诗','song-poetry','','[]','平生希慕范萊蕪，恥把耕耘一問奴。',64,'全唐诗/poet.song.52000.json','["平生希慕范萊蕪，恥把耕耘一問奴。", "碑較智愚能幾里，樹爭貧富沒多株。", "報之瓊玖如投李，遺以珩璜恍弋鳬。", "傳語小城休負固，元侯今後不言無。"]'),
('8730d3ff-70f2-4336-baa1-b1e2fde17818','答毅夫遺橘株之什三首  其二','陸佃','宋','宋诗','song-poetry','','[]','亭榭新修道不蕪，豐年焉用橘千奴。',64,'全唐诗/poet.song.52000.json','["亭榭新修道不蕪，豐年焉用橘千奴。", "請教青帝留三月，擬就嫦娥乞一株。", "種玉水田飛白鷺，泳珠風檻對沈鳬。", "便難圖畫猶爭看，定是京西一路無。"]'),
('b462bda6-5cad-4692-b106-8f232d86e173','答毅夫遺橘株之什三首  其三','陸佃','宋','宋诗','song-poetry','','[]','曾因書史翦繁蕪，更與花王置木奴。',64,'全唐诗/poet.song.52000.json','["曾因書史翦繁蕪，更與花王置木奴。", "藍舊出師青萬頃，竹新齊母綠千株。", "睡餘枕簟屏開鳳，飲盡尊罍勺用鳬。", "一種梧桐亦遭遇，翦封終愧內虛無。"]'),
('3100d795-ebb3-40a7-b5c9-21b3c77128f2','和毅夫倒用無字韵春詩四首  其一','陸佃','宋','宋诗','song-poetry','','[]','皇家寶歷萬年餘，禮貌羣臣自古無。',64,'全唐诗/poet.song.52000.json','["皇家寶歷萬年餘，禮貌羣臣自古無。", "龍馬已陪阿閣鳳，鼎湖猶想裕陵鳬。", "劉郎莫恨桃千樹，匠伯應憐櫟一株。", "猶喜後來門戶在，小兒能賦崑崙奴。"]'),
('8191da09-81ff-4deb-8c59-6f131f3ce05c','和毅夫倒用無字韵春詩四首  其二','陸佃','宋','宋诗','song-poetry','','[]','一別勾芒僅歲餘，不知今度老顔無。',64,'全唐诗/poet.song.52000.json','["一別勾芒僅歲餘，不知今度老顔無。", "管人憂喜何如鵲，與世浮沈可奈鳬。", "擬看笏頭花四朵，更栽槐面樹三株。", "若教上番成新竹，須戒人家婢與奴。"]'),
('173743fe-8752-4184-81b6-1384e8a8abac','和毅夫倒用無字韵春詩四首  其三','陸佃','宋','宋诗','song-poetry','','[]','附庸新又進於餘，欲共南鄰鬭有無。',64,'全唐诗/poet.song.52000.json','["附庸新又進於餘，欲共南鄰鬭有無。", "橫列谿山埋積雪，臥開桃李映新鳬。", "擬舂玉臼丹千杵，更種金鎚麥一株。", "從此有人殽亦有，不煩公帑與官奴。"]'),
('d5ede269-b9d5-4a47-9943-11453301775b','和毅夫倒用無字韵春詩四首  其四','陸佃','宋','宋诗','song-poetry','','[]','公錢雖少俸錢餘，明日如今作會無。',64,'全唐诗/poet.song.52000.json','["公錢雖少俸錢餘，明日如今作會無。", "況有鼈裙勝膾鯉，豈無鵝掌代蒸鳬。", "慶歸子舍芝三秀，官入卿曹棘九株。", "聞說麗人推不去，愛才何止十年奴。"]'),
('6da51d06-e524-40ad-8241-ff8256fca55d','和毅夫病目三首  其一','陸佃','宋','宋诗','song-poetry','','[]','使君詩思謾雕肝，安得頭風與阿瞞。',64,'全唐诗/poet.song.52000.json','["使君詩思謾雕肝，安得頭風與阿瞞。", "然艾爲誰甘受痛，看花緣此負追歡。", "通天犀带應憐瘦，雲母屏風尚畏寒。", "何日長安同一醉，擬教歌舞衒華丹。"]'),
('2a655828-08a8-4060-b718-acfbc35b8659','和毅夫病目三首  其二','陸佃','宋','宋诗','song-poetry','','[]','詩戰空懷壯士肝，未容旃旆累祁瞞。',64,'全唐诗/poet.song.52000.json','["詩戰空懷壯士肝，未容旃旆累祁瞞。", "並遊曾許花含笑，孤憤今慚樹合歡。", "五朵謾將春色寄，二篇還伴夜光寒。", "憑君休造斑貓毒，且向三田養就丹。"]'),
('eb17b731-edf8-4121-9e98-3179d8dd81a9','和毅夫病目三首  其三','陸佃','宋','宋诗','song-poetry','','[]','報君平日願輸肝，常笑飛蝗累李瞞。',64,'全唐诗/poet.song.52000.json','["報君平日願輸肝，常笑飛蝗累李瞞。", "一雨固宜知上德，是花猶可盡君歡。", "孤根自識恩波煖，老健誰爭氣候寒。", "從此憂民免髭白，却疑甘澤是金丹。"]'),
('57792416-12e5-454c-b7db-a5e6587458f3','依韵和毅夫兒病','陸佃','宋','宋诗','song-poetry','','[]','二毛蕭索未應羞，謾說初懷弄瓦憂。',64,'全唐诗/poet.song.52000.json','["二毛蕭索未應羞，謾說初懷弄瓦憂。", "珠母光芒今吐月，豹駒才氣已窺牛。", "自知陰德仙能學，誰有靈符鬼可囚。", "早晚病除聞藥喜，與君詩酒共清遊。"]'),
('90f9bd22-3ac2-4c35-947d-ffdf1f1cea0d','易守建業毅夫有詩贈別次韵五首  其一','陸佃','宋','宋诗','song-poetry','','[]','太守無堪久借留，君王恩禮與昇州。',64,'全唐诗/poet.song.52000.json','["太守無堪久借留，君王恩禮與昇州。", "親輿自可時來往，漁唱猶能數獻酬。", "風色得經揚子渡，月明知在海棠洲。", "北山楷木今成列，獨傍師門想見丘。"]'),
('c590d0ec-d86a-4aa4-9694-66b96ea9b502','易守建業毅夫有詩贈別次韵五首  其二','陸佃','宋','宋诗','song-poetry','','[]','凌晨寒日弄輝輝，我旆東來子旆西。',64,'全唐诗/poet.song.52000.json','["凌晨寒日弄輝輝，我旆東來子旆西。", "對此銷魂兩無語，恨初相遇一何稽。", "梅花可惜空隨驛，鷗鳥多應不下溪。", "猶有往來魚與雁，好將詩什當書題。"]'),
('7102b64c-6b78-4713-8e41-dc126c7b6f39','易守建業毅夫有詩贈別次韵五首  其三','陸佃','宋','宋诗','song-poetry','','[]','紫案焚香拜敕黄，無因久借蓋公堂。',64,'全唐诗/poet.song.52000.json','["紫案焚香拜敕黄，無因久借蓋公堂。", "不堪落日離魂斷，頼有薰風引夢長。", "吹律漸知寒谷暖，賣漿曾值暑天凉。", "他年果若成功去，乞取南陽作鄧王。"]'),
('9c1fa0f1-49a5-4ae9-820b-814fc952e70b','易守建業毅夫有詩贈別次韵五首  其四','陸佃','宋','宋诗','song-poetry','','[]','春渚秋潭不可尋，回頭城郭礙高林。',64,'全唐诗/poet.song.52000.json','["春渚秋潭不可尋，回頭城郭礙高林。", "但知自白三分鬢，更與誰論一寸心。", "紅粉淚痕消片玉，故人情分重千金。", "臨岐不忍醒時別，一任玻瓈酒盞深。"]'),
('e22b20d2-113a-4ea8-b77e-4e5c7dfed2b1','易守建業毅夫有詩贈別次韵五首  其五','陸佃','宋','宋诗','song-poetry','','[]','誰信金陵刺史腸，曾懷珠玉夜光芒。',64,'全唐诗/poet.song.52000.json','["誰信金陵刺史腸，曾懷珠玉夜光芒。", "一塵侍從才雖短，雙奉君親日更長。", "得郡免營三釜粟，過都容捧萬年觴。", "遙知南北相望處，風在檀欒月在棠。"]'),
('a744b040-e9f7-4172-b1fc-7de2fadc8615','依韵和徐大夫鳳凰池九首  其一','陸佃','宋','宋诗','song-poetry','','[]','借山樓小已新奇，更近東邊得鳳池。',64,'全唐诗/poet.song.52000.json','["借山樓小已新奇，更近東邊得鳳池。", "一日未嘗無客過，百年今始有人知。", "舞餘裙带雙垂綠，詩就珊瑚半露枝。", "爲問鵷雛歸得未，虛來阿閣已多時。"]'),
('16a91465-fcd6-4f07-ab34-5c43ca6a949d','依韵和徐大夫鳳凰池九首  其二','陸佃','宋','宋诗','song-poetry','','[]','使君年老强搜奇，來傍吟窗擁被池。',64,'全唐诗/poet.song.52000.json','["使君年老强搜奇，來傍吟窗擁被池。", "明月清風初未覺，白鷗黄鳥舊相知。", "水通河漢無多地，鳳在梧桐第幾枝。", "好是與民同此樂，豐穰仍值太平時。"]'),
('f879ccd7-fd4d-45d8-98ed-99223bd20320','依韵和徐大夫鳳凰池九首  其三','陸佃','宋','宋诗','song-poetry','','[]','池就臺成竟大奇，畫堂新燕亦差池。',64,'全唐诗/poet.song.52000.json','["池就臺成竟大奇，畫堂新燕亦差池。", "人非楊柳看來瘦，春有梅花探得知。", "華髮漸驚强半白，素娥曾與第三枝。", "海邦莫道無賓客，冠蓋如今盛一時。"]'),
('16dab26d-3c5c-46f2-b22e-579cce192536','依韵和徐大夫鳳凰池九首  其四','陸佃','宋','宋诗','song-poetry','','[]','東君著力信神奇，桃李中間水滿池。',64,'全唐诗/poet.song.52000.json','["東君著力信神奇，桃李中間水滿池。", "定是祇教淮甸有，若爲長得泰州知。", "行藏正倚樓千尺，勳業初橫草一枝。", "投老尚堪驅使在，問春何似少年時。"]'),
('5f5caebd-ce86-46e0-b42b-ec0f15311bbf','依韵和徐大夫鳳凰池九首  其五','陸佃','宋','宋诗','song-poetry','','[]','公事稀疏已自奇，那堪園更勝舒池。',64,'全唐诗/poet.song.52000.json','["公事稀疏已自奇，那堪園更勝舒池。", "誘將醉尹來無數，禁得詩人瘦不知。", "蝶夢幾隨蝴蝶遠，鳳雛仍在鳳凰枝。", "賞心樂事知多少，雪月風花是四時。"]'),
('8d3964ad-8944-4aae-8c8a-b5e92b31b2ad','依韵和徐大夫鳳凰池九首  其六','陸佃','宋','宋诗','song-poetry','','[]','平生仕宦不求奇，誰怕他人奪我池。',64,'全唐诗/poet.song.52000.json','["平生仕宦不求奇，誰怕他人奪我池。", "地勝更無塵可到，天陰惟有病先知。", "從教寶塔來當面，消得雲樓爲折枝。", "看取鶠堂何似好，夜深歌管月明時。"]'),
('4b302ab4-c647-4432-9935-92a4c09b640c','依韵和徐大夫鳳凰池九首  其七','陸佃','宋','宋诗','song-poetry','','[]','老懶由來怕立奇，偶然尋得舊家池。',64,'全唐诗/poet.song.52000.json','["老懶由來怕立奇，偶然尋得舊家池。", "一州祇此爲無及，累政因何盡不知。", "歌吹徹雲城百尺，樓臺侵夜火千枝。", "憑誰爲報鶑花道，一日須來十二時。"]'),
('6da799ec-1bb3-4504-9b49-ec89051dedb7','依韵和徐大夫鳳凰池九首  其八','陸佃','宋','宋诗','song-poetry','','[]','彷彿華胥一夢奇，斬新樓閣舊城池。',64,'全唐诗/poet.song.52000.json','["彷彿華胥一夢奇，斬新樓閣舊城池。", "夜深猶有人家看，晝寢惟應燕子知。", "疏雨有時三兩點，好花何啻萬餘枝。", "諸公若肯相追逐，趁取春風爛漫時。"]'),
('cc5cb5dd-a2bc-4ad7-b0cf-306c63355afa','依韵和徐大夫鳳凰池九首  其九','陸佃','宋','宋诗','song-poetry','','[]','恰似蒲萄水亦奇，遊人多似後園池。',64,'全唐诗/poet.song.52000.json','["恰似蒲萄水亦奇，遊人多似後園池。", "壺中日在歸前落，醉裏詩成醒後知。", "芳徑綽開楊柳樹，小牆闌出杏花枝。", "老拳毒手渾相若，望立降旗是幾時。"]'),
('3e5b9529-8c0e-4abf-8f5a-e07d8479d223','朝散','陸佃','宋','宋诗','song-poetry','','[]','使君竟亦不能奇，頼有詩翁壯觀池。',64,'全唐诗/poet.song.52000.json','["使君竟亦不能奇，頼有詩翁壯觀池。", "二百年來無此作，兩三人外有誰知。", "魚應變化垂天翼，鵲不經營墮地枝。", "况復鳳毛如得鳳，古來遭遇或同時。"]'),
('bfee25df-cfbc-4d4a-8407-f69766d53594','依韵和張椿','陸佃','宋','宋诗','song-poetry','','[]','一年三十有餘旬，最愛韶華是令辰。',64,'全唐诗/poet.song.52000.json','["一年三十有餘旬，最愛韶華是令辰。", "坐久落花深一尺，睡餘淺粉看重勻。", "況當諸縣無公事，且與雲樓作主人。", "今日與君俱白髮，看花情味尚青春。"]'),
('013d5e06-46a0-4733-a464-9a0a4c79d8f2','依韵和查朝散贈新恩先輩','陸佃','宋','宋诗','song-poetry','','[]','收得宮花上带春，綠袍仍共草爭新。',64,'全唐诗/poet.song.52000.json','["收得宮花上带春，綠袍仍共草爭新。", "發揚杜老詩無敵，蓋覆吳侯政不神。", "平地彩雲看接武，一天明月負垂綸。", "怪來瀕海多儒士，龍閣從來是里人。"]'),
('278568a1-1577-4141-aa68-390ff6071898','依韵和徐大夫','陸佃','宋','宋诗','song-poetry','','[]','朱絲同直水同清，紅袖何妨當使令。',64,'全唐诗/poet.song.52000.json','["朱絲同直水同清，紅袖何妨當使令。", "可惜去年他處看，不知今夜幾州明。", "年華老去知無補，眉嫵初閒似有情。", "且向雲樓拌共醉，儘他燈火暮禽驚。"]'),
('93efd7dd-db41-4b86-ab9c-08301b895f9d','中秋微陰','陸佃','宋','宋诗','song-poetry','','[]','年年月色是中秋，莫爲今宵海上樓。',64,'全唐诗/poet.song.52000.json','["年年月色是中秋，莫爲今宵海上樓。", "要得長圓真妄意，放教微暗亦良籌。", "步金磚上顔仍好，頹玉山前德盡柔。", "生怪嫦娥苦羞澀，都緣瞋不强公遊。"]'),
('da83b184-ba77-4151-979e-0c40be031b77','中秋用別韵答張椿兼呈徐瓘','陸佃','宋','宋诗','song-poetry','','[]','偶被微雲掩素娥，昏昏如似隔輕羅。',64,'全唐诗/poet.song.52000.json','["偶被微雲掩素娥，昏昏如似隔輕羅。", "祇應夢裏朦朧慣，可是秋來淡薄多。", "捨此豈無珠可玩，學渠猶有扇能歌。", "會須明夜分明在，況有詩人爲琢磨。"]'),
('86555435-3fe0-4e61-8d5d-c603ad117890','依韵和查許國二首  其一','陸佃','宋','宋诗','song-poetry','','[]','重淵誰道探珠難，恰值驪龍睡重間。',64,'全唐诗/poet.song.52000.json','["重淵誰道探珠難，恰值驪龍睡重間。", "工部藩籬今夢草，司空門館舊銜環。", "心腸何啻吞雲夢，身手猶堪擘華山。", "況有舊家仙桂在，姮娥留著待君攀。"]'),
('2bcfd23e-c6ad-41d8-81e1-dc0598890dbe','依韵和查許國二首  其二','陸佃','宋','宋诗','song-poetry','','[]','誰作明堂一柱看，謫官猶詿罪中間。',64,'全唐诗/poet.song.52000.json','["誰作明堂一柱看，謫官猶詿罪中間。", "名成何必頻看鏡，道在終須得賜環。", "一片靈臺江上月，七株仙果海中山。", "回頭爲報姮娥道，擬把高枝次第攀。"]'),
('130776ac-1739-4a94-a111-88ade8cfe5e0','寄龔深之曾子開','陸佃','宋','宋诗','song-poetry','','[]','先生官冷久京華，衣有塵埃飯有沙。',64,'全唐诗/poet.song.52000.json','["先生官冷久京華，衣有塵埃飯有沙。", "半夜尚聞親舊草，一春長是負新花。", "兩龔清潔推君子，二陸文章屬當家。", "更憶巷南曾學士，坐將盤誥解聱牙。"]'),
('6ad0ebd6-a50a-475d-8181-ecde5cecc9cf','依韵和查許國梅花六首  其一','陸佃','宋','宋诗','song-poetry','','[]','臘月狐裘尚御黄，靚妝先了爲誰忙。',64,'全唐诗/poet.song.52000.json','["臘月狐裘尚御黄，靚妝先了爲誰忙。", "與春不足都緣淡，教雪難知祇爲香。", "曾擁旌旗聞鼓角，終隨彝鼎見烝嘗。", "少陵頼爾牽詩思，得向詩中號帝王。"]'),
('d26afa41-e484-40fc-853b-613315b586c0','依韵和查許國梅花六首  其二','陸佃','宋','宋诗','song-poetry','','[]','水天清淺月昏黄，傳語諸花未要忙。',64,'全唐诗/poet.song.52000.json','["水天清淺月昏黄，傳語諸花未要忙。", "詞客盡應相識早，玉人誰有自然香。", "祇承雨露尤消得，況乃冰霜已備嘗。", "未用夜寒吹玉笛，切須丁囑與寧王。"]'),
('5b56d847-35af-407c-92a3-08ac8e4f9f0c','依韵和查許國梅花六首  其三','陸佃','宋','宋诗','song-poetry','','[]','平日栽培土盡黄，看來人自有閒忙。',64,'全唐诗/poet.song.52000.json','["平日栽培土盡黄，看來人自有閒忙。", "池臺直下疏疏影，簾箔中間淡淡香。", "命說夢魂猶未破，說湯滋味得先嘗。", "憑誰爲訪桃花浪，何路能酬百谷王。"]'),
('c9ab67bd-3a37-479a-ace4-4b761538a5d3','依韵和查許國梅花六首  其四','陸佃','宋','宋诗','song-poetry','','[]','妝閣無端畫月黄，見他閒淡轉蒼忙。',64,'全唐诗/poet.song.52000.json','["妝閣無端畫月黄，見他閒淡轉蒼忙。", "隴頭惆悵經年別，衣上慇懃盡日香。", "期刻莫將蓬鬢插，思量消得瓠犀嘗。", "若教梵竺諸天有，何必龍華引象王。"]'),
('97a45393-b60b-452c-8ec0-edaec7edbb14','依韵和查許國梅花六首  其五','陸佃','宋','宋诗','song-poetry','','[]','北窗高臥識羲黄，靜看東君職事忙。',64,'全唐诗/poet.song.52000.json','["北窗高臥識羲黄，靜看東君職事忙。", "短帽上垂年少事，浄瓶中養月餘香。", "鏡鸞羞愧臨梳裹，鹽虎推先在饗嘗。", "試問古來誰可伴，風流東晉有諸王。"]'),
('245ade6b-22c2-4290-b459-d348193469b2','依韵和查許國梅花六首  其六','陸佃','宋','宋诗','song-poetry','','[]','共月新成牓字黄，使君霜鬢未須忙。',64,'全唐诗/poet.song.52000.json','["共月新成牓字黄，使君霜鬢未須忙。", "春前臘後千回顧，天上人間一分香。", "莊子夢魂休道識，太公牙齒要須嘗。", "論功縱在姚黄下，果子花中合是王。"]'),
('9047db30-d2d8-4bfd-bf94-8667e32dccc8','依韵和許安石','陸佃','宋','宋诗','song-poetry','','[]','風和鵲喜就中靈，忽報軒車到驛亭。',64,'全唐诗/poet.song.52000.json','["風和鵲喜就中靈，忽報軒車到驛亭。", "解得禮經歸指掌，弄成詩筆勝丹青。", "早年花萼光原隰，今日芝蘭滿戶庭。", "聞說龍州佳闕近，蜀人先已望流星。"]'),
('ec03b648-02b8-4d47-b12b-e21079a0dcf8','從駕幸龍德宮','陸佃','宋','宋诗','song-poetry','','[]','玉鎖晨開厚載門，人家隨處著彫輪。',64,'全唐诗/poet.song.52000.json','["玉鎖晨開厚載門，人家隨處著彫輪。", "潜龍宮邸來惟舊，復辟簾幃卷尚新。", "深巷盡言窺日月，麤官難得後埃塵。", "戴恩自覺丘山重，願放鼇更六萬春。"]'),
('2b6e9f0b-0906-4bdc-b674-aa44436517a0','天寧節口號','陸佃','宋','宋诗','song-poetry','','[]','九天宮闕五雲新，共向中間望紫宸。',64,'全唐诗/poet.song.52000.json','["九天宮闕五雲新，共向中間望紫宸。", "几杖一千年父老，衣冠三萬里君臣。", "瀨鄉老子如今檜，蒙縣莊生上古椿。", "就祝聖君千萬歲，過于天上壽星辰。"]'),
('596be0cb-8c46-404a-94d3-32931acd0d2e','寄彥猷閣老某前歲奉使還領揚州今彥猷亦自境外歸得姑蘇','陸佃','宋','宋诗','song-poetry','','[]','相望持節出盧龍，繼踵分符別紫宮。',64,'全唐诗/poet.song.52000.json','["相望持節出盧龍，繼踵分符別紫宮。", "汲黯雖嫌棄爲郡，袁絲應憚久居中。", "文章不見于時益，出處何知與子同。", "紅藥萬株天下絕，謝公來肯醉薰風。"]'),
('0b89e5d3-9cf6-445c-965d-e41d3aebcaab','和周邠朝奉','陸佃','宋','宋诗','song-poetry','','[]','相見還如潁水濱，不應衰邁久風塵。',64,'全唐诗/poet.song.52000.json','["相見還如潁水濱，不應衰邁久風塵。", "幾回醉裏成狂客，一向詩中作貴人。", "故國生涯元自薄，老來情分剩相親。", "薦賢況有諸公在，早晚除書下玉宸。"]'),
('710155d4-3b02-4468-b783-6baf9ec76175','新橋','陸佃','宋','宋诗','song-poetry','','[]','碧光新近跨長橋，免使遊人隔岸招。',64,'全唐诗/poet.song.52000.json','["碧光新近跨長橋，免使遊人隔岸招。", "想像蓬瀛今彷彿，丁寧風雨莫漂摇。", "少浮蛟蜃平生氣，纔露虹霓一半腰。", "明月滿天天似水，直疑霄漢路非遙。"]'),
('0cd9fb14-2bb5-4b68-aaa2-5cf43159cf1d','題周中散至樂堂','陸佃','宋','宋诗','song-poetry','','[]','一瓢到底勝珠玉，萬籟由來當管弦。',64,'全唐诗/poet.song.52000.json','["一瓢到底勝珠玉，萬籟由來當管弦。", "盡日海鷗陪燕坐，有時溪柳伴閒眠。", "不知萱草憂何事，今見蟠桃定幾年。", "回首真人足官府，劉安何苦要升天。"]'),
('3bf20eac-a158-42d4-a9b3-b6911929f479','丞相荆公挽歌詞','陸佃','宋','宋诗','song-poetry','','[]','慣識無心有海鷗，行藏須向古人求。',64,'全唐诗/poet.song.52000.json','["慣識無心有海鷗，行藏須向古人求。", "皋陶一死隨神禹，孟子平生學聖丘。", "雕篹想陪清廟食，玉杯應從裕陵遊。", "遙瞻舊館知難報，絳帳橫經二十秋。"]'),
('35ad5a04-a810-40d1-9b6d-91435a7a806e','呂申公挽歌詞','陸佃','宋','宋诗','song-poetry','','[]','家世從來聳具瞻，平生僚友憚方嚴。',64,'全唐诗/poet.song.52000.json','["家世從來聳具瞻，平生僚友憚方嚴。", "挂閒麈尾清談罕，傅盡龍髭老病添。", "共惜一朝埋玉樹，正當雙日下珠簾。", "自慚曾借風雷便，初與魚龍出滯淹。"]'),
('0019ee74-1965-4bab-a20f-d8760a713dc6','韓康公挽歌詞三首  其一','陸佃','宋','宋诗','song-poetry','','[]','熙寧初見築隄沙，曾與千官聽白麻。',64,'全唐诗/poet.song.52000.json','["熙寧初見築隄沙，曾與千官聽白麻。", "常棣行中排宰相，梧桐名上識韓家。", "平生事業留青史，一夜塵埃暗碧紗。", "聞說手栽桃李在，春來應有萬株花。"]'),
('dcc0cd9d-9e4a-483e-a4e5-19ea86750c3e','韓康公挽歌詞三首  其二','陸佃','宋','宋诗','song-poetry','','[]','三台光耀紫微中，康國仍兼萬戶封。',64,'全唐诗/poet.song.52000.json','["三台光耀紫微中，康國仍兼萬戶封。", "有子晨昏長侍膳，誰家兄弟盡登庸。", "非關庚日曾占鵩，自是辰年併值龍。", "他日凌烟求繪匠，願憑丹筆爲形容。"]'),
('64cd9c85-8fe6-478e-84c0-9b502c5a3832','韓康公挽歌詞三首  其三','陸佃','宋','宋诗','song-poetry','','[]','龍虎常瞻牓上名，識公初向鳳凰城。',64,'全唐诗/poet.song.52000.json','["龍虎常瞻牓上名，識公初向鳳凰城。", "三千賓客知毛遂，五百人家待晏嬰。", "擬看玉書容拔宅，安知金鼎誤垂成。", "後園履迹今蕪沒，惟有清風伴月明。"]'),
('ed88d2e7-8eb2-43fc-86b0-1920a73e1086','呂尚書挽歌詞','陸佃','宋','宋诗','song-poetry','','[]','禍患相仍涕淚頻，司空墳上草猶新。',64,'全唐诗/poet.song.52000.json','["禍患相仍涕淚頻，司空墳上草猶新。", "鶺鴒花萼空餘子，龍馬圖書併失人。", "遍歷名藩今始老，長如寒士本非貧。", "如何一日埋金碗，獨向清時不秉鈞。"]'),
('ca73d745-c1ba-4716-8f35-f31bc1d718b9','蹇翁待制挽歌詞','陸佃','宋','宋诗','song-poetry','','[]','仕宦聲名四十年，歸心日夜望林泉。',64,'全唐诗/poet.song.52000.json','["仕宦聲名四十年，歸心日夜望林泉。", "文移竟負登山屐，牋記空隨過海船。", "花塢夕陽今逝矣，錦江春色謾依然。", "傳家況有珠璣在，會向人間月夜圓。"]'),
('81891c8a-8cb5-4e0e-bc11-a07d71ecb8fa','程給事挽歌詞','陸佃','宋','宋诗','song-poetry','','[]','桃花墳塢土新乾，歎息高才又玉棺。',64,'全唐诗/poet.song.52000.json','["桃花墳塢土新乾，歎息高才又玉棺。", "竟逐兩翁談笑盡，空留三老畫圖看。", "異書會見傳吳市，妙斲何知失郢墁。", "聞說錦囊佳句在，光芒猶伴夜珠寒。"]'),
('caf19cd8-a986-4598-9a95-aa6c4ee091ac','王聖美學士挽歌詞','陸佃','宋','宋诗','song-poetry','','[]','使君政事與文章，憂患平生亦備嘗。',64,'全唐诗/poet.song.52000.json','["使君政事與文章，憂患平生亦備嘗。", "資善故人今白髮，邯鄲一夢已黄粱。", "田園倚仗千株橘，花萼飄零一樹棠。", "聞說異書奇字在，不妨分付與諸郎。"]'),
('0d4daa67-511b-4f4c-a906-9968d2853a70','魏國太夫人陳氏挽歌詞','陸佃','宋','宋诗','song-poetry','','[]','門戶同歸太史評，傳芳消息在瑶瓊。',64,'全唐诗/poet.song.52000.json','["門戶同歸太史評，傳芳消息在瑶瓊。", "鳳銜誥詔從夫貴，龍負圖書識父清。", "金鴨火銷香自遠，玉匳珠在月空明。", "也知欲向華胥問，炊盡黄粱夢不成。"]'),
('8e3c9d5a-d62b-49f7-af97-eb6b599562b0','送李劭縣令','陸佃','宋','宋诗','song-poetry','','[]','長官衫色暗，玉雪久甘貧。',24,'全唐诗/poet.song.52000.json','["長官衫色暗，玉雪久甘貧。", "爲問江西月，如君有幾人。"]'),
('19b3a519-11ab-4b3c-a606-99726643d4d0','悼亡二首  其一','陸佃','宋','宋诗','song-poetry','','[]','門巷雨蕭蕭，黄昏掩寂寥。',24,'全唐诗/poet.song.52000.json','["門巷雨蕭蕭，黄昏掩寂寥。", "曲終人不見，花落夢無聊。"]'),
('9ad6761c-9925-4e2a-b927-d803bdb61073','悼亡二首  其二','陸佃','宋','宋诗','song-poetry','','[]','燈火夜寥寥，殘香不可招。',24,'全唐诗/poet.song.52000.json','["燈火夜寥寥，殘香不可招。", "朱扉寒半掩，金鴨煖全消。"]'),
('c1c7851d-cd65-4262-8e26-11ad64a6e375','詠史','陸佃','宋','宋诗','song-poetry','','[]','珠履三千兩，金椎四十斤。',24,'全唐诗/poet.song.52000.json','["珠履三千兩，金椎四十斤。", "阿誰知狗盜，却解脫田文。"]'),
('b5aaec1a-e2b9-42a9-a225-9619d4bde210','景德寺考試秋日即事四首  其一','陸佃','宋','宋诗','song-poetry','','[]','朝來爽氣雨初乾，喬木陰陰鎖晝寒。',32,'全唐诗/poet.song.52000.json','["朝來爽氣雨初乾，喬木陰陰鎖晝寒。", "深院下簾風不動，夕陽幽鳥傍闌干。"]'),
('2a467bb9-3682-4975-a8e6-1f57c049648f','景德寺考試秋日即事四首  其二','陸佃','宋','宋诗','song-poetry','','[]','秋聲一夜滿長安，密雨疏風次第寒。',32,'全唐诗/poet.song.52000.json','["秋聲一夜滿長安，密雨疏風次第寒。", "幽草落花歸思亂，寂寥終日倚闌干。"]'),
