('9e70fcc0-2eea-45f8-bc5c-d310481fdc55','詠西湖十洲 松島','劉珵','宋','宋诗','song-poetry','','["\u897f\u6e56"]','恥隨楊柳嬌春色，厭近芙蕖透暗香。',32,'全唐诗/poet.song.52000.json','["恥隨楊柳嬌春色，厭近芙蕖透暗香。", "直幹凌霜終偃蹇，願爲一柱壯明堂。"]'),
('5b498dcf-f98c-4be6-931b-8ac8510c3185','題虎丘次蒲章二公韵','劉淑','宋','宋诗','song-poetry','','[]','衮席頻虛未賜環，遊心暫寄水雲間。',64,'全唐诗/poet.song.52000.json','["衮席頻虛未賜環，遊心暫寄水雲間。", "霓旌初下姑蘇苑，蠟屐先尋虎踞山。", "高興不辭溪路險，幽情更羨野僧閑。", "留連景物慵回首，畫舫寒侵暮角還。"]'),
('be7acb0a-a6a0-499f-abcb-3e7a797a0fd5','再至新定有感','岑象求','宋','宋诗','song-poetry','','[]','蜀地吳天各一涯，去來三紀亦云賒。',64,'全唐诗/poet.song.52000.json','["蜀地吳天各一涯，去來三紀亦云賒。", "烏龍遶郭儼如舊，白髮滿頭良可嗟。", "老矣不堪多感慨，使乎何處是光華。", "周行歷覽猶疑夢，更問庭櫧幾度花。"]'),
('2350eeb1-b421-46c6-9b48-1720cdfac5ae','詠縣廳前古櫧木','岑象求','宋','宋诗','song-poetry','','[]','三十年前宰一同，朝朝相對此庭中。',64,'全唐诗/poet.song.52000.json','["三十年前宰一同，朝朝相對此庭中。", "如今翠葉樛枝好，依舊朱欄戒石東。", "潘岳河陽花立盡，陶潜彭澤柳隨空。", "唯君獨負堅剛操，何異靈椿與夏蟲。"]'),
('c98e9da1-f440-495f-9fe9-81cb6edc7433','滌慮軒','岑象求','宋','宋诗','song-poetry','','[]','聖人重洗心，君子貴浴德。',71,'全唐诗/poet.song.52000.json','["聖人重洗心，君子貴浴德。", "清心是道場，金仙有遺則。", "人言我慮不須滌，我謂幾人能滌得。", "以此息萬緣，以此銷六賊。", "君不見水觀月觀成道人，盡向此門生妙識。"]'),
('ac257e2f-e60e-4a16-bcc3-6c0ba273c089','中巖','岑象求','宋','宋诗','song-poetry','','[]','瀟洒監城隈，聊驅俗駕回。',24,'全唐诗/poet.song.52000.json','["瀟洒監城隈，聊驅俗駕回。", "世塵飛不到，山色翠成堆。"]'),
('33f0cda5-ada5-4a10-a081-e04ec0578012','劍門關','岑象求','宋','宋诗','song-poetry','','[]','當道雙峰闢，凌空萬仞酋。',24,'全唐诗/poet.song.52000.json','["當道雙峰闢，凌空萬仞酋。", "於秦置扃鐍，與蜀作襟喉。"]'),
('2488341b-696b-4d69-8bae-a3795c7bdb1c','遊定林院','岑象求','宋','宋诗','song-poetry','','[]','野闊蓮宮迥，樓臺半倚山。',96,'全唐诗/poet.song.52000.json','["野闊蓮宮迥，樓臺半倚山。", "地聯巴峽近，門對濮溪灣。", "柏徑松烟濕，石房雨蘚斑。", "白雲邀客住，明月伴僧閒。", "經梵喧譁外，香燈杳靄間。", "勝遊成邂逅，危搆喜躋攀。", "世路誠何極，塵心久欲還。", "輶車正催發，緩步出重關。"]'),
('1e0f4ec6-ccb4-4063-a9a2-477a5e9c6164','藥洲','許彥先','宋','宋诗','song-poetry','','[]','花藥氛氳海上洲，水中雲影带沙流。',32,'全唐诗/poet.song.52000.json','["花藥氛氳海上洲，水中雲影带沙流。", "直應路與銀潢接，槎客時來犯斗牛。"]'),
('6e20aee3-4a8a-4bfe-9804-95d956bbd54c','再遊陽春通真巖','許彥先','宋','宋诗','song-poetry','','[]','壁倚乾寧碣，龕籠大業僧。',24,'全唐诗/poet.song.52000.json','["壁倚乾寧碣，龕籠大業僧。", "七年馳使路，兩躡石梯層。"]'),
('eda17895-ee9a-495a-9e03-64ac0832d31e','遊碧落洞二首  其一','許彥先','宋','宋诗','song-poetry','','[]','崖卷層霄闊，溪穿碧玉橫。',24,'全唐诗/poet.song.52000.json','["崖卷層霄闊，溪穿碧玉橫。", "銀河一派水，終日瀉天聲。"]'),
('f7bfea9e-492e-405f-8c3f-6940e8b233ac','遊碧落洞二首  其二','許彥先','宋','宋诗','song-poetry','','[]','玉峰刳不盡，滿室碧琅玕。',24,'全唐诗/poet.song.52000.json','["玉峰刳不盡，滿室碧琅玕。", "太始藏靈氣，寥寥五月寒。"]'),
('0141fa4e-e71f-41fd-9a6c-66b767d5f156','南山宣聖廟竊見太守黄公題名有作  其一','許彥先','宋','宋诗','song-poetry','','[]','千仞巖巖湧白雲，不教紫翠落塵氛。',32,'全唐诗/poet.song.52000.json','["千仞巖巖湧白雲，不教紫翠落塵氛。", "長留雨後凭欄意，堆疊清光伴使君。"]'),
('6bbed65a-3157-44c4-ae62-2849e208dbbc','南山宣聖廟竊見太守黄公題名有作  其二','許彥先','宋','宋诗','song-poetry','','[]','數仞環分一徑深，講筵深處暮烟沈。',32,'全唐诗/poet.song.52000.json','["數仞環分一徑深，講筵深處暮烟沈。", "金鈴木舌新揚意，忠孝昭昭剌史心。"]'),
('dd08adb6-e856-4ed2-9bd2-0a42924fc4e9','湖上十亭','許彥先','宋','宋诗','song-poetry','','[]','昔年曾看海陽圖，巧狀湖山恐見誣。',32,'全唐诗/poet.song.52000.json','["昔年曾看海陽圖，巧狀湖山恐見誣。", "今日登臨真可愛，畫圖翻覺少工夫。"]'),
('68d2582b-22d6-46d0-87c5-d7c7895e6b8a','題舜井斷碑','許彥先','宋','宋诗','song-poetry','','[]','一千二百餘年外，萬古銷磨不可尋。',64,'全唐诗/poet.song.52000.json','["一千二百餘年外，萬古銷磨不可尋。", "舜子井泉誰記古，隨人閭巷祇如今。", "隸書字雜科蟲體，氏爵名存樂石陰。", "登覽時來醒醉眼，也勝他物在園林。"]'),
('88940aa4-bd2a-4de1-aae7-29604fb1d223','知府伯常度支宿熙春台輒成拙詩上寄','張紘','宋','宋诗','song-poetry','','[]','雲藏雨意明還暗，水激溪聲斷復來。',32,'全唐诗/poet.song.52000.json','["雲藏雨意明還暗，水激溪聲斷復來。", "恨君不且留千騎，同折巖花對酒杯。"]'),
('da541a60-778f-479e-86d5-17c619700146','句','郭汝賢','宋','宋诗','song-poetry','','[]','萬工填巨海，千古作良田。',12,'全唐诗/poet.song.52000.json','["萬工填巨海，千古作良田。"]'),
('fd9f9bae-bac5-4576-825c-40e5ddfd1bfc','題迎薰閣','張杲之','宋','宋诗','song-poetry','','[]','虛閣勢崢嶸，高陵涿鹿城。',120,'全唐诗/poet.song.52000.json','["虛閣勢崢嶸，高陵涿鹿城。", "前瞻青巀嶭，下闞碧澄泓。", "弊宇隨時去，雕甍不日成。", "佳蓮供夏景，喬木送秋聲。", "乳鷺欣雙入，北鴻想萬程。", "風生舜弦古，月射庾樓清。", "隠隠分行客，憧憧憫細氓。", "憑高愁自失，懷遠恨難平。", "賞縱棋兼酒，吟羞石對瑛。", "炎蒸登覽者，方愛此嘉名。"]'),
('b36cfc24-30ba-401e-b0e2-872d3f43c55e','賦得同江華令貫之黄兄遊陽華巖一篇','練潜夫','宋','宋诗','song-poetry','','[]','萬里蒼山麓，陽華古洞天。',240,'全唐诗/poet.song.52000.json','["萬里蒼山麓，陽華古洞天。", "晨光迎海日，晝暝入溪烟。", "穴窾蛟龍蟄，峰巉鬼魅鎸。", "初筵堂半闢，末勢霤孤穿。", "玉乳垂虛竇，金沙引漫泉。", "欄危浮絕壁，庋迥跨遙川。", "隠約燒丹竈，橫斜種玉田。", "劌桐魚燭燭，撾石鼓鼘鼘。", "翠羽岩蕉靜，玄幢石桂圓。", "捫穹藤黝糾，襯步草茵綿。", "暫止蘇門嘯，來因葉縣仙。", "籃輿收弱屐，桂檝盪輕舷。", "勝賞平生興，尋幽最可憐。", "奇遊陵宇宙，班坐馥蘭荃。", "谷鳥酤新釀，松風韵古弦。", "祇應銷永晝，何用蠹塵編。", "蔣賦初無得，元銘久更妍。", "留連資曠士，吟詠屬高賢。", "塵土閑中厭，山林老更便。", "臨分凉月白，回首正依然。"]'),
('a2e2758e-a614-4634-a618-2bef1e76219c','遊層巖','練潜夫','宋','宋诗','song-poetry','','[]','朝尋白鵝山，夕次層巖曲。',228,'全唐诗/poet.song.52000.json','["朝尋白鵝山，夕次層巖曲。", "中虛谷窈窕，一水流其腹。", "澄渟注淵奫，冬夏不盈縮。", "初疑有神物，毛骨森戚促。", "魂驚不敢吐，髮膩不敢沐。", "跨梁怛臨深，矧敢濯余足。", "聞昔宅祕怪，蒙鴻狀河瀆。", "黄昏嘷猩鼯，正晝飛蝙蝠。", "豚肩走巫覡，歌舞神所欲。", "尋幽到其趾，精爽戒託宿。", "張公熙寧初，曾是舒幽獨。", "鎸題百許字，煥爛奪人目。", "幾呵護守嚴，百魅不敢觸。", "往往風雨夜，啾啾鬼神哭。", "乃知正直士，所至即蒙福。", "往時元次山，今日蔣穎叔。", "或鑱陽華銘，或刻舜祠錄。", "與公成三人，萬代仰高躅。", "因書巖石間，聊用美淇澳。"]'),
('709f518d-34fa-49c5-80b1-0d031a7f1d83','約東坡遊金山','徐疇','宋','宋诗','song-poetry','','[]','黯淡灘頭一艇橫，夕陽西下大江平。',32,'全唐诗/poet.song.52000.json','["黯淡灘頭一艇橫，夕陽西下大江平。", "與君不負平生約，同向金鼇背上行。"]'),
('2ce049bc-e0d0-45bf-ac61-f7a8859e9823','連都官祭歌','王莘','宋','宋诗','song-poetry','','[]','恂好善兮行以躬，完素履兮一初終。',96,'全唐诗/poet.song.52000.json','["恂好善兮行以躬，完素履兮一初終。", "化邦鄉兮革姦凶，出爲政兮用其中。", "三鍾山兮屹穹崇，與公德兮並其隆。", "豈獨文兮耀幽宮，宜配社兮同勾龍。", "俾世世兮倣而從，里閭樂兮廉讓風。", "刑罰措兮年屨豐，慱哉利兮垂無窮。"]'),
('0e66b668-67b4-4c75-b739-a5214854f900','白雲庵','許仲蔚','宋','宋诗','song-poetry','','[]','雲本山家物，庵茅相就居。',48,'全唐诗/poet.song.52000.json','["雲本山家物，庵茅相就居。", "竹扉閒自掩，烟凍冷無餘。", "嶺上來還去，風前卷復舒。", "禪僧却應笑，擾擾竟何如。"]'),
('9588a972-fcbd-4599-a7cf-9988dd6ad6c5','和許廣淵南山','許仲蔚','宋','宋诗','song-poetry','','[]','青山疊疊水重重，古道纔容匹馬通。',64,'全唐诗/poet.song.52000.json','["青山疊疊水重重，古道纔容匹馬通。", "飛鳥自由啼晚照，落花無著趁春風。", "巖前積靄參差綠，天末餘霞點綴紅。", "一一廣陵如在眼，詩壇誰敢較豪雄。"]'),
('01d0efef-9930-4b93-8977-cf0f285a6ad9','杜公井','許仲蔚','宋','宋诗','song-poetry','','[]','德地見圖牒，神機發杜稜。',48,'全唐诗/poet.song.52000.json','["德地見圖牒，神機發杜稜。", "寇圍炎甚火，壺飲冽於冰。", "古邑桑田換，靈源鑑面澄。", "如今風月夕，煮茗詫山僧。"]'),
('aa6415b9-1363-4ea8-9ea1-ace477b44991','鍊丹井','許仲蔚','宋','宋诗','song-poetry','','[]','青雲路在天，棄鼎亦徒然。',48,'全唐诗/poet.song.52000.json','["青雲路在天，棄鼎亦徒然。", "九轉果何物，一泓空舊泉。", "競知丹可煮，不悟骨非仙。", "汲引殊無狀，翻尤葛稚川。"]'),
('c0e69acb-17a0-417a-89f6-647e801b795c','放生池','許仲蔚','宋','宋诗','song-poetry','','[]','唐家舊佛祠，樓閣影參差。',48,'全唐诗/poet.song.52000.json','["唐家舊佛祠，樓閣影參差。", "魚散不知處，水流無斷時。", "山光朝暮變，人事古今移。", "惟有好生德，恩波尚滿池。"]'),
('1bf2e770-a6e3-4d39-8ec3-48ba7ce7fb94','百丈山','許仲蔚','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','勢擎霄漢直，根截亂山兼。',48,'全唐诗/poet.song.52000.json','["勢擎霄漢直，根截亂山兼。", "雲葉閑鋪地，烟煤潤灑嶺。", "遠疑題塞雁，高欲篆秋蟾。", "倒瀉長江水，陶泓未足沾。"]'),
('9299ae18-9e91-4ad5-b884-86598d16d96d','葛溪','許仲蔚','宋','宋诗','song-poetry','','[]','一道碧琉璃，靈源杳不知。',48,'全唐诗/poet.song.52000.json','["一道碧琉璃，靈源杳不知。", "寒通鍊丹井，潤接放生池。", "釣叟相從處，仙翁有到時。", "徘徊無所見，月艇去猶夷。"]'),
('4b41a331-5c3f-4fe7-abcd-6f79bfb03c95','廣利廟','許仲蔚','宋','宋诗','song-poetry','','[]','遺靴存故事，碑斷不知名。',48,'全唐诗/poet.song.52000.json','["遺靴存故事，碑斷不知名。", "老木合雙抱，荒祠間數楹。", "編民陰有賜，神像凜於生。", "簫鼓寒溪上，歡呼賀歲成。"]'),
('f6090762-e83e-491c-bc7f-918ca707b8c1','碧治寺','許仲蔚','宋','宋诗','song-poetry','','[]','松竹森森匝四圍，一回來此一忘歸。',64,'全唐诗/poet.song.52000.json','["松竹森森匝四圍，一回來此一忘歸。", "猿攀東嶺啼寒月，僧指西峰笑落暉。", "山色雲含牽客思，池光風動射人衣。", "樂山樂水皆仁智，豈倦驅馳到翠微。"]'),
('e6100ed2-ed6b-4218-8396-0f26d253f88c','羅隠宅','許仲蔚','宋','宋诗','song-poetry','','[]','吟魂散何處，舊居荒可嗟。',48,'全唐诗/poet.song.52000.json','["吟魂散何處，舊居荒可嗟。", "江山間白日，圖籍落誰家。", "野燒寒煨龦，春風暖自花。", "詩名蟠不得，埋沒任桑麻。"]'),
('f9e3e346-fe2d-4490-aa71-4a848bed9de0','留題曹娥廟','蕭闢','宋','宋诗','song-poetry','','[]','屈平以楚死，死濁不死清。',228,'全唐诗/poet.song.52000.json','["屈平以楚死，死濁不死清。", "伍員以吳死，死暗不死明。", "死者人所難，一死鴻毛輕。", "壯哉二子爲，留得不死名。", "曹娥以父死，年齡童未成。", "抱屍出洪瀾，非可二子并。", "二子諫不從，齊秦韓魏征。", "娥若不之死，父葬鱣與鯨。", "二子死以介，娥死以孝誠。", "於今會稽人，事之如事生。", "娥若生堯時，舜不妻女英。", "娥若逢孔子，娥名書孝經。", "娥父若罹辜，豈止爲緹縈。", "蔡邕不知娥，但愛碑上銘。", "我來拜祠下，古木寒雲橫。", "往往大江水，猶作哀哀鳴。", "安得娥有知，爲我神陰靈。", "鼓此大江波，注入四瀆平。", "洗濯天下心，皆行娥所行。"]'),
('a2c62e01-c6b9-4adb-8c61-57c558846b1c','送程給事知越州','陳康民','宋','宋诗','song-poetry','','[]','五羊城郭一朝新，歸作黄扉侍從臣。',64,'全唐诗/poet.song.52000.json','["五羊城郭一朝新，歸作黄扉侍從臣。", "暫向天邊辭禁闥，更於江外福吾民。", "錦衣上冢鄉山曉，熊軾頒條驛路春。", "不待期年應報政，即看朝覲對嚴宸。"]'),
('26069b6a-61b1-445b-b6c9-f0cab83e9df4','題招提院靜照堂','張賁','宋','宋诗','song-poetry','','[]','缾錫爲生久，門闌過客疏。',48,'全唐诗/poet.song.52000.json','["缾錫爲生久，門闌過客疏。", "於間見真寂，燕坐此清虛。", "事事皆身外，悠悠度歲餘。", "如何繁草木，還長舊庭除。"]'),
('c4c3679a-2144-4757-a392-007f8b8d2d90','薛嶺','張翥','宋','宋诗','song-poetry','','[]','衣冠陳氏族，桃李薛公園。',48,'全唐诗/poet.song.52000.json','["衣冠陳氏族，桃李薛公園。", "場老遺文古，巖僧舊跡存。", "苔磯荒磧岸，金榜勒瑶琨。", "已憐松特異，尤喜石能翻。"]'),
('5b1ed2e0-d185-45bd-b6c2-c8c7a52ee586','送王迪夫婦偕隠','劉純臣','宋','宋诗','song-poetry','','[]','髮如抹漆左參軍，脫去青衫從隠淪。',64,'全唐诗/poet.song.52000.json','["髮如抹漆左參軍，脫去青衫從隠淪。", "世上更無羈絆事，壺中別有自由身。", "鼎烹玉兔山前藥，花看金鰲背上春。", "莫怪少年能决烈，藍田夫婦總登真。"]'),
('37a3cda2-86f5-439c-a958-ab26035ccbdf','詠周貫','劉純臣','宋','宋诗','song-poetry','','[]','八十西山作酒仙，麻鞋乳斷布衣穿。',32,'全唐诗/poet.song.52000.json','["八十西山作酒仙，麻鞋乳斷布衣穿。", "形骸一脫塵緣盡，太極光陰不記年。"]'),
('add9a821-39b9-4746-83ae-e8c5aeb09d93','遊風水洞','許遵','宋','宋诗','song-poetry','','[]','水洞連風洞，精藍兩洞前。',48,'全唐诗/poet.song.52000.json','["水洞連風洞，精藍兩洞前。", "山高易藏日，樹老不知年。", "板有華宗什，名留少傅篇。", "烟波門外境，寂寞變桑田。"]'),
('6d98530a-7034-486d-850e-a8b787917409','廬州','許遵','宋','宋诗','song-poetry','','[]','金鑾失職下蓬瀛，也向淮邊領郡城。',64,'全唐诗/poet.song.52000.json','["金鑾失職下蓬瀛，也向淮邊領郡城。", "堆案簿書爲俗吏，滿樓山色負吟情。", "廬江地近音塵斷，何遜詩來格調清。", "未得尊前一開口，可憐心緒獨摇旌。"]'),
('7d871248-3974-4570-92de-b8e7b60a8ad8','大雨聯句','程建用','宋','宋诗','song-poetry','','[]','庭松偃蓋如醉，夏雨凄凉似秋。',28,'全唐诗/poet.song.52000.json','["庭松偃蓋如醉，夏雨凄凉似秋。", "有客高吟擁鼻，無人共喫饅頭。"]'),
('fe3fbd4e-9de7-465a-a099-b3bdfc2c3543','大雨聯句','楊咨','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.52000.json','["無正文。"]'),
('e476cb22-373a-49dd-8e61-a9548b9bbd06','賦新繁周表權如詔亭','黎持正','宋','宋诗','song-poetry','','[]','義教名亭梗概存，要將詩禮及雲孫。',64,'全唐诗/poet.song.52000.json','["義教名亭梗概存，要將詩禮及雲孫。", "當年偶出嚴君意，後日冥符內使言。", "座釂撥醅披茜綬，人觀新榜駐高軒。", "汝南盛事誰能得，未獨于公納駟門。"]'),
('d674f3b5-62b3-4afd-8654-1b964fe24a48','壽傅守','黄革','宋','宋诗','song-poetry','','[]','來日中元毓寇公，萬年事業一朝同。',64,'全唐诗/poet.song.52000.json','["來日中元毓寇公，萬年事業一朝同。", "入陪清切星辰履，出奏循良屏翰功。", "棣萼一時騰最治，棠陰兩紀繼遺風。", "陰功數卷書金簡，遐算應須等岱嵩。"]'),
('38c2a79c-8fbb-49aa-8ec6-ae50401d4128','東峰亭','劉讀','宋','宋诗','song-poetry','','[]','黄塵數騎捷書來，嘯入東峰醉倚臺。',64,'全唐诗/poet.song.52000.json','["黄塵數騎捷書來，嘯入東峰醉倚臺。", "遙看山川消殺氣，同欣寰宇掃氛埃。", "當年巖谷碑千字，曠世功名土一抔。", "有美斯人風烈壯，故亭重葺畫圖開。"]'),
('a6b07b01-35d8-45aa-8e65-940d18253911','下第投荆公','饒竦','宋','宋诗','song-poetry','','[]','又還垂翅下烟霄，歸指臨川去路遙。',32,'全唐诗/poet.song.52000.json','["又還垂翅下烟霄，歸指臨川去路遙。", "二畝荒田須賣却，要錢準備納青苗。"]'),
('bb0014b8-b92d-4c66-b1ca-6a61c2b1d999','岑崎山','朱素','宋','宋诗','song-poetry','','[]','小洞隠遙岑，松蘿翠復陰。',24,'全唐诗/poet.song.52000.json','["小洞隠遙岑，松蘿翠復陰。", "遊人曾到不，方信白雲深。"]'),
('a115b49e-9c30-4139-8f89-9a5f0bcd3d79','頌  其一','陳易','宋','宋诗','song-poetry','','[]','密坐研窮省細微，到頭須是自忘機。',64,'全唐诗/poet.song.52000.json','["密坐研窮省細微，到頭須是自忘機。", "應無祖佛能超越，豈有冤親更順違。", "歷歷孤明猶認影，巍巍獨步尚披衣。", "翻嗟會得昭靈者，也道尋師得旨歸。"]'),
('2d0769f4-d8bb-41a3-b98e-80753d89cd77','頌  其二','陳易','宋','宋诗','song-poetry','','[]','個中端的有誰知，知者歸來到者稀。',64,'全唐诗/poet.song.52000.json','["個中端的有誰知，知者歸來到者稀。", "即見即聞還錯會，離聲離色轉乖違。", "山青水綠明玄旨，鶴唳猿啼顯妙機。", "有意覓渠終不遇，無心到處盡逢伊。"]'),
('794c495e-b399-4f61-a2a6-e02a26aee915','遊石所題于軒壁','陳易','宋','宋诗','song-poetry','','[]','酒吸陽春入肺腸，茶罷清風生肘腋。',32,'全唐诗/poet.song.52000.json','["酒吸陽春入肺腸，茶罷清風生肘腋。", "安知石所洞中人，不是武陵溪上客。"]'),
('de1f13e8-5141-45b7-b095-33558ab1cd5d','答有需禪師','陳易','宋','宋诗','song-poetry','','[]','年來多病愛棲禪，寶鑑慵將照醜妍。',32,'全唐诗/poet.song.52000.json','["年來多病愛棲禪，寶鑑慵將照醜妍。", "却憶南湖孤頂月，定回金磬落巖前。"]'),
('2eac20cd-1e04-4a6c-b25d-56e7466299ca','石門歌','釋有需','宋','宋诗','song-poetry','','[]','吾結草菴蔡溪側，四顧峰巒皆峭壁。',192,'全唐诗/poet.song.52000.json','["吾結草菴蔡溪側，四顧峰巒皆峭壁。", "石門千仞鎖天津，來者欲登那措足。", "住此庵中是何緣，不詩不頌亦不禪。", "饑來苦菜和根煮，疊石爲床困即眠。", "日照諸峰陰羃羃，負暄孤坐情何適。", "馴伏珍禽趁不飛，猨猱捫我衣中蝨。", "閑搘瘦筇六七尺，山行野步扶危力。", "披雲入草不辭勞，逢人打破修行窟。", "或停松，或坐石，靜聽溪泉漱鳴玉。", "源深洞邃來不休，聲聲奏盡無生曲。", "雜羽流商誰辨的，五音六律徒敲擊。", "有時乘興上高峰，大笑狂歌天地窄。"]'),
('fd1c7d5e-8e3a-40dc-b1a9-e6d9b221dc77','寄陳聘君體常','釋有需','宋','宋诗','song-poetry','','[]','拂石跏趺樹影寬，定回霜月照人寒。',32,'全唐诗/poet.song.52000.json','["拂石跏趺樹影寬，定回霜月照人寒。", "此時況味誰知得，寫與秋藤居士看。"]'),
('546a39a4-9c2a-44fa-b27a-af73539ed85e','遊東禪寺','張某','宋','宋诗','song-poetry','','[]','好峰飛去後，流出亂雲根。',24,'全唐诗/poet.song.52000.json','["好峰飛去後，流出亂雲根。", "應爲留僧住，□□□□門。"]'),
('d834f6db-2cf3-48f8-8d38-c50be8486445','澹山巖','胡奕','宋','宋诗','song-poetry','','[]','一景曲彎彎，初遺號澹山。',48,'全唐诗/poet.song.52000.json','["一景曲彎彎，初遺號澹山。", "崖邊烟草亂，石上雨苔班。", "客往長時望，僧居永日閑。", "幾迴將欲去，心只在巖間。"]'),
('6b517de6-c07b-48aa-be8a-191681bfd776','頌','釋重喜','宋','宋诗','song-poetry','','[]','地爐無火一囊空，雪似楊花落歲窮。',32,'全唐诗/poet.song.52000.json','["地爐無火一囊空，雪似楊花落歲窮。", "乞得苧麻縫破衲，不知身在寂寥中。"]'),
('0dbe9434-ad7f-4837-84b8-8632924a34e4','句','釋重喜','宋','宋诗','song-poetry','','[]','行到寺中寺，坐觀山外山。',12,'全唐诗/poet.song.52000.json','["行到寺中寺，坐觀山外山。"]'),
('8047f193-98cf-49e2-9ce8-f970e6962a64','投李珦廟三首  其一','張芝','宋','宋诗','song-poetry','','[]','風軟潮生江水平，遙峰隠隠浸寒青。',32,'全唐诗/poet.song.52000.json','["風軟潮生江水平，遙峰隠隠浸寒青。", "自從香骨沉波底，獨我爲詩吊爾靈。"]'),
('b66c5d99-d001-4b25-b88d-c5a8f1b9f46f','投李珦廟三首  其二','張芝','宋','宋诗','song-poetry','','[]','軋軋櫓聲離遠浦，蕭蕭帆影落寒濤。',32,'全唐诗/poet.song.52000.json','["軋軋櫓聲離遠浦，蕭蕭帆影落寒濤。", "殷勤滴酒陳佳果，將此深心慰寂寥。"]'),
('059dbc68-6d04-4273-90ed-bb2c21b32b21','投李珦廟三首  其三','張芝','宋','宋诗','song-poetry','','[]','江雨初晴遠岸低，心因啼鳥陡思歸。',32,'全唐诗/poet.song.52000.json','["江雨初晴遠岸低，心因啼鳥陡思歸。", "爾如會我題詩意，魂夢相求一處飛。"]'),
('08bcfb49-951a-4afb-98b5-c3c6543800a6','十竹','釋清順','宋','宋诗','song-poetry','','[]','城中寸土如寸金，幽軒種竹只十箇。',32,'全唐诗/poet.song.52000.json','["城中寸土如寸金，幽軒種竹只十箇。", "春風慎勿長兒孫，穿我階前綠苔破。"]'),
('e0023153-d6d6-477e-94e3-56725c9a4e22','林下','釋清順','宋','宋诗','song-poetry','','[]','久從林下遊，頗識林下趣。',48,'全唐诗/poet.song.52000.json','["久從林下遊，頗識林下趣。", "縱渠綠陰繁，不礙清風度。", "閑來石上眠，落葉不知數。", "一鳥忽飛來，啼破幽寂處。"]'),
('c2721e55-d2c8-4b32-923c-b2e8b0ea67e9','西湖僧舍','釋清順','宋','宋诗','song-poetry','','["\u897f\u6e56"]','竹暗不通日，泉聲落如雨。',24,'全唐诗/poet.song.52000.json','["竹暗不通日，泉聲落如雨。", "春風自有期，桃李亂深塢。"]'),
('1d3b3d9f-3a41-4a2d-9213-e5d687915346','宿天竺','釋清順','宋','宋诗','song-poetry','','[]','昔人不可見，行路多長松。',48,'全唐诗/poet.song.52000.json','["昔人不可見，行路多長松。", "空遺煉丹處，井幹綠苔封。", "月明還獨宿，白雲下疏鐘。", "夜半桂子落，不知自何峰。"]'),
('4b427375-6d64-4513-9c0b-5352b7e054b9','書景舒菴壁','釋清順','宋','宋诗','song-poetry','','[]','大布君能衣，始知蠶口非。',48,'全唐诗/poet.song.52000.json','["大布君能衣，始知蠶口非。", "冢間容一榻，身外但三衣。", "護戒避生草，浄心觀落暉。", "寂寥能自守，今世固應稀。"]'),
('6cd6d881-94a0-46c0-b7ad-16ca08e4f2c4','留別句容簿','高坦','宋','宋诗','song-poetry','','[]','巖下相逢不忍還，狂歌醉酒且盤桓。',32,'全唐诗/poet.song.52000.json','["巖下相逢不忍還，狂歌醉酒且盤桓。", "仇香莫問神仙事，天上人間總一般。"]'),
('6e121966-2643-4d39-9cbd-8e9bbf081a12','句','李頎','宋','宋诗','song-poetry','','[]','但看青玉五枝燈，蟠螭火盡光欲然。',16,'全唐诗/poet.song.52000.json','["但看青玉五枝燈，蟠螭火盡光欲然。"]'),
('1c44ef3b-20e9-4906-b269-fba595bfb8a4','夢中詩','張亶','宋','宋诗','song-poetry','','[]','天風吹散赤城霞，染出連雲萬樹花。',32,'全唐诗/poet.song.52000.json','["天風吹散赤城霞，染出連雲萬樹花。", "誤入醉鄉迷去路，傍人應笑不還家。"]'),
('3f686c0f-3e77-4f39-8cca-13ca5f01f848','題招提院靜照堂','陸伸','宋','宋诗','song-poetry','','[]','閑房增締構，宴坐隔囂埃。',48,'全唐诗/poet.song.52000.json','["閑房增締構，宴坐隔囂埃。", "屋木不加飾，庭花時自開。", "虛明殊止水，寂絕等寒灰。", "齋外無餘事，欣逢高士來。"]'),
('e0e2bcdb-a6a9-445e-9c95-69c95fb6983e','神劍頌','勇禪師','宋','宋诗','song-poetry','','[]','提得神鋒勝太阿，萬年妖孽盡消磨。',32,'全唐诗/poet.song.52000.json','["提得神鋒勝太阿，萬年妖孽盡消磨。", "直饒埋向塵泥裏，爭奈靈光透匣何。"]'),
('3b836bd6-24e1-462d-abc1-4508efe501d0','頌一首','勇禪師','宋','宋诗','song-poetry','','[]','胡孫兒子太惺惺，愛弄千年鬼眼睛。',32,'全唐诗/poet.song.52000.json','["胡孫兒子太惺惺，愛弄千年鬼眼睛。", "不現宰官身說法，時時來我頂頭行。"]'),
('d0baceb6-5bd3-4d82-a324-63ddabe7b934','神劍頌呈勇禪師','顯首座','宋','宋诗','song-poetry','','[]','凜凜寒光出匣時，乾坤閃爍耀潜輝。',32,'全唐诗/poet.song.52000.json','["凜凜寒光出匣時，乾坤閃爍耀潜輝。", "當鋒坐斷毗盧頂，更有何妖作是非。"]'),
('447b3273-e590-4cda-921c-6585f890a31e','柳花','王巖叟','宋','宋诗','song-poetry','','[]','銀毬拋出翠烟深，聚散高低不自禁。',32,'全唐诗/poet.song.52000.json','["銀毬拋出翠烟深，聚散高低不自禁。", "飄去長郊迎暖日，飛來深院怯春陰。"]'),
('5eda22ef-5c7f-4221-99b1-10623a801ffa','芡','王巖叟','宋','宋诗','song-poetry','','[]','水精冷浸碧叢玉，琉璃湧出青毛蝟。',32,'全唐诗/poet.song.52000.json','["水精冷浸碧叢玉，琉璃湧出青毛蝟。", "何人采得離波瀾，劈破顆顆生光寒。"]'),
('8d778806-4b3e-4297-840b-0e1c34e6cf4d','和公齊臨替有感見寄','王巖叟','宋','宋诗','song-poetry','','[]','孤宦邊城遇衆賢，及瓜能不動依然。',64,'全唐诗/poet.song.52000.json','["孤宦邊城遇衆賢，及瓜能不動依然。", "風號古木葉堆地，雲攪遙山水拍天。", "籬菊開時寒有信，賓鴻過後暑無權。", "古今惜別君須念，乘暇何妨倒酒船。"]'),
('7dd4d1f4-24b4-42b6-8235-dbda379c09ea','揚州感舊','王巖叟','宋','宋诗','song-poetry','','[]','隠隠蕪城枕碧流，繁華曾是帝王州。',64,'全唐诗/poet.song.52000.json','["隠隠蕪城枕碧流，繁華曾是帝王州。", "一聲水調滿明月，十里春風半畫樓。", "白鳥不離圖上去，江雲長在鑑中遊。", "廢興屈指千年事，何異行人寄傳郵。"]'),
('7588778f-c035-4ccf-975d-538ac2ccf06d','望釣臺','王巖叟','宋','宋诗','song-poetry','','[]','桐江快人眼，江水綠于苔。',48,'全唐诗/poet.song.52000.json','["桐江快人眼，江水綠于苔。", "一棹中流去，千山兩岸來。", "風摇黄葉落，潮捲白沙開。", "欲問嚴陵事，雲中望釣臺。"]'),
('4fbb3fb5-e44f-4b1c-bd0d-ffcfa74ba241','延慶寺','王巖叟','宋','宋诗','song-poetry','','[]','龍影函潭寺已空，惟餘翠竹混青松。',24,'全唐诗/poet.song.52000.json','["龍影函潭寺已空，惟餘翠竹混青松。", "路窮西北無他景。"]'),
('6f69d5b0-5f11-45a9-af6f-8d78205ff028','駕幸太學','王巖叟','宋','宋诗','song-poetry','','[]','享餘精意煥龍章，就促鑾輿視上庠。',64,'全唐诗/poet.song.52000.json','["享餘精意煥龍章，就促鑾輿視上庠。", "億萬圜觀人作堵，三千迎拜士成行。", "虛心訪道資洪業，異禮尊儒冠百王。", "四海嚮風知自勸，足應愚魯亦升堂。"]'),
('7c0dfad9-c759-4b0a-b47c-a3f962978314','存目  其一','王巖叟','宋','宋诗','song-poetry','','[]','詩題：陪孫之翰太博登成都樓首句：齪齪古之人。',22,'全唐诗/poet.song.52000.json','["詩題：陪孫之翰太博登成都樓首句：齪齪古之人。"]'),
('c9eec0e9-14c2-451a-885a-332fe3746fd8','存目  其二','王巖叟','宋','宋诗','song-poetry','','[]','詩題：霧山首句：霧山環合自雲川。',16,'全唐诗/poet.song.52000.json','["詩題：霧山首句：霧山環合自雲川。"]'),
('7d2d6e78-ea94-4f58-9918-71d4648308fa','廬山雜興  其一','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','古帝論匡山，南國之德鎮。',108,'全唐诗/poet.song.52000.json','["古帝論匡山，南國之德鎮。", "邇來得躋攀，此語始吾信。", "雄雄壓九江，矗矗排萬仞。", "青天落飛瀑，白日雷霆震。", "石鏡俄忽開，孤光舞而運。", "異花無冬春，瑶草亦芳潤。", "遠公初渡江，道譽藹東晉。", "劉雷贊高風，遯世各無悶。", "陳迹虎溪頭，于今誰與訊。"]'),
('3ea6dadd-4ad3-48ed-9160-4dcba6e421fb','廬山雜興  其二','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','衆峰勢連環，萬疊不可窮。',72,'全唐诗/poet.song.52000.json','["衆峰勢連環，萬疊不可窮。", "香爐獨秀拔，佳氣常葱葱。", "長風卷游霧，曉壁開曈矓。", "招提出其下，樓觀排青紅。", "回眸盻五老，刻削金芙蓉。", "宜哉謫仙子，愛此巢雲松。"]'),
('5eacddcf-9afe-4ed3-bec9-798504fc270f','廬山雜興  其三','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','白鶴峰後原，逶迤曠平陸。',96,'全唐诗/poet.song.52000.json','["白鶴峰後原，逶迤曠平陸。", "道周問樵子，古實青牛谷。", "披榛得徑路，曳杖驚麋鹿。", "鮑生古騷人，曾過鍊師宿。", "明月古壇邊，題詩記脩竹。", "茲焉廢耕隴，歲晏空菽粟。", "薄日靜銜山，驚湍瀉哀玉。", "回首睇吾廬，風幡隔林麓。"]'),
('849d7a2d-f630-4646-996a-e3ee986f1321','廬山雜興  其四','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','山南信美矣，山北尤增奇。',84,'全唐诗/poet.song.52000.json','["山南信美矣，山北尤增奇。", "春風錦繡谷，紅素自相依。", "梯空上絕巘，雲日驚倒窺。", "崖壁暈祥光，五色成頗梨。", "旁通大林寺，松竹短且欹。", "樂天當日游，四月桃始披。", "餘齡願寄此，永與人世違。"]'),
('40f604f1-b2e5-40df-927b-d94f0b70d936','廬山雜興  其五','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','少文好山林，每往輒忘歸。',72,'全唐诗/poet.song.52000.json','["少文好山林，每往輒忘歸。", "余生千載後，獨與斯人違。", "朅來爐峰下，結宇聊棲遲。", "長林拱茂木，九夏遺炎曦。", "溪雨晝忽破，藤花照清漪。", "黄鸝語深竹，可聽不可窺。"]'),
('b3eabd6c-bf5a-477d-a80b-1597f204ec8b','廬山雜興  其六','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','暮峰騰玄雲，飛雨來滂沱。',84,'全唐诗/poet.song.52000.json','["暮峰騰玄雲，飛雨來滂沱。", "亂點洒蒼壁，森森挂青蘿。", "須臾漲前溪，蕩蕩浮銀河。", "中流轉巨石，出沒如黿鼉。", "天宇夜開霽，星蟾瑩摩挲。", "玲瓏辨崖樹，宛轉照庭柯。", "詠詩無桀句，奈此佳景何。"]'),
('d20af8f5-356a-4a5d-9683-0b6be6eb1ff6','廬山雜興  其七','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','中巖不知暑，但覺晝景長。',96,'全唐诗/poet.song.52000.json','["中巖不知暑，但覺晝景長。", "朝來出孤定，踽踽行西岡。", "風泉漱石齒，松雨飛蒼蒼。", "猿鳥亦我喜，鹿麋還相將。", "喬林積翠下，粲然矚孤芳。", "冉冉抱絕格，霏霏浮暗香。", "山祇善守護，每吐雲霧藏。", "寄言樵蘇子，慎勿輕摧傷。"]'),
('75a1c32a-5290-4986-879b-88281983fcea','廬山雜興  其八','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','龍湫亙三峽，草木皆森奇。',108,'全唐诗/poet.song.52000.json','["龍湫亙三峽，草木皆森奇。", "禪餘得支徑，別塢行逶迤。", "上人吳門秀，邈有方外姿。", "芒鞋襯兩足，策策欣相追。", "秋田罷刈穫，雲水明空陂。", "雙雙林中禽，文彩光陸離。", "雍容事飲啄，相顧忘驚飛。", "鮮飈忽騰馥，巖桂飄葳蕤。", "峰端臥落日，眷此忘還期。"]'),
('c0732467-b654-4f82-85c9-2d9a12d12fca','廬山雜興  其九','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','霜清玉繩曉，澗谷風未號。',84,'全唐诗/poet.song.52000.json','["霜清玉繩曉，澗谷風未號。", "澄潭不可極，俛盼驚骨毛。", "豈不有神物，於茲能遁逃。", "海日射兩崖，餘輝何昭昭。", "游鱗出岸穴，翻覆如銀刀。", "偶來殊不惡，勝事俄所遭。", "聊爲五字詠，遠愧謝與陶。"]'),
('d638ff20-6e1e-4b73-b1eb-47b78a2402b6','廬山雜興  其一○','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','山深雲物清，挹玩洗浮慮。',72,'全唐诗/poet.song.52000.json','["山深雲物清，挹玩洗浮慮。", "昨日行澗南，飄然即芒屨。", "風潭耿危彴，晚與樵爭度。", "隔水認梅花，方驚歲華暮。", "幽人眇江海，樂事期誰預。", "山月獨多情，娟娟遲歸路。"]'),
('325dc8fa-0003-457a-849b-09f05e49d448','廬山雜興  其一一','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','高巖吐奇雲，倏忽千萬丈。',60,'全唐诗/poet.song.52000.json','["高巖吐奇雲，倏忽千萬丈。", "援毫欲名貌，卷縮非一狀。", "飛仙或遨游，隠隠出其上。", "驚飈忽吹滅，轉盻惟清嶂。", "山中勝事多，彼俗誰能亮。"]'),
('8112a55b-2a57-4332-ab86-1ec9dcf250dc','廬山雜興  其一二','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','圓月未出嶺，衆峰環蒼蒼。',72,'全唐诗/poet.song.52000.json','["圓月未出嶺，衆峰環蒼蒼。", "裴回倚脩竹，遲此清夜光。", "俄驚衆木顛，灧灧浮銀潢。", "玉兔既且躍，浮雲亦難妨。", "須臾經中天，下矚被八荒。", "却瞻中外官，森森斂低昂。"]'),
('f3eabe7a-4c31-4466-b642-03042611eebd','廬山雜興  其一三','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','一月廬山陽，光風動林壑。',72,'全唐诗/poet.song.52000.json','["一月廬山陽，光風動林壑。", "陰崖拆曾冰，隠隠飛溜落。", "曦和伯化工，萬彙欣並作。", "匆匆鳥聲聒，艷艷花霧薄。", "瘦骨喜攀躋，芒鞋便犖確。", "期遇山阿人，賞心將共託。"]'),
('28ba7950-58a0-4850-b072-2b43a8f8e970','廬山雜興  其一四','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','五更山雨餘，海月漏雲表。',72,'全唐诗/poet.song.52000.json','["五更山雨餘，海月漏雲表。", "流輝入庭戶，烱烱白如縞。", "百舌語空林，關關催欲曉。", "衆禽亦和鳴，爲我釋孤抱。", "杉松本奇姿，洗滌看愈好。", "惆悵桃李花，東風卷如掃。"]'),
('305b7039-1d06-4dee-81bc-cb981bdd750d','廬山雜興  其一五','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','通玄接香谷，夾道青松直。',72,'全唐诗/poet.song.52000.json','["通玄接香谷，夾道青松直。", "高秋得微雨，秀色寒更碧。", "林梢挂紅子，照眼明的的。", "散策從所歡，悠悠事遐歷。", "僧坊媚烟篆，笑語戀几席。", "陶謝安在哉，空山獨行迹。"]'),
('3de0b6fc-603e-4b41-83f9-3d13a7e0ef1b','陳季常靜庵','釋道潜','宋','宋诗','song-poetry','','[]','龐公與少陵，不肯入州府。',180,'全唐诗/poet.song.52000.json','["龐公與少陵，不肯入州府。", "畏人嫌其真，但喜歸茅宇。", "先生豈其徒，與世亦齟齬。", "年來作庵榜以靜，靜非對動默即語。", "閉門謝客親荷鋤，秀甲珍芽春滿圃。", "黄雞白酒厭妻孥，醉以詩書相媚娬。", "况復家傳侍郎後，縹囊玉匣收奇古。", "寶刀錯落走金蛇，至藥晶熒嘯鉛虎。", "先生妙齡已絕人，放浪江湖棄簪組。", "居閑自不減前烈，遇物陰施功不數。", "我疑造物已收錄，富貴來尋君勿阻。", "不然騎鶴扣玄關，跨躒松喬攀佛祖。"]'),
('e644920d-48b7-4ecf-80b1-960f0f4b7d31','何氏寒碧堂','釋道潜','宋','宋诗','song-poetry','','[]','城東十畝春蕭瑟，脩竹漫山藹如櫛。',112,'全唐诗/poet.song.52000.json','["城東十畝春蕭瑟，脩竹漫山藹如櫛。", "颼颼細浪鳴石齒，黯黯蒼雲翳朝日。", "虛堂正在無有處，不惜千竿開翠密。", "鳴鳩野鵲亦解喜，頡頏穿林語啾唧。", "但得凉陰過酒樽，莫辭晚色侵書帙。", "蓬萊仙人爲書榜，筆端矯矯龍蛇逸。", "壯觀南來無與倫，千載風流君不失。"]'),
('52f4cba7-3bcf-4bd3-a9f6-81b335f38dad','玉荆山人崔君草堂','釋道潜','宋','宋诗','song-poetry','','[]','玉荆山蒼勢蜿蜒，玉荆澗碧涵漪漣。',128,'全唐诗/poet.song.52000.json','["玉荆山蒼勢蜿蜒，玉荆澗碧涵漪漣。", "山人結廬占幽絕，如使世俗來無緣。", "窗前松竹交夏蔭，砌下紅紫爭春妍。", "清腸終日飽葵藿，耳目久厭論腥膻。", "山空月晝猨鳥寂，象床拂拭翻朱弦。", "泠然細韵發幽指，妙意自得人誰傳。", "烏巾席帽事高格，蹇馿獨跨何翩翩。", "行當近林就卜築，與子來往聊窮年。"]'),
('e08f97d8-26ce-45fc-bdd4-81a21f34fb31','虛寂堂','釋道潜','宋','宋诗','song-poetry','','[]','吾聞卓道士，操節如冰霜。',204,'全唐诗/poet.song.52000.json','["吾聞卓道士，操節如冰霜。", "學窺老莊本，淵然閟光芒。", "當時世莫識，落魄依四方。", "嘗爲京洛游，不踐聲利場。", "衣裾卷塵土，獨鶴翻南翔。", "千里不駐足，飄飄指潯陽。", "潯陽多名山，飛仙共徜徉。", "晚歲隠城郭，古宮極凄凉。", "千金售鄰壤，增築成虛堂。", "流塵斷四壁，虛白浮中央。", "惜哉今已往，吊影空歎傷。", "頼有賢弟子，黄冠挺昂藏。", "區區慕高格，綽欲傳芬芳。", "逐客蘇太史，堂堂國之良。", "言爲天下重，墨妙逾珪璋。", "爲君易華榜，庭戶增輝光。", "風流滿江左，知子非尋常。"]'),
('38e7d8b5-4b4c-4046-86be-26180cc4367e','遊詠真洞贈陶道人','釋道潜','宋','宋诗','song-poetry','','[]','淵明骨已朽，陳迹尚可求。',108,'全唐诗/poet.song.52000.json','["淵明骨已朽，陳迹尚可求。", "我復識其孫，長鬣青兩眸。", "相去僅千載，猶能繼風流。", "寄跡黄冠中，神姿邈清脩。", "相携行洞天，暝色藹已浮。", "松寒語栖鶴，潭靜眠蒼虬。", "蘭膏照深夜，風磬鳴重樓。", "吾廬閟三峽，清凈亦此侔。", "何時駕鹿車，訪我西林丘。"]'),
('c6259f8a-b28a-4d90-ab13-4df86cf00266','廖司法挽辭','釋道潜','宋','宋诗','song-poetry','','[]','吾聞廖夫子，名大不得睹。',120,'全唐诗/poet.song.52000.json','["吾聞廖夫子，名大不得睹。", "讀書盡五車，行義拔前古。", "聚徒從妙齡，所至變鄒魯。", "身雖甘陋巷，志欲望伊呂。", "風雲苟超騰，名教當有補。", "蹉跎鬢毛改，寸祿晚方取。", "青衫適南營，素幔歸湓浦。", "秋原起新隴，寂寞一抔土。", "悲歌動閭里，清血洒如雨。", "蘭玉已含芳，行看秀庭戶。"]'),
('74efff3c-3c07-43a5-9e0b-4bccc4cfd340','絕句','釋道潜','宋','宋诗','song-poetry','','[]','高巖有鳥不知名，款語春風入戶庭。',32,'全唐诗/poet.song.52000.json','["高巖有鳥不知名，款語春風入戶庭。", "百舌黄鸝方用事，汝音雖好復誰聽。"]'),
('c0f426f5-f587-4622-9cb0-3fe3231983c5','覽秀亭','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','飛甍巨棟出高墉，覽秀開亭實有功。',64,'全唐诗/poet.song.52000.json','["飛甍巨棟出高墉，覽秀開亭實有功。", "湓水秋橫簾幙外，廬山晴落酒杯中。", "俯窺城郭千艘轉，仰見星河四面同。", "江左元規存舊觀，孟侯還此繼高風。"]'),
('9fdf2ee2-019f-4d46-b7d0-a5a3e13cef45','歸宗道中','釋道潜','宋','宋诗','song-poetry','','[]','朝日未出海，杖藜適松門。',204,'全唐诗/poet.song.52000.json','["朝日未出海，杖藜適松門。", "老樹暗絕壁，蕭條聞哀猨。", "迤邐轉谷口，悠悠見前村。", "農夫爭道來，聒聒更笑喧。", "數辰競一墟，邸店如雲屯。", "或携布與楮，或驅雞與㹠。", "縱橫箕箒材，瑣細難具論。", "老翁主貿易，俯仰衆所尊。", "區區較尋尺，一一手自翻。", "得無筋力疲，兩鬢埋霜根。", "吾鄉東南會，百貨常源源。", "金鐶衣短後，群奴列崑崙。", "通衢旅犀象，顛倒同籬藩。", "鮫綃與翡翠，觸目亦已繁。", "少壯供所役，耆年臥高軒。", "翁今處窮獨，未易聽我言。", "且當具鹽米，歸家飯兒孫。"]'),
('1c14b5ee-90b0-4b31-abf4-6059b31c5c8f','寄王慎中教授','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','高人屏迹匡廬山，不入州府今幾年。',128,'全唐诗/poet.song.52000.json','["高人屏迹匡廬山，不入州府今幾年。", "煮葵烹藿日一飯，目光炯炯明星懸。", "行脩道富神所憐，絳帳弟子如雲烟。", "憶昨秋風宿曾巘，杖藜扣戶君未眠。", "階松影月不到席，耿耿唯有青燈然。", "高談一傾百慮洗，似拂蒿艾披蘭荃。", "清詩落筆有餘地，頃刻百紙珠璣聯。", "錦囊別後有新句，勿惜東使聊相傳。"]'),
('57af732a-37a0-4950-9046-e6f9a455e4ab','夏日山居  其一','釋道潜','宋','宋诗','song-poetry','','[]','杜宇鳴春已歇，薔薇尚有餘花。',28,'全唐诗/poet.song.52000.json','["杜宇鳴春已歇，薔薇尚有餘花。", "吾廬宛同彭澤，遶屋美蔭交加。"]'),
('b8bb5c7c-c492-4b4e-8a67-8967c7f25a83','夏日山居  其二','釋道潜','宋','宋诗','song-poetry','','[]','苦笋爭抽豸角，枇杷競吐驪珠。',28,'全唐诗/poet.song.52000.json','["苦笋爭抽豸角，枇杷競吐驪珠。", "午飯松間睡足，茶甌滿泛雲腴。"]'),
('47931432-27ad-4b3d-ba48-843808592dc3','夏日山居  其三','釋道潜','宋','宋诗','song-poetry','','[]','紈扇輕裁孤月，竹簟冷織雙紋。',28,'全唐诗/poet.song.52000.json','["紈扇輕裁孤月，竹簟冷織雙紋。", "呼取凉襟幽吹，拂開亂眼浮雲。"]'),
('416ab060-6bdc-426d-93d6-0973fb0ec1ac','夏日山居  其四','釋道潜','宋','宋诗','song-poetry','','[]','麥浪遙翻隴底，雲峰忽起空端。',28,'全唐诗/poet.song.52000.json','["麥浪遙翻隴底，雲峰忽起空端。", "拄杖支頤松下，直須細細吟看。"]'),
('b8d95a53-5a2e-4318-b45d-e71f30ff1437','夏日山居  其五','釋道潜','宋','宋诗','song-poetry','','[]','山月明含草木，溪風暗度襟裳。',28,'全唐诗/poet.song.52000.json','["山月明含草木，溪風暗度襟裳。", "寂寂簾櫳夜半，羽蟲相趁飛揚。"]'),
('1e0284b2-4c86-460b-a3a3-eeb0eed35120','夏日山居  其六','釋道潜','宋','宋诗','song-poetry','','[]','陰洞石床初掃，誰來共飯胡麻。',28,'全唐诗/poet.song.52000.json','["陰洞石床初掃，誰來共飯胡麻。", "鳥道新疏碧注，爲君沉李浮瓜。"]'),
('05a49a82-963e-46a8-a73b-e220dfd9654f','夏日山居  其七','釋道潜','宋','宋诗','song-poetry','','[]','古徑斜依杉竹，薰風永日無人。',28,'全唐诗/poet.song.52000.json','["古徑斜依杉竹，薰風永日無人。", "噪鵲鳴鳩去後，一聲幽磬南鄰。"]'),
('6a7fad86-7d39-4713-a25d-6772f157ed3a','夏日山居  其八','釋道潜','宋','宋诗','song-poetry','','[]','門外溪行碧玉，林梢日墮黄金。',28,'全唐诗/poet.song.52000.json','["門外溪行碧玉，林梢日墮黄金。", "好景莫愁吟盡，會看月出遙岑。"]'),
('712215d4-4b18-4e08-be7f-c718be4662ce','夏日山居  其九','釋道潜','宋','宋诗','song-poetry','','[]','山雨洗開林幄，梧桐日射荆扉。',28,'全唐诗/poet.song.52000.json','["山雨洗開林幄，梧桐日射荆扉。", "傍砌榴花初吐，照人特地光輝。"]'),
('390c38a0-9146-4055-a930-55fea56d7ed4','夏日山居  其一○','釋道潜','宋','宋诗','song-poetry','','[]','遠壑尚餘殘照，飛蚊已鬧前簷。',28,'全唐诗/poet.song.52000.json','["遠壑尚餘殘照，飛蚊已鬧前簷。", "巢燕歸來何暮，呼童爲汝開簾。"]'),
('ed796067-d940-4993-986f-b78b2de0bb99','秋江','釋道潜','宋','宋诗','song-poetry','','[]','赤葉楓林落酒旗，白沙洲渚夕陽微。',32,'全唐诗/poet.song.52000.json','["赤葉楓林落酒旗，白沙洲渚夕陽微。", "數聲柔櫓蒼茫外，何處江村人夜歸。"]'),
('57ae891f-4451-418f-b325-a59085c34559','周茂叔郎中濂溪','釋道潜','宋','宋诗','song-poetry','','[]','蓮花峰下水，東出其流長。',180,'全唐诗/poet.song.52000.json','["蓮花峰下水，東出其流長。", "十里漱石齒，鏘然韵珩璜。", "坡陀滀野岸，烱烱浮明光。", "衣冠有曠士，眷此宜徜徉。", "乞身不待老，結屋栖其旁。", "高風慕箕潁，不羨尚書郎。", "松菊手自插，葱葱蔚連岡。", "了無川澤營，庶以廉自方。", "禽魚出階塹，詎識矰繳防。", "雲山侑几席，風月非迎將。", "萬事委空洞，頹然寄壺觴。", "詩書叢屋壁，教子心獨强。", "翹翹雙鳳雛，炳炳具文章。", "婆娑刷勁翮，雲漢期翱翔。", "高名與溪水，千載同湯湯。"]'),
('0940e00d-f57f-4a70-a789-147f771b43e2','陶宣德逸老堂  其一','釋道潜','宋','宋诗','song-poetry','','[]','湓浦城南舊隠淪，一堂無地可栖塵。',32,'全唐诗/poet.song.52000.json','["湓浦城南舊隠淪，一堂無地可栖塵。", "石床春臥荼醾砌，撩亂餘花墮酒巾。"]'),
('0b6a4d04-50d5-45e8-830e-6db9a8d48f51','陶宣德逸老堂  其二','釋道潜','宋','宋诗','song-poetry','','[]','歸來詩酒洽天機，騷客無煩詠式微。',32,'全唐诗/poet.song.52000.json','["歸來詩酒洽天機，騷客無煩詠式微。", "三徑就荒松菊在，洗除蒿艾浄秋暉。"]'),
('7d73b63c-8fc1-48d8-8fde-603da314e5af','夜渡採石','釋道潜','宋','宋诗','song-poetry','','[]','滄江夜半月沉輝，客子行舟失渺瀰。',32,'全唐诗/poet.song.52000.json','["滄江夜半月沉輝，客子行舟失渺瀰。", "不用然犀剛照耀，波間百怪惡人窺。"]'),
('0929dfc3-2ae2-4dbe-b024-082db8eb432c','秋日西園  其一','釋道潜','宋','宋诗','song-poetry','','[]','日月更代顯，光華難並留。',132,'全唐诗/poet.song.52000.json','["日月更代顯，光華難並留。", "昔人尚行樂，俯仰無暫休。", "平居得君子，出處常相求。", "良辰援余臂，共作西園遊。", "極目瞰平野，緬然見蒼洲。", "千林澹霽色，萬韵生凉秋。", "露華漙菊英，藹藹香可揉。", "參差間畦壠，芋栗森相儔。", "綠蔓無芳姿，碧花茂牽牛。", "低回矚籬落，樹影環清流。", "賞物志已諧，何用登蓬丘。"]'),
('1714d2bc-3d58-42a6-a514-971a7d11e63a','秋日西園  其二','釋道潜','宋','宋诗','song-poetry','','[]','山家無外營，超然閉幽室。',132,'全唐诗/poet.song.52000.json','["山家無外營，超然閉幽室。", "薄團北窗下，默坐終永日。", "炎景忽差池，凉飈動蕭瑟。", "中林多橘柚，粲粲垂華實。", "凭高試裴回，幽興遽超逸。", "雲霞散平岡，太白空際出。", "禽歸杳莫辨，積翠鎖深蔚。", "吁哉宇宙間，濩落竟一物。", "胡爲市朝客，終歲浪汩沒。", "翳吾樂餘生，勝事良可詰。", "放懷在冥冥，身世兩俱失。"]'),
('c3dc2edc-5d22-42d8-ba22-7bd386478ec4','秋日西園  其三','釋道潜','宋','宋诗','song-poetry','','[]','嘗聞晉支遁，矯志歸沃洲。',108,'全唐诗/poet.song.52000.json','["嘗聞晉支遁，矯志歸沃洲。", "千載激清風，邈哉誰與儔。", "余今雖不敏，萬事非身謀。", "朅來臥窮谷，未覺慙先脩。", "一法尚無遣，何勞問三休。", "卷舒在至理，賞詠歸優游。", "採薇陟曾阿，濯足依澗流。", "但驚桂花拆，詎識江漢秋。", "滄溟空汗漫，無意狎群鷗。"]'),
('2e17a1a8-e90b-4b5f-89d2-b79b0d3f462d','秋日西園  其四','釋道潜','宋','宋诗','song-poetry','','[]','憶昔少壯時，意氣摩雲霓。',120,'全唐诗/poet.song.52000.json','["憶昔少壯時，意氣摩雲霓。", "游心黄卷間，豈顧白日西。", "由來昧根本，旦旦從所迷。", "邇獨悟無爲，文字如委泥。", "物生豈高下，至道良自齊。", "青山繞吾廬，開戶衆鳥啼。", "曉日上喬木，秋光媚回溪。", "畸人長往來，絕壁同攀躋。", "遐天浄若掃，曠目無端倪。", "楚客一何苦，登臨獨曈曈。"]'),
('50f5e2da-e473-421f-ad84-cb9264d3dce6','秋日西園  其五','釋道潜','宋','宋诗','song-poetry','','[]','秋山夜來雨，雲氣朝尚昏。',96,'全唐诗/poet.song.52000.json','["秋山夜來雨，雲氣朝尚昏。", "禪庭無來轍，但見落葉繁。", "石室暗燈火，天容開霽痕。", "耳目思遠適，曠然啟曾軒。", "長謠緩輕策，去去窮深源。", "方塘灧清流，鳬雁靜不喧。", "時遭羲皇翁，容與諧笑言。", "邈然採真賞，歲晏誰與論。"]'),
('95c65097-7388-4c1c-bf8d-f2263f0535ff','寄題濟源令楊君蘭軒','釋道潜','宋','宋诗','song-poetry','','[]','昔人慕猗蘭，佩服比脩潔。',104,'全唐诗/poet.song.52000.json','["昔人慕猗蘭，佩服比脩潔。", "往往卒歲間，山中行採掇。", "吁哉昔人去已久，此花憔悴今誰折。", "濟源長官真好古，王屋天壇馳遠步。", "陽崖月窟得芳叢，滿握歸來誇所遇。", "凈掃幽軒植蘚墀，紫莖綠葉弄奇姿。", "疏簾風軟日華薄，芳馥滿懷君自知。"]'),
('7a0ba8c8-7eeb-45ac-882c-b803bf232e7f','送琳上人還杭','釋道潜','宋','宋诗','song-poetry','','[]','聚水作一雨，多少近遠隨所遭。',254,'全唐诗/poet.song.52000.json','["聚水作一雨，多少近遠隨所遭。", "或霑枯荄僅濡浹，或入巨海成波濤。", "少林真風今百紀，悵惜至此何蕭條。", "喜君齊志早寂寞，同我十載淪芻樵。", "含沖嗜漠不自厭，更欲刺口嘗群餚。", "師門祖席在在有，得此失彼良自嘲。", "朅來東南走千里，但願刈楚逢翹翹。", "駃浮長川不憚惡，陟彼巨巘寧知勞。", "誠專志苦若有相，行斷西壤逢英豪。", "金鎚扣天玄楗廓，玉電激海明珠高。", "星霜因循共千日，誰爾使子先行包。", "湖山蜿蜒湖水薄，湖上幽人想如昨。", "秋入芙蓉露已漙，曉捲簾櫳暑初却。", "明明潭底見行雲，謾謾空中聞唳鶴。", "此景從來吾已知，異鄉寧羨君先歸。", "由來出處元無隔，同看明朝日上時。"]'),
('578c32cf-f0d7-49f6-8f1a-660482fcb097','春日即事呈定海尉葛叔忱','釋道潜','宋','宋诗','song-poetry','','[]','曾臺宿霞披，滴瀝朝露濕。',152,'全唐诗/poet.song.52000.json','["曾臺宿霞披，滴瀝朝露濕。", "有客獨登臨，含情空佇立。", "問君佇立何所爲，報言遠人嘗有期。", "菊花黄日出山去，芳草綠時猶未歸。", "萬壑千巖望何極，願託孤鴻寄消息。", "少年游衍易蹉跎，翻恐歸來不相識。", "滿目春暉花爛熳，花底幽禽自相喚。", "紛紛萬類皆有從，獨我參差邈雲漢。", "勸君不用長相思，容顔消竭神空疲。", "無情况有西樓月，夜夜清光照不虧。"]'),
('7e3ab11a-5e4c-4379-baa1-96fe33976214','臨平道中','釋道潜','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u5199\u666f"]','風蒲獵獵弄輕柔，欲立蜻蜓不自由。',32,'全唐诗/poet.song.52000.json','["風蒲獵獵弄輕柔，欲立蜻蜓不自由。", "五月臨平山下路，藕花無數滿汀洲。"]'),
('f33ae30a-807a-4a70-a977-c1afead1529f','寄龍井辨才法師','釋道潜','宋','宋诗','song-poetry','','[]','法師安遠徒，我見常磬折。',168,'全唐诗/poet.song.52000.json','["法師安遠徒，我見常磬折。", "頹綱製像運，基搆甚宏達。", "煌煌四十載，說法傾吳越。", "人天會方丈，萬趾常雜遝。", "藹然如丘山，四座羞蟻垤。", "投老倦揮麈，毅然辭且决。", "饑鷹得秋風，轉盼俄一掣。", "結茅南山陲，雲蘿占幽絕。", "昔我海上還，相尋訪林樾。", "夜闌叩微要，猨鳥寂不聒。", "慧風洒幽襟，法雨濯枯枿。", "別來今四載，寒暑驚屢闋。", "相望如晨星，杳杳各天末。", "何當從杖藜，一笑龍泓月。"]'),
('10ea7592-8afa-4818-8186-b3ab6849079a','再遊鶴林寺','釋道潜','宋','宋诗','song-poetry','','[]','招隠山南寺，重來歲已寒。',48,'全唐诗/poet.song.52000.json','["招隠山南寺，重來歲已寒。", "風林驚墜雪，雨澗咽飛湍。", "壁暗詩千首，霜清竹萬竿。", "東軒謫仙句，洗眼共君看。"]'),
('22257b8d-9e96-4865-9be6-a7e5be75c91f','江上秋夜','釋道潜','宋','宋诗','song-poetry','','[]','雨暗蒼江晚未晴，井梧翻葉動秋聲。',32,'全唐诗/poet.song.52000.json','["雨暗蒼江晚未晴，井梧翻葉動秋聲。", "樓頭夜半風吹斷，月在浮雲淺處明。"]'),
('2f3d8023-a98f-498a-93b2-94f1a77b83ce','邵仲恭許相過金山未至','釋道潜','宋','宋诗','song-poetry','','[]','二月歸來江上居，江流變淥江鷗去。',112,'全唐诗/poet.song.52000.json','["二月歸來江上居，江流變淥江鷗去。", "時移物改何足論，身世悠悠本非固。", "鳩鳴屋角山雨餘，花苞破紅滿芳樹。", "晴窗曉日幽興催，振衣出戶凌高臺。", "潮回浪死風色定，縹緲沙岸烟中開。", "故人佳期絕消息，滿眼空看暮雲碧。", "何日扁舟南渡來，一洒高風破吾臆。"]'),
('f84502c2-2d3d-4b4a-b6d8-24d6fae73bda','維王府園與王元規承事同賦  其一','釋道潜','宋','宋诗','song-poetry','','[]','年少王郎一幅巾，杖藜呼我步城闉。',32,'全唐诗/poet.song.52000.json','["年少王郎一幅巾，杖藜呼我步城闉。", "紅泥亭子闌干外，絕目遙看萬樹春。"]'),
('b6ef6250-4622-409d-ab7b-f53660a39596','維王府園與王元規承事同賦  其二','釋道潜','宋','宋诗','song-poetry','','[]','一霎催花驟雨來，集芳堂下錦千堆。',32,'全唐诗/poet.song.52000.json','["一霎催花驟雨來，集芳堂下錦千堆。", "浪紅狂紫渾爭發，不待商量細細開。"]'),
('2051f3bb-8530-4adc-b4c3-ae898a77e8a1','維王府園與王元規承事同賦  其三','釋道潜','宋','宋诗','song-poetry','','[]','藹藹春空宿霧披，桃溪柳陌共逶迤。',32,'全唐诗/poet.song.52000.json','["藹藹春空宿霧披，桃溪柳陌共逶迤。", "阿戎莫道無才思，細草幽花總要詩。"]'),
('ed4e6e47-0c10-4315-b5c1-30816d8bb3cb','春晚  其一','釋道潜','宋','宋诗','song-poetry','','[]','疊穎叢條翠欲流，午陰濃處聽鳴鳩。',32,'全唐诗/poet.song.52000.json','["疊穎叢條翠欲流，午陰濃處聽鳴鳩。", "兒童賭罷榆錢去，狼藉春風漫不收。"]'),
('4ff22ef6-9777-4c17-9199-3d133c374e60','春晚  其二','釋道潜','宋','宋诗','song-poetry','','[]','曉風池沼水瀾翻，春盡淮南麥秀寒。',32,'全唐诗/poet.song.52000.json','["曉風池沼水瀾翻，春盡淮南麥秀寒。", "院落無人日亭午，柳花如雪滿闌干。"]'),
('74e15ee9-f9de-432f-9fb6-caf07df5a42c','春晚  其三','釋道潜','宋','宋诗','song-poetry','','[]','怪雨盲風卷却春，傍欄蕭瑟只青筠。',32,'全唐诗/poet.song.52000.json','["怪雨盲風卷却春，傍欄蕭瑟只青筠。", "引雛燕子朝來去，回首多情語更頻。"]'),
('85165dfe-3e7e-4644-9554-bcba408de7b6','邵伯道中  其一','釋道潜','宋','宋诗','song-poetry','','[]','一道河流遠接天，兩行官柳復蕭然。',32,'全唐诗/poet.song.52000.json','["一道河流遠接天，兩行官柳復蕭然。", "村舂歷歷鳴何處，彷彿孤烟落日邊。"]'),
('8177446f-eaf3-46e1-8a6c-11a65c6672a0','邵伯道中  其二','釋道潜','宋','宋诗','song-poetry','','[]','回首山光古寺基，拂天寒木耿斜暉。',32,'全唐诗/poet.song.52000.json','["回首山光古寺基，拂天寒木耿斜暉。", "孤撐漸與鍾聲遠，但見風幡竹外飛。"]'),
('f6a0cdfb-034a-499b-8a69-776a8a858f04','平山堂觀雨','釋道潜','宋','宋诗','song-poetry','','[]','午枕藜床夢忽驚，柳邊雷送雨如傾。',32,'全唐诗/poet.song.52000.json','["午枕藜床夢忽驚，柳邊雷送雨如傾。", "蜀岡西望蕪城路，銀竹森森十里橫。"]'),
('d92eb1e9-a061-441f-ac65-bc95f109fb07','建隆秋夜  其一','釋道潜','宋','宋诗','song-poetry','','[]','梵唄聲沈香霧銷，月明金殿影岧嶢。',32,'全唐诗/poet.song.52000.json','["梵唄聲沈香霧銷，月明金殿影岧嶢。", "夜深唯有龕燈在，風露滿庭人寂寥。"]'),
('8b10e8ec-fbb1-4d2e-aef4-1e70891d861e','建隆秋夜  其二','釋道潜','宋','宋诗','song-poetry','','[]','娟娟雲月照窗扉，紙帳形開夢覺時。',32,'全唐诗/poet.song.52000.json','["娟娟雲月照窗扉，紙帳形開夢覺時。", "庭下風篁自成韵，吹簫安用玉人爲。"]'),
('2e39af17-7edc-4020-b2b4-86ea363807c4','晚步','釋道潜','宋','宋诗','song-poetry','','[]','叢薄蕭蕭朔吹翻，暝鴉遼亂欲投村。',32,'全唐诗/poet.song.52000.json','["叢薄蕭蕭朔吹翻，暝鴉遼亂欲投村。", "江南雪後山無數，林表纔分翠一痕。"]'),
('66717ade-5e87-4bf6-82b0-d793e883ece2','次韵閻永仁博士同飲蜀井','釋道潜','宋','宋诗','song-poetry','','[]','潭潭古甃閟高岡，脩綆低懸百尺長。',64,'全唐诗/poet.song.52000.json','["潭潭古甃閟高岡，脩綆低懸百尺長。", "廋語樂天推絕特，第泉鴻漸許甘凉。", "金盤謾說漙秋露，玉碗休誇沃蔗漿。", "更有碧梧盤爽蔭，坐驚亭午失驕陽。"]'),
('19e5ab7b-0190-40b2-a81c-9a4cc714205d','次韵永仁見贈','釋道潜','宋','宋诗','song-poetry','','[]','憐君泣血依墳墓，雖設衡門不妄開。',64,'全唐诗/poet.song.52000.json','["憐君泣血依墳墓，雖設衡門不妄開。", "盈几貝多翻百遍，同龕彌勒禮千回。", "夜寒幽鳥窺香火，歲暮鄰僧數往來。", "何日爲余重掃榻，臥聽松韵落清哀。"]'),
('3b207b0f-aa4f-46f7-a307-a2294a18fbb1','次韵何子溫龍圖見贈','釋道潜','宋','宋诗','song-poetry','','[]','春破邗溝古驛旁，揮毫邂逅沈東陽。',64,'全唐诗/poet.song.52000.json','["春破邗溝古驛旁，揮毫邂逅沈東陽。", "自慙擊壤無高韵，但愧投珠有異光。", "曠達未應輸靖節，風流可復羨知章。", "我非照鏡迷頭客，一接清歡亦似狂。"]'),
('1a5c26a8-1f38-46a3-9aa6-4418d2becf47','楊康功待制所藏醉道士石','釋道潜','宋','宋诗','song-poetry','','[]','天官夜燕瓊樓春，一官大醉頹穹旻。',128,'全唐诗/poet.song.52000.json','["天官夜燕瓊樓春，一官大醉頹穹旻。", "飛光貫地若素練，百里雞犬聲紛紛。", "吹風洗雨歲月古，化此頑石良悲辛。", "楚山之老頗知異，濯以澗底清漪淪。", "霓裳彷彿認羽客，楮冠數寸橫秋雲。", "空齋晝閑戲一擊，琅然哀韵還清真。", "我聞天官天所陳，雖復暫屈終當申。", "烈風迅雷一朝作，却上蒼蒼朝紫宸。"]'),
('722c5784-b905-433e-ae62-cd5d63629228','乾明夜坐懷孫莘老學士','釋道潜','宋','宋诗','song-poetry','','[]','余生飄泊猶斷蓬，詎肯低回附根柢。',96,'全唐诗/poet.song.52000.json','["余生飄泊猶斷蓬，詎肯低回附根柢。", "茲焉得坎謾栖止，一日從風即輕逝。", "淮南十月寒未苦，耿耿虛堂屬宵外。", "星辰錯落挂簷廡，爽氣侵尋入衣袂。", "桐葉聲翻玉露圓，竹枝影掃金波碎。", "安得南鄰龐老翁，揮麈堂堂坐相對。"]'),
('ef0425b6-f89f-48cd-9c56-b59346d6dd1e','維陽府學四柏堂','釋道潜','宋','宋诗','song-poetry','','[]','頖宮本凄凉，庭戶無冗長。',108,'全唐诗/poet.song.52000.json','["頖宮本凄凉，庭戶無冗長。", "蒼然餘四栢，終日清相向。", "夫人擅所有，高懷益超放。", "炎蒸五六月，大厦如甕盎。", "凉飈天外來，披拂逾一餉。", "怳如乘虛舟，破月渡溟漲。", "嚴冬衆木死，薿薿獨無恙。", "非求造化私，故與冰雪抗。", "宜亦有神明，茲焉陰所相。"]'),
('8c2cba9b-ae26-4be7-980b-09c41cda243d','次韵少游學士送龔深之往金陵見王荆公  其一','釋道潜','宋','宋诗','song-poetry','','[]','春風隨意可嬉娛，水有舟航陸有車。',32,'全唐诗/poet.song.52000.json','["春風隨意可嬉娛，水有舟航陸有車。", "應笑楊雄未忘我，閉門猶著解嘲書。"]'),
('8e6c5cde-271a-4c0e-ace2-6c3fef3166fe','次韵少游學士送龔深之往金陵見王荆公  其二','釋道潜','宋','宋诗','song-poetry','','[]','夢幻皆輸古竺乾，功名何用咤燕然。',32,'全唐诗/poet.song.52000.json','["夢幻皆輸古竺乾，功名何用咤燕然。", "羨君一棹江南去，碧薺時魚暮雨邊。"]'),
('756b9222-f3a7-4d9b-8896-fc9bcbcc2b05','次韵少游學士送龔深之往金陵見王荆公  其三','釋道潜','宋','宋诗','song-poetry','','[]','虎踞龍盤亦漫雄，城荒狐兔往來通。',32,'全唐诗/poet.song.52000.json','["虎踞龍盤亦漫雄，城荒狐兔往來通。", "可人惟有秦淮月，出沒娟娟波浪中。"]'),
('89c5877d-91fe-4cc5-9d62-c3781a9b5486','次韵少游學士送龔深之往金陵見王荆公  其四','釋道潜','宋','宋诗','song-poetry','','[]','白下長干春霧披，家家桃李粲朝暉。',32,'全唐诗/poet.song.52000.json','["白下長干春霧披，家家桃李粲朝暉。", "懸知一見毗耶老，心地如灰不更飛。"]'),
('8f50095a-28a8-4085-a964-a13fed5743e5','次韵黄子理宣德田居四時  其一','釋道潜','宋','宋诗','song-poetry','','[]','四序自逶迤，田園常局促。',108,'全唐诗/poet.song.52000.json','["四序自逶迤，田園常局促。", "春陽旋東皋，迫我事銚鎒。", "出種曝籬根，驅牛飲溪曲。", "暉暉明朝陽，聒聒喧布穀。", "頹齡惜筋骸，曉睡謾云足。", "蓐食出柴門，荷篠赴幽谷。", "搴條視柔桑，密葉已舒綠。", "今年氣候早，膏雨厭霢霂。", "鄰翁時一來，耕耨每相屬。"]'),
('3dfb34f9-9daf-4c52-be71-c7ca1c4d1fcf','次韵黄子理宣德田居四時  其二','釋道潜','宋','宋诗','song-poetry','','[]','離離小麥黄，習習南風度。',120,'全唐诗/poet.song.52000.json','["離離小麥黄，習習南風度。", "桑棗暗蓬麻，耘鋤困朝暮。", "種瓜屋東隅，翠蔓已分布。", "黄花引疏籬，冉冉欲橫路。", "白水漫青秧，聯翩下鷗鷺。", "新絲換濁酒，肴蔌羞薄具。", "掃洒聚比鄰，環坐蔭高樹。", "稚子羨贏餘，牽衣傍翁嫗。", "牛羊嶺外歸，落日林梢去。", "餉婦亦還家，笑言隔烟霧。"]'),
('714680bb-026f-42f5-9cc8-b32a8add47e9','次韵黄子理宣德田居四時  其三','釋道潜','宋','宋诗','song-poetry','','[]','村落已徂暑，蚊蠅尚喧啾。',132,'全唐诗/poet.song.52000.json','["村落已徂暑，蚊蠅尚喧啾。", "衡門霽朝雨，茅竹歸新秋。", "機絲迫鄰女，札札無停休。", "中田藹黄稼，爛熳如雲浮。", "淥蟻釀新甕，嘉魴釣清流。", "瓦尊遲來客，禮數忘獻酬。", "三盃未肯辭，笑語方綢繆。", "時平盜自隠，場圃無宵憂。", "兒孫漸束髮，婚嫁迫所謀。", "款曲從我言，歸途蹇淹留。", "林端有月色，相送前溪頭。"]'),
('8b2aa830-491c-48e5-94c8-3b739e5d3b99','次韵黄子理宣德田居四時  其四','釋道潜','宋','宋诗','song-poetry','','[]','朔吹鳴高林，回塘冰已結。',120,'全唐诗/poet.song.52000.json','["朔吹鳴高林，回塘冰已結。", "牛羊臥茅屋，原野暗飛雪。", "壯男臂彫弓，短後事田獵。", "饑鷹一號呼，荒徑洒毛血。", "歸來誇意氣，鄰舍呼飲啜。", "明朝過南山，更欲窮窟穴。", "寒爐然豆萁，光燄時起滅。", "布被擁嬌兒，從渠踏裏裂。", "老翁寢不寐，展轉念鵝鴨。", "籬落易穿窬，狐狸恐驚發。"]'),
('d78c24e8-9c0b-4f9c-b032-d25f06753c29','和龍直夫秘校細雨  其一','釋道潜','宋','宋诗','song-poetry','','[]','細雨連阡陌，輕雲濕不飛。',48,'全唐诗/poet.song.52000.json','["細雨連阡陌，輕雲濕不飛。", "池寒鷗自臥，巢冷燕催歸。", "慘澹疑沈樹，飄蕭忽近幃。", "簷花霑已久，稍欲墮人衣。"]'),
('32f99d1b-27c9-4538-aa6b-477275ea8568','和龍直夫秘校細雨  其二','釋道潜','宋','宋诗','song-poetry','','[]','薄霧兼寒雨，凌晨靄未分。',48,'全唐诗/poet.song.52000.json','["薄霧兼寒雨，凌晨靄未分。", "細宜池上見，清愛竹邊聞。", "斗帳侵蘭夢，虛櫺逼蕙薰。", "晚來欣小霽，鈎箔見疏雲。"]'),
('7cd852cb-65d1-4d69-b969-a644f1707077','和龍直夫秘校細雨  其三','釋道潜','宋','宋诗','song-poetry','','[]','傍砌飄纔斷，從風强更來。',48,'全唐诗/poet.song.52000.json','["傍砌飄纔斷，從風强更來。", "斑斑泣蛛網，浥浥汗江梅。", "薄日光時漏，曾陰意未開。", "少陵心易感，詩句寫清哀。"]'),
('64ebac0a-7d04-4dd5-8902-a4121480c3da','次韵孫傳師龍圖游醴泉寺','釋道潜','宋','宋诗','song-poetry','','[]','楊林幾曲到城根，中有招提氣象昏。',64,'全唐诗/poet.song.52000.json','["楊林幾曲到城根，中有招提氣象昏。", "暝雀聚群盤棟吻，老藤垂蔓覆高垣。", "月生歸路無燈火，巷轉人家有笑言。", "却掩吾廬還寂寞，冷風摇幔影翩翻。"]'),
('da602fd6-8b8b-45d7-af10-817b741a69a9','春晴  其一','釋道潜','宋','宋诗','song-poetry','','[]','積雨久不破，曾陰蔽城闕。',84,'全唐诗/poet.song.52000.json','["積雨久不破，曾陰蔽城闕。", "曉來得春風，掃蕩凈六合。", "綽約牆頭花，依微带殘月。", "少年誰家子，驊騮飛蹀躞。", "揚鞭出郊去，逸興生林樾。", "黄鳥弄柔音，青梅已堪折。", "行樂須及辰，芳時易消歇。"]'),
('c18402b3-ab6a-4010-94da-be2e276ed0e1','春晴  其二','釋道潜','宋','宋诗','song-poetry','','[]','寒食東城隅，青楊夾馳道。',72,'全唐诗/poet.song.52000.json','["寒食東城隅，青楊夾馳道。", "高樓暖鳳笙，絕曲聞縹緲。", "晴日動鞦韆，飛烟拂瑶草。", "南鄰與北里，良辰競爲好。", "人生逆旅間，何必事枯槁。", "仰首笑春風，茲懷誰與造。"]'),
('c91d1392-f563-4010-81a1-6daa4cfa97f8','東園  其一','釋道潜','宋','宋诗','song-poetry','','[]','斜照明明射竹籬，桑陰翳翳麥蛾飛。',32,'全唐诗/poet.song.52000.json','["斜照明明射竹籬，桑陰翳翳麥蛾飛。", "蕭條一徑無來轍，時見羸牛引犢歸。"]'),
('e0216429-4343-4d30-85e8-0702b12ccc65','東園  其二','釋道潜','宋','宋诗','song-poetry','','[]','曲渚回塘孰與期，杖藜終日自忘歸。',32,'全唐诗/poet.song.52000.json','["曲渚回塘孰與期，杖藜終日自忘歸。", "隔林彷彿聞機杼，應有人家在翠微。"]'),
('adb099ce-3f56-4097-919d-8999dd112e29','東園  其三','釋道潜','宋','宋诗','song-poetry','','[]','雲峰缺處支筇立，溪溜聲中弄扇行。',32,'全唐诗/poet.song.52000.json','["雲峰缺處支筇立，溪溜聲中弄扇行。", "習習南風吹百草，幽香知有蕙蘭生。"]'),
('720ee096-dcb8-4732-9f1e-e99b0ef1b299','淮上  其一','釋道潜','宋','宋诗','song-poetry','','[]','蘆梢向曉戰秋風，浦口寒潮尚未通。',32,'全唐诗/poet.song.52000.json','["蘆梢向曉戰秋風，浦口寒潮尚未通。", "日出岸沙多細穴，白蝦青蟹走無窮。"]'),
('2d9af14d-e233-454a-a7e6-4654e35db40b','淮上  其二','釋道潜','宋','宋诗','song-poetry','','[]','今夜沙頭月上遲，小螢零碎傍船飛。',32,'全唐诗/poet.song.52000.json','["今夜沙頭月上遲，小螢零碎傍船飛。", "可憐光彩雖無限，何似嬋娟一寸輝。"]'),
('417967f6-1573-450b-a086-f917540b8437','淮上  其三','釋道潜','宋','宋诗','song-poetry','','[]','天闊陰雲低抱樹，沙寒鷗鷺欲親人。',32,'全唐诗/poet.song.52000.json','["天闊陰雲低抱樹，沙寒鷗鷺欲親人。", "小航泊處誰家住，脩竹疏花宛似春。"]'),
('104421b1-c0f0-40f2-bea8-7baaf6693511','冬夜會孫莘老司諫書齋  其一','釋道潜','宋','宋诗','song-poetry','','[]','去馬來車聲已闌，雪雲低壓暮簷寒。',32,'全唐诗/poet.song.52000.json','["去馬來車聲已闌，雪雲低壓暮簷寒。", "地爐山枿燒初熟，軟語聊爲世外歡。"]'),
('40222b9a-1af9-41f8-8e00-5f717f0cc374','冬夜會孫莘老司諫書齋  其二','釋道潜','宋','宋诗','song-poetry','','[]','碧瓦爐焚裊裊香，紅柑紫栗更分嘗。',32,'全唐诗/poet.song.52000.json','["碧瓦爐焚裊裊香，紅柑紫栗更分嘗。", "從來樂事人間少，不惜歸途夜漏長。"]'),
('1be8297c-50a8-43f3-b983-d8f57090bb74','冬夜會孫莘老司諫書齋  其三','釋道潜','宋','宋诗','song-poetry','','[]','多病山人能放曠，忘緣居士解逍遙。',32,'全唐诗/poet.song.52000.json','["多病山人能放曠，忘緣居士解逍遙。", "蒲團疊足清相向，誰道雲林勝市朝。"]'),
('f1b80954-119e-4538-9c47-7f942b039d4b','曉出土山','釋道潜','宋','宋诗','song-poetry','','[]','遶山脩竹曉參差，葉葉塗霜墜碧枝。',32,'全唐诗/poet.song.52000.json','["遶山脩竹曉參差，葉葉塗霜墜碧枝。", "日脚漸高風乍起，蕭蕭恰似雨來時。"]'),
('24b48197-382d-47dd-8585-e690d690f083','寄蔡彥規主簿','釋道潜','宋','宋诗','song-poetry','','[]','遶舍蒼烟晚更凝，隔簾新月未多明。',64,'全唐诗/poet.song.52000.json','["遶舍蒼烟晚更凝，隔簾新月未多明。", "棲烏著樹無餘噪，老檜吟風有細聲。", "客散愈憐真境好，定回猶覺幻身輕。", "可堪俗子能知味，此語聊傳北郭生。"]'),
('4229bfdf-8aaa-41fc-854e-00e357a8f31c','次韵太虛夜坐','釋道潜','宋','宋诗','song-poetry','','[]','古寺冬蕭瑟，天寒色更冥。',48,'全唐诗/poet.song.52000.json','["古寺冬蕭瑟，天寒色更冥。", "捲幃延素月，轉盼失流星。", "爐底眠枯枿，窗根立凍瓶。", "談餘焚栢子，一燧小烟清。"]'),
('e4cdc5a4-4150-4cfb-b960-849f2d22c8db','廣陵城外野步呈莘老','釋道潜','宋','宋诗','song-poetry','','[]','林梢聒聒鳥聲繁，積雪初消澗水渾。',64,'全唐诗/poet.song.52000.json','["林梢聒聒鳥聲繁，積雪初消澗水渾。", "老樹臥波寒影動，野烟浮草夕陽昏。", "風回笛響山前路，犬吠人行竹外村。", "杖屨不知幽興遠，歸來新月在柴門。"]'),
('3144a1d4-6236-4edb-991c-a65eb56b4676','次韵王通叟寺丞見寄','釋道潜','宋','宋诗','song-poetry','','[]','彫斲肝脾欲報公，還如獻豕過遼東。',64,'全唐诗/poet.song.52000.json','["彫斲肝脾欲報公，還如獻豕過遼東。", "珠璣屢獲淵雲妙，土木曾無粲忍風。", "耿耿吟魂嗟異處，迢迢桂魄謾相同。", "錦囊應有新詩在，九曲池邊多塞鴻。"]'),
('06f563a6-7f25-4ffc-9f3b-bebc4e2a83e3','寄仲恭','釋道潜','宋','宋诗','song-poetry','','[]','曉雨霽郛郭，晴雲遞紛披。',96,'全唐诗/poet.song.52000.json','["曉雨霽郛郭，晴雲遞紛披。", "曦和拆萬物，初莖弄葳蕤。", "儵魚泳弱藻，漾漾動碧漪。", "緬彼空際山，黛影摇參差。", "感此芳菲節，美人曠佳期。", "音形眇何方，莽莽天一涯。", "長河泮春冰，花浪激箭馳。", "好憑三尺鯉，寄我相思詩。"]'),
('5034c0b1-bd48-45d3-8aeb-017accbba961','早秋南樓書事','釋道潜','宋','宋诗','song-poetry','','[]','白帝初回天地秋，井梧葉老陰尚稠。',160,'全唐诗/poet.song.52000.json','["白帝初回天地秋，井梧葉老陰尚稠。", "森森爽氣入屏幔，骨冷魂清無汗流。", "覺來覽眺覓佳處，挾冊獨上西南樓。", "崇山廣澤坐可挹，遠水孤村橫道周。", "上窺青天墮海日，下瞰白鶴盤庭楸。", "誰令濃陰起曾嶂，撲撲亂眼如雲浮。", "埋林漲壑只俄頃，撫袂掩抑將誰儔。", "明星皎月邈難見，絡緯蟋蟀空啁啾。", "安得風生土囊口，萬里一掃無停留。", "王孫未歸空碧草，我思不見徒離憂。"]'),
('ccaea32e-2403-45ec-8f8b-5fc16d4fad29','和莘老經六合西門水亭懷裴學士','釋道潜','宋','宋诗','song-poetry','','[]','折柳相從地，重來失舊柯。',48,'全唐诗/poet.song.52000.json','["折柳相從地，重來失舊柯。", "林光延晚照，岸影動霜波。", "碧圃檀欒密，朱簷翡翠過。", "主人成異物，搔首奈情何。"]'),
('5870b0b0-07cc-490b-b355-192463e69852','和莘老初至溫泉呈慶禪師','釋道潜','宋','宋诗','song-poetry','','[]','年華行已老，林莽尚葱蒼。',48,'全唐诗/poet.song.52000.json','["年華行已老，林莽尚葱蒼。", "地勝連龍窟，泉溫注鬼湯。", "人風遠城市，鍾梵近僧坊。", "九夏來投錫，棲心應更凉。"]'),
('32ee195e-0274-4437-8687-0d827b90b583','再賦溫泉','釋道潜','宋','宋诗','song-poetry','','[]','赭落峰前與世分，溶溶湯井翳深雲。',64,'全唐诗/poet.song.52000.json','["赭落峰前與世分，溶溶湯井翳深雲。", "月生滋穴流寒影，風入華清皺碧紋。", "暗引石池波宛轉，暖蒸苔壁氣氤氳。", "解衣盤礴南窗下，骨肉都融到日曛。"]'),
('06994eec-1dfb-42b9-bac9-d16c0ab42fb5','次韵莘老游龍洞','釋道潜','宋','宋诗','song-poetry','','[]','曈矓杲日破林坰，杖策相將馬暫停。',64,'全唐诗/poet.song.52000.json','["曈矓杲日破林坰，杖策相將馬暫停。", "路與猿猱爭險磴，身隨鴻鵠入青冥。", "巉巖曲穴疑無底，盤屈蒼虬信有靈。", "能使謝公詩興動，宛如游刃發新硎。"]'),
('6d614de1-7091-4029-845a-9c19517a6713','次韵莘老贈顯之','釋道潜','宋','宋诗','song-poetry','','[]','盤盤秀嶺遶曾簷，方丈門開挹翠嵐。',64,'全唐诗/poet.song.52000.json','["盤盤秀嶺遶曾簷，方丈門開挹翠嵐。", "風激松梢聲間發，月留泉底影相涵。", "天機清曉猊臺震，險句窮宵虎穴探。", "白傅異時修故事，杖藜應許到雲庵。"]'),
('9e93c2c9-6c84-4458-9dcb-67233684049c','虛樂亭','釋道潜','宋','宋诗','song-poetry','','[]','誰構新亭近翠微，似教陶令洽天機。',64,'全唐诗/poet.song.52000.json','["誰構新亭近翠微，似教陶令洽天機。", "池光引月來簷廡，竹影疏風到客衣。", "愛酒有時携玉斝，無弦聊自拂金徽。", "人間樂事還能幾，肯向良辰與物違。"]'),
('2c046ff3-8be2-4b77-afe4-cbe2c385b9bf','次韵朱伯收主簿觀雪  其一','釋道潜','宋','宋诗','song-poetry','','[]','朝來密雪蔽天涯，坐目丘園發素華。',64,'全唐诗/poet.song.52000.json','["朝來密雪蔽天涯，坐目丘園發素華。", "初著敗梧驚擁腫，久霑庭竹見欹斜。", "水精不動垂千筯，雲母無聲落萬家。", "安得曾穹返收拾，莫教狼藉渾泥沙。"]'),
('2975e9ae-3de7-4fc6-9db9-9070cbcb6504','次韵朱伯收主簿觀雪  其二','釋道潜','宋','宋诗','song-poetry','','[]','陰風何事吼簷牙，夜半窗前變物華。',64,'全唐诗/poet.song.52000.json','["陰風何事吼簷牙，夜半窗前變物華。", "夢斷只疑蟾影在，褰幃俄駭練光斜。", "苦侵陋巷凌寒士，强入高樓媚酒家。", "霽後請看庭下草，蕙蘭含綠出晴沙。"]'),
('163dd1cd-f666-4a14-b7e3-b194089568b7','次韵姜伯輝朝奉宿九曲池','釋道潜','宋','宋诗','song-poetry','','[]','當時樓闕已桑麻，陳迹何須置齒牙。',64,'全唐诗/poet.song.52000.json','["當時樓闕已桑麻，陳迹何須置齒牙。", "宛轉頹城圍綠野，嶔崟孤塔背明霞。", "山雲度晚飛瓊葉，海月生秋墮桂花。", "圓嶠方壺同笑語，終宵疑在水仙家。"]'),
('dd5d0ea7-4fc9-48bf-90ba-32bb947321c5','邗溝絕句','釋道潜','宋','宋诗','song-poetry','','[]','隔屋蕭蕭風度竹，當空粲粲斗翻芒。',32,'全唐诗/poet.song.52000.json','["隔屋蕭蕭風度竹，當空粲粲斗翻芒。", "崢嶸歲月人間暮，目斷雲山歸興長。"]'),
('fba5c039-9f5b-4237-b0c9-128415182a73','過新開湖寄李端叔大夫','釋道潜','宋','宋诗','song-poetry','','[]','新開湖邊秋夢曉，雞犬無聲人悄悄。',160,'全唐诗/poet.song.52000.json','["新開湖邊秋夢曉，雞犬無聲人悄悄。", "試揭疏篷覘日華，水面殘星猶繚繞。", "嘗聞明珠藏巨浸，光焰一出輝群草。", "篙師爲我暫停櫓，罔象終期入幽討。", "波間宛轉興方豪，依然別恨生懷抱。", "故人離群東海頭，徇祿摧眉事枯槁。", "菰梢蘋末翠猶在，蕙蘭憔悴青楓老。", "浪游不知歲月徙，舊約無端失天杪。", "目羨南鴻兩兩飛，安得身同羽翰小。", "游胥堂在吾必行，一榻數椽應預掃。"]'),
('9a721c40-c995-4621-b02b-2e4b77ef1a11','都下曉霽','釋道潜','宋','宋诗','song-poetry','','[]','千門昨夜雨，萬木曉生光。',48,'全唐诗/poet.song.52000.json','["千門昨夜雨，萬木曉生光。", "御水浮紅蕊，宮雲麗粉牆。", "轉樓遲日靜，縈草亂絲長。", "想像西池路，濃陰覆綠楊。"]'),
('6b0f78a0-c533-43f3-82df-a90e02dd0adc','酬邵彥瞻朝奉見寄','釋道潜','宋','宋诗','song-poetry','','[]','楊州從事多文華，新詩組織如朝霞。',128,'全唐诗/poet.song.52000.json','["楊州從事多文華，新詩組織如朝霞。", "高懷忽念朔方客，秋風一紙來天涯。", "都城冠蓋屬休沐，邂逅過我森如麻。", "開緘傳讀不知厭，愕立圜視相驚誇。", "上言音形闊川路，下言杖屨埋風沙。", "蹲鴟正熟邀我返，城南古寺無諠譁。", "我今翩然已東下，輕舟早晚從公家。", "平山堂西百尺井，請公爲汲烹露芽。"]'),
('8ed7e9c5-7483-4393-9888-9368f20271f7','訪彭門太守蘇子瞻學士','釋道潜','宋','宋诗','song-poetry','','[]','眉山鬰茀眉水清，清淑之氣鍾群形。',272,'全唐诗/poet.song.52000.json','["眉山鬰茀眉水清，清淑之氣鍾群形。", "精璆美璞不能擅，散發宇內爲豪英。", "煌煌蘇氏挺三秀，豫章杞梓參青冥。", "少年著書即稽古，經緯八極何崢嶸。", "未央宮中初射策，落筆游刃揮新硎。", "翰林醉翁發奇歎，臺閣四座爭相驚。", "逡巡傳玩騰衆手，一日紙價增都城。", "同時父子擅芳譽，芝蘭玉樹羅中庭。", "風流浩蕩播江海，粲若高漢懸明星。", "前年聞公適吳會，壺漿跪道人爭迎。", "浮雲流水付幽討，下視世網鴻毛輕。", "野人弱齡不事事，白首丘壑甘忘情。", "神仙高標獨未識，暫棄蘿月人間行。", "朝吳暮楚失邂逅，惝怳夜夢還惸惸。", "邇來旅食寄梁苑，坐歎白日徒虛盈。", "彭門千里不憚遠，秋風匹馬吾能征。", "鈴齋吏退屬幽款，一看揮塵銀河傾。"]'),
('da95dfbf-56a2-460e-9db9-0a6cc6dfc2e7','彭門書事寄少游  其一','釋道潜','宋','宋诗','song-poetry','','[]','我思君處君思我，此語由來自謫仙。',32,'全唐诗/poet.song.52000.json','["我思君處君思我，此語由來自謫仙。", "欲借野人傳紙尾，待憑新雁寄遼天。"]'),
('3e150eb2-08af-4669-9906-3464979e80a6','彭門書事寄少游  其二','釋道潜','宋','宋诗','song-poetry','','[]','戲馬臺邊駐馬蹄，回廊曲院總攀躋。',32,'全唐诗/poet.song.52000.json','["戲馬臺邊駐馬蹄，回廊曲院總攀躋。", "秦郎前日曾來否，試拂凝塵覓舊題。"]'),
('2d6d752e-ae27-4c21-b48e-b7aa3eb56ea5','彭門書事寄少游  其三','釋道潜','宋','宋诗','song-poetry','','[]','百尺黄樓拂杳冥，樓前風物極崢嶸。',32,'全唐诗/poet.song.52000.json','["百尺黄樓拂杳冥，樓前風物極崢嶸。", "東州詞客渾爭詠，獨怪相如賦未成。"]'),
('600c92cb-2712-4365-bf37-28a94041f966','虛白齋','釋道潜','宋','宋诗','song-poetry','','[]','嘉魚滿盤初出水，尚有青萍點紅尾。',96,'全唐诗/poet.song.52000.json','["嘉魚滿盤初出水，尚有青萍點紅尾。", "銀腮戢戢畏烹煎，掘强有時俄自起。", "彼客殷勤贈使君，願向中厨薦醪醴。", "使君事道不事腹，杞菊終年食甘美。", "傳呼慎勿付庖人，百步洪邊放清泚。", "回首無欺子産淳，謾道悠然泳波底。"]'),
('fb386499-80da-47b0-861a-22066312ed8a','子瞻席上令歌舞者求詩戲以此贈','釋道潜','宋','宋诗','song-poetry','','[]','底事東山窈窕娘，不將幽夢囑襄王。',32,'全唐诗/poet.song.52000.json','["底事東山窈窕娘，不將幽夢囑襄王。", "禪心已作沾泥絮，肯逐春風上下狂。"]'),
('2f136214-c6ba-4923-ba35-d5c099e6491a','陪子瞻登徐州黄樓','釋道潜','宋','宋诗','song-poetry','','[]','黄花離披秋日短，使君無事邀僧飯。',128,'全唐诗/poet.song.52000.json','["黄花離披秋日短，使君無事邀僧飯。", "飯餘軟語爇香幽，共坐圓庵不知晚。", "燭籠持火報黄昏，使君愛客還留連。", "前登脩徑步超逸，後却從御來聯翩。", "城頭陰陰未上月，城下激激鳴潺湲。", "漁燈照船沙岸近，賈客夜唱聲清圓。", "徘徊始轉黄樓側，銀箭銅壺知幾刻。", "欄干倚遍惜分携，泣泣芙蓉珠露滴。"]'),
('98c701e2-0878-4ba3-9ec7-aea7e7297c27','逍遙堂書事呈子瞻','釋道潜','宋','宋诗','song-poetry','','[]','尋常臥雲林，往往厭闤闠。',108,'全唐诗/poet.song.52000.json','["尋常臥雲林，往往厭闤闠。", "今朝郡齋裏，岑寂返可愛。", "曦和破簾櫳，幽鳥語庭際。", "開門面脩圃，珍木羅翠蓋。", "蕭疏舊菊叢，裛露有餘態。", "主人事天和，萬慮屏身外。", "勞生一斷梗，何處考根柢。", "安能從物役，擾擾空卒歲。", "脫巾每相從，頗得資傲睨。"]'),
('e5f3b849-55c1-4241-91cf-140301087d61','次韵子瞻飯別','釋道潜','宋','宋诗','song-poetry','','[]','鈴閤追隨半月强，葵心菊腦厭甘凉。',64,'全唐诗/poet.song.52000.json','["鈴閤追隨半月强，葵心菊腦厭甘凉。", "身行異土老多病，路憶故山秋易荒。", "西去想難陪蜀芋，南來應得共吳薑。", "白雲出處元無定，只恐從風入帝鄉。"]'),
('5d334710-e544-4e5d-bb69-63a64df9c103','次韵少游寄李齊州','釋道潜','宋','宋诗','song-poetry','','[]','畫船京口見停橈，萧洒渾疑謝與陶。',64,'全唐诗/poet.song.52000.json','["畫船京口見停橈，萧洒渾疑謝與陶。", "但把好山供勝踐，不將餘論挂塵勞。", "諫垣天上經焚草，藩國年來屢夢刀。", "北客近傳新政美，未嘗因物强吹毛。"]'),
('3ced7ba1-cd1e-4b9d-b168-05a6394cacc2','次韵少游和子理梅花','釋道潜','宋','宋诗','song-poetry','','[]','朔風蕭蕭方振槁，雪壓茅齋欲欹倒。',128,'全唐诗/poet.song.52000.json','["朔風蕭蕭方振槁，雪壓茅齋欲欹倒。", "門前誰送一枝梅，問訊山僧少病惱。", "强將筆力爲摹寫，麗句已輸何遜早。", "碧桃丹杏空自妍，嚼蕊嗅香無此好。", "先生携酒傍玉叢，醉裏雄辭驚電掃。", "東溪不見謫仙人，江路還逢少陵老。", "我雖不飲爲詩牽，不惜山衣同藉草。", "要看陶令插花歸，醉臥清風軼軒昊。"]'),
('e4404ba0-3a27-47f0-8957-b86f04ba194a','自彭門回止淮上因寄子瞻','釋道潜','宋','宋诗','song-poetry','','[]','朅來淮上臥蕭宮，回首人間萬事空。',64,'全唐诗/poet.song.52000.json','["朅來淮上臥蕭宮，回首人間萬事空。", "院靜水沈銷薄幔，睡餘寒日耿脩桐。", "南山訪古思杯渡，北海談經憶孔融。", "寂寞兼葭霜雪後，何時重倚玉青葱。"]'),
('2a6380f2-1452-43df-92d3-fe04ebdf36f7','與曾逢原寺丞相別','釋道潜','宋','宋诗','song-poetry','','[]','落葉追奔卷地飛，淮流轉處楚山稀。',64,'全唐诗/poet.song.52000.json','["落葉追奔卷地飛，淮流轉處楚山稀。", "君騎黄鵠朝天去，我憶青松舊壑歸。", "道在不須驚契闊，情親聊用惜分違。", "巖居祿隠都如夢，莫向秋風歎式微。"]'),
('8851fd76-cba6-49e3-9ccb-4849dd86436c','夜泊淮上復寄逢原','釋道潜','宋','宋诗','song-poetry','','[]','黄沙白草滿淮垠，逆旅蕭條思不禁。',64,'全唐诗/poet.song.52000.json','["黄沙白草滿淮垠，逆旅蕭條思不禁。", "風約亂雲歸隴首，角催明月出波心。", "槎頭湧處潮初上，斗柄移時夢未沈。", "遙想故人投宿地，畫船應在碧榆林。"]'),
('99b17786-a623-4c48-82e0-f6cb31a59cd3','曉發桃源渡寄端叔','釋道潜','宋','宋诗','song-poetry','','[]','桃源渡頭雞一鳴，舟子夜起趨南行。',64,'全唐诗/poet.song.52000.json','["桃源渡頭雞一鳴，舟子夜起趨南行。", "泯泯河流浮落月，蕭蕭岸木警秋聲。", "依人翡翠霜翎重，拂棹芙蓉露蕊輕。", "爲報舊游朝士說，天街何似此中清。"]'),
('375d34b9-8cac-42d5-9c9f-868d09b72cf4','贈鄒醫','釋道潜','宋','宋诗','song-poetry','','[]','君不見宋清市藥長安西，衆工就取資刀圭。',243,'全唐诗/poet.song.52000.json','["君不見宋清市藥長安西，衆工就取資刀圭。", "瘡瘍疾病一皆往，所應不必黄金賫。", "度未能酬輒焚券，耻學庸生憂噬臍。", "人人德清莫肯負，日獲遠利豐子妻。", "公侯餽遺日相屬，螘食華衣乘駃騠。", "羅池神人爲作傳，至今名譽橫雲霓。", "鄒君業醫世淮海，瀉盛補衰知徑蹊。", "玉函金匱恣探討，拏以自副能不迷。", "頃年西游抵京室，達官貴吏爭品題。", "歸來鄉縣頗蕭瑟，湖水粘雲芳草萋。", "憐余寢瘵古佛剎，每辱珍劑相扶携。", "傾囊倒橐願爲贈，唯有圓蒲并杖藜。", "君聞掉頭不我顧，止索詩句光衡圭。", "夜披陳編見清事，重嗟此道今如泥。", "君誠有意嗣前躅，篋笥不憂無錦綈。"]'),
('454c0f70-379d-4013-8660-d27f27077fbe','寄蘇子由著作','釋道潜','宋','宋诗','song-poetry','','[]','先生道德若爲容，曾向南都幕下逢。',64,'全唐诗/poet.song.52000.json','["先生道德若爲容，曾向南都幕下逢。", "拔俗高標驚萬丈，凌雲逸氣藹千重。", "低梧暫宿張家鳳，濁水難藏許氏龍。", "歲晚雪霜雖更苦，未應憔悴碧巖松。"]'),
('2866f269-389a-472d-b89d-ea2cc6a40f8c','贈子固舍人  其一','釋道潜','宋','宋诗','song-poetry','','[]','文章煒燁動當時，雋乂雖多不並馳。',64,'全唐诗/poet.song.52000.json','["文章煒燁動當時，雋乂雖多不並馳。", "解激頹波旋往古，獨憐夫子抱青規。", "山川淑氣真能感，宇宙雄名豈浪垂。", "未信長途老天馬，行看蹴踏上瑶池。"]'),
('b2c30929-b486-4264-b985-39f59b4baaf9','贈子固舍人  其二','釋道潜','宋','宋诗','song-poetry','','[]','吏部遺編久寂寥，潁濱居士亦蓬蒿。',64,'全唐诗/poet.song.52000.json','["吏部遺編久寂寥，潁濱居士亦蓬蒿。", "支流盡屈江湖闊，衆阜爭隆泰華高。", "落落千章揮琬琰，湯湯萬頃起波濤。", "玉堂鵷鷺遲公久，何事崎嶇尚夢刀。"]'),
('a4461f79-2add-4329-a593-054c297502e0','宿乾明','釋道潜','宋','宋诗','song-poetry','','[]','五更風雨鬧秋堂，夢斷篝燈尚有光。',32,'全唐诗/poet.song.52000.json','["五更風雨鬧秋堂，夢斷篝燈尚有光。", "明日又爲湖上客，船頭雲水正茫茫。"]'),
('62912d7c-ee64-4317-9c70-4d0dbcc6ffdb','寄莘老','釋道潜','宋','宋诗','song-poetry','','[]','十年手把使君麾，一日歸來踐赤墀。',64,'全唐诗/poet.song.52000.json','["十年手把使君麾，一日歸來踐赤墀。", "偶爾夢中成故事，凜然霜後見奇姿。", "枯荄在昔嘗叨廕，微蚋于今頼附馳。", "况有雲庵閟深谷，他時香火與君期。"]'),
('8ae6ef55-ce9e-4521-acf2-7ac399416e2c','寄李公擇侍郎','釋道潜','宋','宋诗','song-poetry','','[]','高城夜寂起清風，月下清霜墮曉空。',64,'全唐诗/poet.song.52000.json','["高城夜寂起清風，月下清霜墮曉空。", "澤國已驚黄橘柚，省垣應對老梧桐。", "青錢舊數文才妙，碧落新游問望隆。", "四海倚公調鼎鼐，佇瞻和氣洽沖融。"]'),
('9deb72b1-fa76-4abf-8ff3-12edc608b104','俞公達待制挽辭  其一','釋道潜','宋','宋诗','song-poetry','','[]','金鐸哀傳靜列營，將星飛墜漢蕃驚。',64,'全唐诗/poet.song.52000.json','["金鐸哀傳靜列營，將星飛墜漢蕃驚。", "森森氣與秦山在，奄奄魂隨隴水傾。", "塞路簫笳悲部曲，海天風雨濕銘旌。", "堪嗟未勒燕然石，遽失連雲萬里城。"]'),
('2ab3f5e4-d6da-447c-bf16-1ea0f669b426','俞公達待制挽辭  其二','釋道潜','宋','宋诗','song-poetry','','[]','東吳佳氣久氤氳，果見雄才出海濱。',64,'全唐诗/poet.song.52000.json','["東吳佳氣久氤氳，果見雄才出海濱。", "屢試干將羌破膽，忽摧梁木士霑巾。", "人間夢斷黄粱熟，天上樓成白玉新。", "零落山丘今古事，情鍾我輩謾傷神。"]'),
('92f6c732-0ebd-4c44-8621-c1d85ced53ad','春行','釋道潜','宋','宋诗','song-poetry','','[]','朝入春山千萬重，暮歸溪上漫匆匆。',32,'全唐诗/poet.song.52000.json','["朝入春山千萬重，暮歸溪上漫匆匆。", "白沙岸口長回首，無數漁燈翠靄中。"]'),
('4d375b13-58f3-4c50-80d0-7139792b66f6','次韵傳師見過','釋道潜','宋','宋诗','song-poetry','','[]','孫郎萧洒逼人衣，咫尺塵埃隔蕙帷。',64,'全唐诗/poet.song.52000.json','["孫郎萧洒逼人衣，咫尺塵埃隔蕙帷。", "陋巷有時過佛剎，談經還共惜秋暉。", "百年空果冥中謝，一寸靈珠象外歸。", "久矣此情人不諭，援毫聊復爲君揮。"]'),
('c1d89cee-5ade-406c-8a74-aa83d294dafb','淮上聞雁寄仲恭','釋道潜','宋','宋诗','song-poetry','','[]','欹枕船舷夜櫓停，數行南去雁如繩。',32,'全唐诗/poet.song.52000.json','["欹枕船舷夜櫓停，數行南去雁如繩。", "起來欲寄相思字，高拂銀河喚不應。"]'),
('f1c5ac52-e1b6-49a3-8f6a-5ad5ba654b9b','與怡然夜話','釋道潜','宋','宋诗','song-poetry','','[]','雲埋碧瓦寒侵戶，榻照青燈夜色空。',32,'全唐诗/poet.song.52000.json','["雲埋碧瓦寒侵戶，榻照青燈夜色空。", "故國十年無限事，笑談如在夢魂中。"]'),
('d98c99ae-0390-49e1-b66f-b3cacf51d91c','鶴林寺','釋道潜','宋','宋诗','song-poetry','','[]','宛轉回廊漫布金，蕭條寒日墮牆陰。',32,'全唐诗/poet.song.52000.json','["宛轉回廊漫布金，蕭條寒日墮牆陰。", "門前合抱松千尺，黄鶴不來年已深。"]'),
('e186ebad-b83b-4cea-94dc-ef8bc2552eba','寄舒堯文教授','釋道潜','宋','宋诗','song-poetry','','[]','經綸滿腹貯雲霓，卓犖丘門道可躋。',64,'全唐诗/poet.song.52000.json','["經綸滿腹貯雲霓，卓犖丘門道可躋。", "絳帳開時霞影亂，青衿立處雁行齊。", "憶親麈尾焚香夜，共惜筠梢落月低。", "別後鳳毛知更長，五車應已識詮題。"]'),
('fedbca5d-5370-43a9-b22c-ec50a6cf8d1c','次韵順上人寄叔康講師','釋道潜','宋','宋诗','song-poetry','','[]','少年好詩書，齷齪空閉戶。',132,'全唐诗/poet.song.52000.json','["少年好詩書，齷齪空閉戶。", "有若丹青徒，秉筆學畫虎。", "法師當是時，聲價久已負。", "籍籍東州人，高談慕支許。", "余時跡四方，浪涉川陸苦。", "昨夜北山翁，挑燈同軟語。", "因論鄉里賢，悵師成獨阻。", "南徐號名都，興發歷漢楚。", "崢嶸江上山，王氣埋千古。", "至今風前笛，夜夜怨江浦。", "感慨易成吟，安得君來伍。"]'),
('d71d5284-ba14-4107-9806-362a6aaacc58','次韵順上人登壽寧閣','釋道潜','宋','宋诗','song-poetry','','[]','昔過廣陵日，茲樓亦盤桓。',144,'全唐诗/poet.song.52000.json','["昔過廣陵日，茲樓亦盤桓。", "飛甍切星斗，鴻鵠爭危欄。", "怳若隨扶摇，九萬直上摶。", "下視古帝基，蕭條空湠漫。", "當時競豪華，人物鏤綺紈。", "孰謂千載後，故宮半耕殘。", "城西舊輦道，繚繞猶屈盤。", "咫尺見螢苑，枯桑生晝寒。", "閻閭豈復隘，狐兔穴已寬。", "楚楚但喬木，萋萋無寸山。", "苟非壯士懷，往往不忍看。", "青旗催畫角，回首送飛翰。"]'),
('4715e935-0d5d-4de2-a4c0-9faccc513153','得端叔淮上書','釋道潜','宋','宋诗','song-poetry','','[]','飛鴻從西來，有客遺我書。',204,'全唐诗/poet.song.52000.json','["飛鴻從西來，有客遺我書。", "開緘識遠意，字字情有餘。", "報言歷長淮，泛泛乘舳艫。", "天開滅遠霧，水碧涵空虛。", "超然忘端倪，身世疑有無。", "徜徉極幽致，恨我失之俱。", "我昔與曾子，茲游頗躊躕。", "風高當白帝，露冷凋紅蕖。", "扁舟僅半月，歷覽窮朝晡。", "伊人亦才華，俊逸千里駒。", "結交慕豪彥，倜儻非迂儒。", "當時欲相從，恨子隔海隅。", "今朝子獨往，我輩還星疏。", "邂逅亦有分，夤緣非强圖。", "茫然臨西風，俛首良自吁。", "庶幾有至理，去彼形跡拘。", "相望雲漢間，皎潔同蟾蜍。"]'),
('def87f50-be00-4bdf-8160-02db9004d5e7','送慧悟大師還闕下','釋道潜','宋','宋诗','song-poetry','','[]','道人本丘壑，浪爲京華居。',132,'全唐诗/poet.song.52000.json','["道人本丘壑，浪爲京華居。", "一往二十年，歲月驚須臾。", "禪餘挾妙術，出入卿大夫。", "飛揚動天子，聲問傾九衢。", "紛彼戶外屨，泛如水中鳬。", "高懷倦酬應，逸賞思江湖。", "春風卷衣祴，千里隨舳艫。", "中泠湧樓觀，圓嶠連方壺。", "杖策步鰲頭，直上窮崎嶇。", "超然萬象外，所得良有餘。", "興盡乘白雲，飄飄還帝都。"]'),
('23f11b5a-ab0e-4f8c-a39a-0e8d460a80a7','將之金陵寄侍琪服之秀才','釋道潜','宋','宋诗','song-poetry','','[]','黄昏落帆牛渚磯，蒼石岸黑行人稀。',64,'全唐诗/poet.song.52000.json','["黄昏落帆牛渚磯，蒼石岸黑行人稀。", "漁燈夜深遠近沒，水鳥月明來去飛。", "瓶盂漸與南斗闊，身世東去將焉爲。", "鍾山咫尺行可及，會當與子同遨嬉。"]'),
('fadec8a2-f6b9-449c-945d-f3d95fdede7e','鍾山夜月','釋道潜','宋','宋诗','song-poetry','','[]','萬壑千巖夜未央，月華松色共蒼蒼。',32,'全唐诗/poet.song.52000.json','["萬壑千巖夜未央，月華松色共蒼蒼。", "上方已覺無人語，金殿誰焚栢子香。"]'),
('e8184ae8-1338-49d3-8969-cbff35757af4','睡起','釋道潜','宋','宋诗','song-poetry','','[]','紅芳落盡踏青青，啞咤黄鸝隔樹鳴。',32,'全唐诗/poet.song.52000.json','["紅芳落盡踏青青，啞咤黄鸝隔樹鳴。", "午睡覺來聽不足，杖藜重過竹陰行。"]'),
('efdc5e0e-a7d7-47a5-8061-8cf9a544d4c8','曾子固舍人挽辭  其一','釋道潜','宋','宋诗','song-poetry','','[]','命世高標見實難，狂瀾既倒頼公還。',64,'全唐诗/poet.song.52000.json','["命世高標見實難，狂瀾既倒頼公還。", "學窮游夏淵源際，文列班楊伯仲間。", "落落聲塵隨逝水，滔滔論著在名山。", "凄凉四海門人淚，想對秋風爲一潸。"]'),
('54af9f6f-fa70-4b38-a0a1-50f2ec3c96c6','曾子固舍人挽辭  其二','釋道潜','宋','宋诗','song-poetry','','[]','雄詞大冊破幽昏，返覆難窺斧鑿痕。',64,'全唐诗/poet.song.52000.json','["雄詞大冊破幽昏，返覆難窺斧鑿痕。", "投老雍容歸法從，銜哀倉卒去都門。", "雲泉已負高秋約，江渚空悲靜夜魂。", "誰與朝廷終太史，君王應待鶺鴒原。"]'),
('242d9963-58c0-46c8-bbfc-5de466888222','子瞻赴守湖州  其一','釋道潜','宋','宋诗','song-poetry','','[]','山烟弄滅沒，山木含葱蒼。',76,'全唐诗/poet.song.52000.json','["山烟弄滅沒，山木含葱蒼。", "刺舟傍遙岸，理策升虛堂。", "周遭矚曾巘，矯矯如翱翔。", "下瞰平田流，澹然浮日光。", "青{炏/勞}解初籜，洗雨聞清香。", "雖云迫前途，真賞豈易忘。"]'),
('f515266d-7a04-4d86-8f31-d3d493fa73a6','子瞻赴守湖州  其二','釋道潜','宋','宋诗','song-poetry','','[]','松門暗朝雨，寂歷無行人。',72,'全唐诗/poet.song.52000.json','["松門暗朝雨，寂歷無行人。", "隆曦忽穿漏，卉木蔚以新。", "階泉漱石齒，照眼光磷磷。", "史君美無度，卓犖遺囂塵。", "風標傲竹栢，談笑凌穹旻。", "何愧沈冥子，臥霞吞結鄰。"]'),
('0b81e0bd-a38d-4cea-bf21-b2cbee449b1e','子瞻赴守湖州  其三','釋道潜','宋','宋诗','song-poetry','','[]','揚帆渡江來，洗眼驚翠樾。',72,'全唐诗/poet.song.52000.json','["揚帆渡江來，洗眼驚翠樾。", "雲姿既容裔，鳥哢更清絕。", "凌梯訪前蹤，琬琰亦未滅。", "嗟我魚目光，疇能綴明月。", "狂墨掃琅玕，風烟坐中發。", "殊勝區中人，茫茫走飛轍。"]'),
('f9754777-3854-4973-9061-0378eb863f71','吳江垂虹亭同賦得岸字','釋道潜','宋','宋诗','song-poetry','','[]','蜿蜒誇長虹，吳會稱傑觀。',84,'全唐诗/poet.song.52000.json','["蜿蜒誇長虹，吳會稱傑觀。", "淪漣幾萬頃，放目失垠岸。", "倒影射遙山，青螺點空半。", "從來夸震澤，勝事無昏旦。", "破浪湧長鬐，排空度飛翰。", "肺肝入清境，劃若春冰泮。", "安得凌九垓，從公游汗漫。"]'),
('97d846a0-adaf-4404-a590-34ea82acf971','同吳興尉錢濟明南溪泛舟','釋道潜','宋','宋诗','song-poetry','','[]','枇杷弄實梅欲黄，海氣冥冥錯昏晝。',160,'全唐诗/poet.song.52000.json','["枇杷弄實梅欲黄，海氣冥冥錯昏晝。", "僧坊亭午隘可鄙，畫舸從君逐溪溜。", "斗欣紛翳眼前失，但覺波光翻縠縐。", "蘋花洗雨白雪香，荷柄吹風青玉瘦。", "回看行人走南北，蠢蠢岸傍如蟻鬭。", "一竿落日麗樵明，繞郭雲山相倚構。", "嶄嶄青壁映彤霞，轉盼忽驚開錦繡。", "好將傑句爲余寫，天乞君才多穎茂。", "錦囊玉刻厭傳玩，燕尾蠶頭吾未究。", "輕橈欲動蹇淹留，城上哀笳凄已奏。"]'),
('39d4366d-6226-484e-90c9-88747d253cda','吳興道中寄子瞻','釋道潜','宋','宋诗','song-poetry','','[]','弱性嗜幽散，出門隨所便。',120,'全唐诗/poet.song.52000.json','["弱性嗜幽散，出門隨所便。", "蓮房紛可襲，林幄正高褰。", "群木含晨景，孤撐破宿烟。", "逶迤屯秀崿，宛轉滀清漣。", "岸匝藤花暗，崖垂桂影圓。", "引鶵鳴鴶鵴，解籜露嬋娟。", "怳若經愚谷，渾疑渡輞川。", "葑田青泛泛，石葛蔓綿綿。", "緬想醉山簡，相從狂謫仙。", "援毫更妙韵，愧乏碧雲妍。"]'),
('33298756-4d1f-4dd8-a9d5-d3eb28d30685','田居四時  其一','釋道潜','宋','宋诗','song-poetry','','[]','原隰春風暖，池塘雁北翔。',48,'全唐诗/poet.song.52000.json','["原隰春風暖，池塘雁北翔。", "曉耕雲塢潤，午飯野芹香。", "燕子依茅棟，花枝過土牆。", "東阡與南陌，生事日皇皇。"]'),
('231c0d41-5591-4fc8-8f5f-acb8a2252f32','田居四時  其二','釋道潜','宋','宋诗','song-poetry','','[]','五月梅爭熟，村村桑柘稀。',48,'全唐诗/poet.song.52000.json','["五月梅爭熟，村村桑柘稀。", "茜裙蠶婦瘦，粉翅乳鵝肥。", "菱蔓滋溪雨，藤花鎖釣磯。", "呼兒行採去，亭午候荆扉。"]'),
('da698d15-a56e-45d6-9c36-5af2f35e2a68','田居四時  其三','釋道潜','宋','宋诗','song-poetry','','[]','刈穫終吾事，田園日向閑。',48,'全唐诗/poet.song.52000.json','["刈穫終吾事，田園日向閑。", "晚香增橘柚，潦水耗汀灣。", "聚噪棲鴉定，孤吹牧豎還。", "兒童驚野燒，一片起前山。"]'),
('fac789d4-8a62-46c3-9bf7-af40ead2f8fb','田居四時  其四','釋道潜','宋','宋诗','song-poetry','','[]','汩汩防農霧，窮冬亦謾勞。',48,'全唐诗/poet.song.52000.json','["汩汩防農霧，窮冬亦謾勞。", "茅簷催日午，籬落聽雞號。", "臘近還移竹，宵閑更索綯。", "春風歸早晚，行見事東皋。"]'),
('47c55c24-8b5c-493a-a646-1f33554aa57a','夏日龍井書事  其一','釋道潜','宋','宋诗','song-poetry','','[]','翠櫪高蘿結晝陰，驕陽無地迫吾身。',64,'全唐诗/poet.song.52000.json','["翠櫪高蘿結晝陰，驕陽無地迫吾身。", "石崖細聽紅泉落，林果初嘗碧奈新。", "揮麈已欣從惠遠，談經終恨少遺民。", "何時暫著登山屐，來岸烏紗漉酒巾。"]'),
('d462e850-ad2c-45ab-aa7a-4f169d81985a','夏日龍井書事  其二','釋道潜','宋','宋诗','song-poetry','','[]','雨過千巖爽氣新，孤懷入夜與誰鄰。',64,'全唐诗/poet.song.52000.json','["雨過千巖爽氣新，孤懷入夜與誰鄰。", "風蟬故故頻移樹，山月時時自近人。", "禮樂汝其攻我短，形骸吾已付天真。", "露華漸冷飛蚊息，窗裏吟燈亦可親。"]'),
('890eee02-49e4-4baa-86fe-4aaca7d00acc','夏日龍井書事  其三','釋道潜','宋','宋诗','song-poetry','','[]','自憐多病畏炎曦，長夏投蹤此最宜。',64,'全唐诗/poet.song.52000.json','["自憐多病畏炎曦，長夏投蹤此最宜。", "青石白沙含淺瀨，碧梧蒼竹聒凉颸。", "雲中雞犬聽難辨，谷口漁樵問不知。", "斑杖芒鞋隨步遠，歸來幽火認茅茨。"]'),
('93465374-9475-4d26-9ac1-f39f0e40856e','夏日龍井書事  其四','釋道潜','宋','宋诗','song-poetry','','[]','朅來人外慰棲遲，谷遠山長萬事遺。',64,'全唐诗/poet.song.52000.json','["朅來人外慰棲遲，谷遠山長萬事遺。", "好鳥未嘗吟俗韵，白雲還解弄奇姿。", "藤花冉冉青當戶，竹色娟娟碧過籬。", "不羨故人探禹穴，短橈孤榜逐漣漪。"]'),
('82112d58-50e3-4ecb-abeb-f484e8a08f20','寄俞伯謨宣義昆仲  其一','釋道潜','宋','宋诗','song-poetry','','[]','謝家蘭玉競芬芳，千里南來未易忘。',32,'全唐诗/poet.song.52000.json','["謝家蘭玉競芬芳，千里南來未易忘。", "猶憶娑羅雙樹院，月明相對坐胡床。"]'),
('ae02b931-d273-4dad-ab5d-01f38d0912bd','寄俞伯謨宣義昆仲  其二','釋道潜','宋','宋诗','song-poetry','','[]','多病侵尋鬢已霜，昔年交友半殊方。',32,'全唐诗/poet.song.52000.json','["多病侵尋鬢已霜，昔年交友半殊方。", "吳臺松栢今何似，想見龍蛇數尺長。"]'),
('2270abd9-bd40-4dfa-a4e2-76d490b04e2d','夏夜','釋道潜','宋','宋诗','song-poetry','','[]','斗帳昏昏夜氣蒸，移床趁月臥中庭。',32,'全唐诗/poet.song.52000.json','["斗帳昏昏夜氣蒸，移床趁月臥中庭。", "紫薇花露霑衣冷，翻覺華胥夢易醒。"]'),
('7391379f-60b3-4e10-b315-c5cecf758fd1','送楚上人還廣陵慶禪師法席','釋道潜','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','吾鄉少年多齷齪，投老家山猶戀著。',192,'全唐诗/poet.song.52000.json','["吾鄉少年多齷齪，投老家山猶戀著。", "何異醯雞舞甕天，肯信十方無壁落。", "羨君壯懷慕遠舉，萬里雲山行犖确。", "荆江洞庭虛浩渺，斂裓浮杯心自若。", "去年臘月過湓城，聆我幽脩臥雲壑。", "朅來相從慰契闊，笑語逸發驚猿鶴。", "春風又復卷征衣，問子東去將何爲。", "廣陵城西古佛剎，中有老禪吾所師。", "當年與君共伏役，妙道彷彿窺藩籬。", "別來星霜歎已久，夜夢往往神魂馳。", "真金雖已出頑鑛，鍛鍊豈厭增鉗鎚。", "縱橫法縛斷除盡，了了方爲獅子兒。"]'),
('74135b69-b8f5-42fa-ab1b-2168870d1395','晚興','釋道潜','宋','宋诗','song-poetry','','[]','牆角風欺竹影斜，數聲啼盡欲棲鴉。',32,'全唐诗/poet.song.52000.json','["牆角風欺竹影斜，數聲啼盡欲棲鴉。", "重門已閉斷還往，獨卷疏簾進月華。"]'),
('18b9d049-9954-4c34-a8a4-d606ce020836','下湖晚歸','釋道潜','宋','宋诗','song-poetry','','[]','屈曲莎隄引興長，肯辭芒屨踏秋霜。',32,'全唐诗/poet.song.52000.json','["屈曲莎隄引興長，肯辭芒屨踏秋霜。", "歸來已奏孤城角，撩亂梅花落女牆。"]'),
('d297c7a5-8c39-4cf8-b8da-938034484d70','秋日西湖  其一','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','兩山斜抱翠逶迤，一水中間似渼陂。',32,'全唐诗/poet.song.52000.json','["兩山斜抱翠逶迤，一水中間似渼陂。", "孤榜獨來還獨往，鸕鷀鸂鶒莫相疑。"]'),
('ba3f07d6-858b-4a80-9863-e8e8f90110fd','秋日西湖  其二','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','琤然一葉墮空庭，似喚幽人夢欲醒。',32,'全唐诗/poet.song.52000.json','["琤然一葉墮空庭，似喚幽人夢欲醒。", "斜倚素屏褰翠幔，沈香烟吐博山青。"]'),
('e39ed84a-6f81-4e51-9871-b173c3da032a','秋日西湖  其三','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','南山爽氣對朝扉，竹露吹風更濕衣。',32,'全唐诗/poet.song.52000.json','["南山爽氣對朝扉，竹露吹風更濕衣。", "可是吟魂怯清景，何妨著屐步苔磯。"]'),
('22c723b7-eba7-4026-81ef-d92ce457d85d','秋日西湖  其四','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','飛來雙鷺落寒汀，秋水無痕玉鏡清。',32,'全唐诗/poet.song.52000.json','["飛來雙鷺落寒汀，秋水無痕玉鏡清。", "疏蓼黄蘆宜掩映，沙邊危立太分明。"]'),
('f07c593b-cab1-4234-a7da-04d3b07ae3c5','秋日西湖  其五','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','欲跨高樓曠遠情，無端秋雨苦冥冥。',32,'全唐诗/poet.song.52000.json','["欲跨高樓曠遠情，無端秋雨苦冥冥。", "崢嶸日脚漏雲處，瞥見遙山一抹青。"]'),
('2f0964f4-cc5d-47f3-bd38-3e81a113587f','秋日西湖  其六','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西風夜半捲庭槐，臥聽鄰翁曉圃開。',32,'全唐诗/poet.song.52000.json','["西風夜半捲庭槐，臥聽鄰翁曉圃開。", "稚子相呼入林去，應知病果落莓苔。"]'),
('2713bdd1-8151-43ae-a983-4b55c37cafde','晨起','釋道潜','宋','宋诗','song-poetry','','[]','窗扉曉闢對平湖，爽氣侵尋冷入膚。',64,'全唐诗/poet.song.52000.json','["窗扉曉闢對平湖，爽氣侵尋冷入膚。", "林迥霜黄垂橘柚，渚清沙碧老菰蒲。", "忘機鷗鷺元相狎，得食猿猱不用呼。", "游目騁懷心正逸，更憑高處立須臾。"]'),
('76fe8685-c5bf-40a7-a35b-8d75aee1b771','戲招李無悔秀才','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','淋漓一雨過秋山，洗出西湖小霽天。',64,'全唐诗/poet.song.52000.json','["淋漓一雨過秋山，洗出西湖小霽天。", "烱烱魚鱗含倒景，飄飄羊角卷荒阡。", "野塘白芡珠盈斗，幽浦紅蕖錦繞船。", "冷炙殘盃當已厭，好來波際弄嬋嬋。"]'),
('a64f5ba0-89eb-4255-9461-dc1dc275c616','西湖雪霽寄彥瞻','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖漫天三日雪，上下一色迷空虛。',176,'全唐诗/poet.song.52000.json','["西湖漫天三日雪，上下一色迷空虛。", "曾巒沓嶂杳難辨，彷彿樓觀疑有無。", "饑雛乳獸失所食，飛走阡陌空號呼。", "中園却羨啄木鳥，利觜自解謀朝晡。", "曉來鍾鼓報新霽，天半稍稍分浮圖。", "試憑高樓肆遠目，千里顛倒羅瓊琚。", "逡巡夜月出海角，光彩猛射來城隅。", "方壺圓嶠只在眼，綽約怳晤神仙居。", "咄哉浩景似欺壓，謂我不足爲傳模。", "風流江左杜從事，氣格豪贍凌相如。", "安得飄颻跨鸞鵠，手持栗尾來爲書。"]'),
('6ef490c0-5971-4a3c-becc-abd7fa062206','次韵彥瞻舟次三墩見寄','釋道潜','宋','宋诗','song-poetry','','[]','雪消幽港漲漪漣，草際晴絲罥細烟。',64,'全唐诗/poet.song.52000.json','["雪消幽港漲漪漣，草際晴絲罥細烟。", "避槳輕鷗翻點點，亞牆脩竹靜娟娟。", "風流遠繼東山後，詩句高凌北斗邊。", "何日去尋陽羨路，相携青嶂弄雲泉。"]'),
('1c999778-2905-4fa0-aba2-e3162f757418','次韵彥瞻樊良道中','釋道潜','宋','宋诗','song-poetry','','[]','幾日官河凍不流，朝來微暖始通舟。',64,'全唐诗/poet.song.52000.json','["幾日官河凍不流，朝來微暖始通舟。", "江梅破蕊香猶淺，汀草埋沙綠未浮。", "脩網橫川魚乍集，晴雲開野雪初收。", "探珠既已從驪頷，何用區區入海搜。"]'),
('01bb59b4-675d-4d81-9363-e8005aca424f','寄張明甫朝奉','釋道潜','宋','宋诗','song-poetry','','[]','昔公令吾鄉，綠髮氣方壯。',240,'全唐诗/poet.song.52000.json','["昔公令吾鄉，綠髮氣方壯。", "鳴弦坐高堂，百里肅清曠。", "良辰騁遨嬉，繭足履青嶂。", "當時陪杖屨，笑語相頡頑。", "論文希鄴都，樂事敦可尚。", "銅章既云解，余亦航海上。", "悠悠亙六載，天角空相望。", "朅來石頭城，邂逅慰離愴。", "携手雨花臺，俛仰得超放。", "瓶盂徙京口，冉冉抱微恙。", "扁舟亂江來，起我神益王。", "浮雲共平生，飄忽無定向。", "去年客梁園，塵土紛冗長。", "狙猿失林木，憔悴無優况。", "獨有青桂枝，冰雪不凋喪。", "惠然肯過從，香積仍接餉。", "秋風迫南還，危帆高且張。", "落日通津門，轉盼增惋悵。", "寢寐見高標，幽魂驚夜帳。", "相忘同海魚，千里各雲浪。"]'),
('f4018e52-28d7-4a1e-83dc-49a4cd06d788','探梅','釋道潜','宋','宋诗','song-poetry','','[]','問訊風篁嶺下梅，疏枝冷蕊未全開。',32,'全唐诗/poet.song.52000.json','["問訊風篁嶺下梅，疏枝冷蕊未全開。", "繁英待得渾如雪，霜曉無人我獨來。"]'),
('f14f2a48-7924-456f-879e-9595730e6b8a','歲寒亭','釋道潜','宋','宋诗','song-poetry','','[]','草枯蓬斷正紛紛，翠幹排簷不改陰。',32,'全唐诗/poet.song.52000.json','["草枯蓬斷正紛紛，翠幹排簷不改陰。", "自是孤根難挫抑，驕霜傲雪本無心。"]'),
('fe69c614-ba87-4c03-b871-ce5c6c8bf21e','與元規話別  其一','釋道潜','宋','宋诗','song-poetry','','[]','湖水蒼茫四接天，短篷孤榜數回旋。',32,'全唐诗/poet.song.52000.json','["湖水蒼茫四接天，短篷孤榜數回旋。", "想君東海東頭夢，猶在汀洲白鳥邊。"]'),
('d99857b2-77f6-467d-9612-07eb8f12a0cb','與元規話別  其二','釋道潜','宋','宋诗','song-poetry','','[]','雷岫庵南千種梅，含芳準擬爲君開。',32,'全唐诗/poet.song.52000.json','["雷岫庵南千種梅，含芳準擬爲君開。", "冷香秀色誰爲主，趁取花時更一來。"]'),
('5f5d1315-74a5-45cf-9386-5d8ce0b90683','春日  其一','釋道潜','宋','宋诗','song-poetry','','[]','蘭英蕙萼競芳新，左右吹香暗襲人。',32,'全唐诗/poet.song.52000.json','["蘭英蕙萼競芳新，左右吹香暗襲人。", "江海久無騷客賦，一枝唯可薦靈均。"]'),
('62c985b7-af94-49ab-b737-30f0cd1a1e28','春日  其二','釋道潜','宋','宋诗','song-poetry','','[]','清溪白石曉磷磷，洗露桃花兩岸新。',32,'全唐诗/poet.song.52000.json','["清溪白石曉磷磷，洗露桃花兩岸新。", "欲覓劉郎家住處，但聞雞犬不逢人。"]'),
('8af5c6e1-e89d-40bb-9cf1-676591acbb54','春詞  其一','釋道潜','宋','宋诗','song-poetry','','[]','輕雲著地柳垂絲，百尺高臺獨步時。',32,'全唐诗/poet.song.52000.json','["輕雲著地柳垂絲，百尺高臺獨步時。", "遙愛南鄰紅杏樹，曉來新有過牆枝。"]'),
('3580632c-cd81-4fa5-9ac5-293385ff6318','春詞  其二','釋道潜','宋','宋诗','song-poetry','','[]','濛濛小雨暗池塘，遠樹依微不辨行。',32,'全唐诗/poet.song.52000.json','["濛濛小雨暗池塘，遠樹依微不辨行。", "可是晚來風更惡，杏花香亂撲回廊。"]'),
('e8ce16b5-2b01-4df4-93c3-dbb2ddf832d3','春詞  其三','釋道潜','宋','宋诗','song-poetry','','[]','冰開池面初浮綠，日促花梢始破紅。',32,'全唐诗/poet.song.52000.json','["冰開池面初浮綠，日促花梢始破紅。", "謾道春光來眼底，茫然無意對芳叢。"]'),
('cf89de02-fe4f-4216-b756-e64a947817b3','駐景樓','釋道潜','宋','宋诗','song-poetry','','[]','額額高樓古道旁，樓前風物鬰摐摐。',64,'全唐诗/poet.song.52000.json','["額額高樓古道旁，樓前風物鬰摐摐。", "溪聲不斷來幽耳，山色常時在小窗。", "金鼎養丹嘗駐景，玉罇傾酒屢空缸。", "宋清賣藥長安市，千載佳名與子雙。"]'),
('530225eb-b4d7-4c20-890c-a7862ac98c71','程公闢給事罷會稽道過錢塘因以詩見贈  其一','釋道潜','宋','宋诗','song-poetry','','[]','嘗聞鍾鼓過蓬萊，席上無非八斗才。',64,'全唐诗/poet.song.52000.json','["嘗聞鍾鼓過蓬萊，席上無非八斗才。", "刻燭揮毫公屢勝，投壺飲釂客先頹。", "老元格調真難繼，短李風流不易陪。", "鑑水稽山行樂處，後車長是載鄒枚。"]'),
('de0cba82-3a68-46d0-8a0d-8d7bfbc0b7f5','程公闢給事罷會稽道過錢塘因以詩見贈  其二','釋道潜','宋','宋诗','song-poetry','','[]','江干千騎送朱輪，父老無緣借寇恂。',64,'全唐诗/poet.song.52000.json','["江干千騎送朱輪，父老無緣借寇恂。", "吳國旌旗開白日，越溪桃李失青春。", "雄名素與珠星爛，妙質長隨玉樹新。", "當宁比聞思舊德，萬方行見入洪鈞。"]'),
('d10bf073-a1ca-4f5a-ab4d-0ac73b1e28bc','寄濟明','釋道潜','宋','宋诗','song-poetry','','[]','茫乎一氣同渾淪，瀰漫六合無邊垠。',224,'全唐诗/poet.song.52000.json','["茫乎一氣同渾淪，瀰漫六合無邊垠。", "吁哉破散幾千載，被在萬物含其真。", "清輕爲天濁爲地，一一厚薄理自勻。", "駑駘騏驥不並廄，夜光魚目難相親。", "錢郎少年稟清裔，英姿綽欲揮等倫。", "忠言讜論躡根本，行義修篤無緇磷。", "是家嚴君抱勁烈，直筆曾預螭頭臣。", "我昔浮游霅溪側，傾蓋遇子情彌欣。", "炎雲燒空五六月，漾舟南郭吟青蘋。", "溪流寬圍野橋碧，溪樹靜嘯凉飈新。", "奇探險取得佳句，欲壓柳惲江南春。", "瓶盂屬我暫行役，樂事一跌成參辰。", "使君旋亦報西去，紛紛萬變難重陳。", "南山暮冬厚積雪，剛茂不死期松筠。"]'),
('c4b579ea-df26-4e17-8b0d-a093afac2c6c','江行寄俞仲寬察院','釋道潜','宋','宋诗','song-poetry','','[]','潮回沙浦寒，月落山未曉。',132,'全唐诗/poet.song.52000.json','["潮回沙浦寒，月落山未曉。", "駕言江上行，行遠心亦悄。", "茅屋兩三家，鷄聲聞縹緲。", "輕風颭垂楊，芳枝何裊裊。", "上有雙鳴禽，下有蕙蘭草。", "蒸蒸物已繁，灼灼花更好。", "時見頳尾鱗，跳波泳紋藻。", "即事起幽情，情含結懷抱。", "故交如參辰，咫尺曠烟島。", "紅日已三竿，回轅白沙道。", "但聞蕭葦間，挐音飛杳杳。"]'),
('59dc22a8-de43-47ab-932f-546bc405f019','春日雜興  其一','釋道潜','宋','宋诗','song-poetry','','[]','池南池北日融融，水荇風蒲各占叢。',32,'全唐诗/poet.song.52000.json','["池南池北日融融，水荇風蒲各占叢。", "幸有花枝能照眼，可無詩句補春工。"]'),
('6f7130a9-7819-468c-8125-3393e6b0bf57','春日雜興  其二','釋道潜','宋','宋诗','song-poetry','','[]','城根野水淥逶沱，颭颭風船掠岸過。',32,'全唐诗/poet.song.52000.json','["城根野水淥逶沱，颭颭風船掠岸過。", "日暮蕙蘭無處採，渚花汀草占春多。"]'),
('bd6a4007-2214-4a44-aa6e-3c588ed15454','春日雜興  其三','釋道潜','宋','宋诗','song-poetry','','[]','柳外披烟舒遠目，花邊植杖坐芳茵。',32,'全唐诗/poet.song.52000.json','["柳外披烟舒遠目，花邊植杖坐芳茵。", "能言百舌深藏葉，解舞鵾雞不避人。"]'),
('0ccd6b07-6a1e-4028-8252-17515cbe0539','春日雜興  其四','釋道潜','宋','宋诗','song-poetry','','[]','雨闋中庭暖日浮，春禽百種聚喧啾。',32,'全唐诗/poet.song.52000.json','["雨闋中庭暖日浮，春禽百種聚喧啾。", "粉腰蜂子尤無頼，撓遍花鬚未肯休。"]'),
('b0221a4f-53d9-4d12-a9df-3713b43cebbf','春日雜興  其五','釋道潜','宋','宋诗','song-poetry','','[]','去歲春風上苑行，爛窺紅紫厭平生。',32,'全唐诗/poet.song.52000.json','["去歲春風上苑行，爛窺紅紫厭平生。", "而今眼底無姚魏，浪蕊浮花懶問名。"]'),
('7cdac563-cb45-4287-8dfb-5415a06971ca','春日雜興  其六','釋道潜','宋','宋诗','song-poetry','','[]','碧流如鏡轉春渠，時送殘紅出雨餘。',32,'全唐诗/poet.song.52000.json','["碧流如鏡轉春渠，時送殘紅出雨餘。", "可怕莓苔黏屐齒，强扶筇竹過鄰居。"]'),
('a4124d9c-3f50-47c0-98e8-09a3f6577dee','春日雜興  其七','釋道潜','宋','宋诗','song-poetry','','[]','雨洗樓頭碧瓦昏，五更殘月墮金盆。',32,'全唐诗/poet.song.52000.json','["雨洗樓頭碧瓦昏，五更殘月墮金盆。", "轆轤索轉玉繩曉，花底宿禽無數喧。"]'),
('6d635913-01a3-4f76-bf50-7dc68aab2170','春日雜興  其八','釋道潜','宋','宋诗','song-poetry','','[]','梅梢青子大於錢，慚愧春光又一年。',32,'全唐诗/poet.song.52000.json','["梅梢青子大於錢，慚愧春光又一年。", "亭午無人初破睡，杜鵑聲在柳花邊。"]'),
('383a0316-662d-4528-b017-92c0e9ab0185','春日雜興  其九','釋道潜','宋','宋诗','song-poetry','','[]','戢戢籬根紫筍長，滿城桃李罷芬芳。',32,'全唐诗/poet.song.52000.json','["戢戢籬根紫筍長，滿城桃李罷芬芳。", "東風雖是無情物，送謝迎繁亦更忙。"]'),
('c32af7fd-09c1-44a0-a51c-afccbebba71f','春日雜興  其一○','釋道潜','宋','宋诗','song-poetry','','[]','樹萱移菊助春榮，沐雨梳風擢翠莖。',32,'全唐诗/poet.song.52000.json','["樹萱移菊助春榮，沐雨梳風擢翠莖。", "童子新能理荒穢，不教蕭艾並叢生。"]'),
('9114a444-b42f-4bec-8593-5a38b91227bf','雪堂雨中','釋道潜','宋','宋诗','song-poetry','','[]','梢林急雨暮凄凄，簾幕風燈暗欲迷。',32,'全唐诗/poet.song.52000.json','["梢林急雨暮凄凄，簾幕風燈暗欲迷。", "向曉請看南陌上，一番紅素掩春泥。"]'),
('6496bb29-bb0e-4e82-9404-da65605da47f','春日赤壁  其一','釋道潜','宋','宋诗','song-poetry','','[]','灧灧春江水拍隄，雙雙出沒羨鳧鷖。',32,'全唐诗/poet.song.52000.json','["灧灧春江水拍隄，雙雙出沒羨鳧鷖。", "白沙青石無泥滓，且逐東風進杖藜。"]'),
('53dc769f-0ade-4f22-b4e5-caeac5dac22b','春日赤壁  其二','釋道潜','宋','宋诗','song-poetry','','[]','蕭瑟江梅樹樹空，蘭芽猶短未成叢。',32,'全唐诗/poet.song.52000.json','["蕭瑟江梅樹樹空，蘭芽猶短未成叢。", "行窮赤壁山西路，只有桃花一樣紅。"]'),
('2c1f2164-9824-485d-a9df-e627e6f50893','留別雪堂呈子瞻','釋道潜','宋','宋诗','song-poetry','','[]','策杖南來寄雪堂，眼看花絮老風光。',32,'全唐诗/poet.song.52000.json','["策杖南來寄雪堂，眼看花絮老風光。", "主人今是天涯客，明日孤帆下渺茫。"]'),
('bfd3e442-85f5-4d8c-a25f-b22de3e2e958','寄題徐德之先生閑軒','釋道潜','宋','宋诗','song-poetry','','[]','建安自古多俊髦，徐子磊落尤其豪。',112,'全唐诗/poet.song.52000.json','["建安自古多俊髦，徐子磊落尤其豪。", "論兵說劍走湖海，身勤事左無所遭。", "綠林五校已屠膾，黑衣三衛羞徒勞。", "歸來故山便卜築，脫棄萬事輕鴻毛。", "橫前澗水漱哀玉，傍舍老櫪藏飛猱。", "山蔬何用羨粱肉，鶴氅未必輸青袍。", "追雲弄月有真趣，慎勿輕語傳兒曹。"]'),
('5d818528-fc85-4c12-b477-8627d71ea303','九江與東坡居士話別','釋道潜','宋','宋诗','song-poetry','','[]','霅水黄樓赤壁間，勝游長得共躋攀。',64,'全唐诗/poet.song.52000.json','["霅水黄樓赤壁間，勝游長得共躋攀。", "屠龍冉冉空三載，窺豹悠悠愧一斑。", "投錫雲林聊避暑，絕江舟檝自東還。", "求田問舍知何處，杖屨它時訪小山。"]'),
('3925675b-efe8-4286-ae0c-858b1dff9359','贈潘邠老秀才','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','去年雲夢澤南州，爲訪太史嘗淹留。',176,'全唐诗/poet.song.52000.json','["去年雲夢澤南州，爲訪太史嘗淹留。", "東坡寒碧最佳處，恨不得子同遨游。", "今年廬山深且窅，感君忽來慰枯槁。", "溪月巖雲亦有情，昨夜爲君顔色好。", "飄飄綠髮方妙年，圖史滿腹皆精研。", "揮毫應敵風雨快，咳唾落紙珠璣圓。", "廣文英豪僅數千，逸群驥子誰與肩。", "男兒窮通故有命，勸子未宜嗟蹭蹬。", "丈夫蓋棺事始定，他日雄飛鵰鶚勁。", "草草論文未有涯，匆匆別我却還家。", "秋風更約通玄府，共訪仙人臥彩霞。"]'),
('75ae9429-5a23-455d-8102-5323f34b618f','酬周元翁推官見贈','釋道潜','宋','宋诗','song-poetry','','[]','南來濟濟多俊良，聲問逸發推周郎。',208,'全唐诗/poet.song.52000.json','["南來濟濟多俊良，聲問逸發推周郎。", "詞場較藝一戰捷，筆陣獨掃千人强。", "烱然眉目行且貴，驥足萬里看騰驤。", "吟詩作賦不媚俗，期與往者同芬芳。", "斷璋殘璧忽我贈，把玩溢目驚輝光。", "自嗟行李久蕭瑟，安得置之雲錦囊。", "又聞跨馬欲過我，此意想君非渺茫。", "山中草木最宜夏，雨餘一一含幽香。", "雛鶑乳燕學飛舞，葉底啞咤調圓吭。", "闌干笋蕨雖已老，璀錯梅杏猶可嘗。", "陰崖碧洞不受暑，谷風習習吹衣凉。", "提携爲子掃盤石，談笑共坐莓苔蒼。", "宣毫越楮須盛載，吟取佳句還巾箱。"]'),
('be77f12c-3664-4f8b-a170-ddeda64011d0','南康與曾子宣內翰','釋道潜','宋','宋诗','song-poetry','','[]','旗亭方喜會高標，杞國天崩促去橈。',64,'全唐诗/poet.song.52000.json','["旗亭方喜會高標，杞國天崩促去橈。", "星渚風花朝冉冉，神林雨脚暮蕭蕭。", "飛流濺沫江翻怒，拆岸頹沙蜃倚驕。", "遙想英雄濟川手，壯懷寧復畏傾摇。"]'),
('bdd9af29-5185-47f2-9359-166530b5b974','曾子開吏部服闋赴召','釋道潜','宋','宋诗','song-poetry','','[]','驛騎駸駸破夕烟，西來遇我虎溪前。',64,'全唐诗/poet.song.52000.json','["驛騎駸駸破夕烟，西來遇我虎溪前。", "征途乍即應勞止，陳迹重窺更泫然。", "天上歸瞻新日月，山中行睹舊林泉。", "感時撫事情何極，且伴幽人此夜禪。"]'),
('4102e73a-dffb-42c1-9a33-a103da75db67','過公擇藏書室','釋道潜','宋','宋诗','song-poetry','','[]','我公昔未仕，託蹤此山阿。',132,'全唐诗/poet.song.52000.json','["我公昔未仕，託蹤此山阿。", "牙籤列圖史，萬卷堆嵯峨。", "披剝得精要，卷衣辭薜蘿。", "一往三十年，功名歎蹉跎。", "公今陟臺省，壯志應未磨。", "出處獨不謬，紛紛當奈何。", "脫身早來歸，挂冠舊庭柯。", "松窗展故帙，烱烱臨羲娥。", "豈復求甚解，聊將寄天和。", "勿憂野馬集，勿念蟲網羅。", "山祇善守護，早晚潜揮訶。"]'),
('de764d0f-e251-47c7-969c-386b4917b0e2','雙溪曉步懷少游子實','釋道潜','宋','宋诗','song-poetry','','[]','亭午炎威劇，風溪破曉行。',48,'全唐诗/poet.song.52000.json','["亭午炎威劇，風溪破曉行。", "紆餘憐野彴，錯落見長庚。", "翻藻魚呈媚，梢林露獻清。", "二豪俱二闕，此樂與誰并。"]'),
('b2a08ddd-06d9-475f-9337-2bf378eff627','寄王元均奉議昆仲','釋道潜','宋','宋诗','song-poetry','','[]','崇文學士後，二子皆翹翹。',168,'全唐诗/poet.song.52000.json','["崇文學士後，二子皆翹翹。", "異哉荆山麓，産此英瓊瑶。", "婆娑翰墨場，文彩相蔚饒。", "頃我未知識，寸心徒摇摇。", "前年廣陵城，會合如有招。", "名都冠淮海，氣象古所豪。", "林園若棋置，佳處遺塵囂。", "良辰肯浪負，杖策同嬉遨。", "清談落玉麈，亹亹如聞韶。", "歲晏樂未闋，離群復蕭蕭。", "扁舟眇一葉，出沒隨江潮。", "雲山列千里，廬霍尤岧嶢。", "孤懷喜自放，跨躒豈憚勞。", "所嗟無二陸，相我吟風騷。"]'),
('1f206222-8d5b-4f5d-992a-aa6809eaee32','廬山雜興  其一','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','溪石斑斑舞碎光，巖花冉冉馥幽香。',32,'全唐诗/poet.song.52000.json','["溪石斑斑舞碎光，巖花冉冉馥幽香。", "當時吳猛逢山處，金闕橫開在上方。"]'),
('c27dea27-ce98-47b8-b3aa-420a224e86df','廬山雜興  其二','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','隔崖垂蔓蔚蒼蒼，隠見莓苔舊石床。',32,'全唐诗/poet.song.52000.json','["隔崖垂蔓蔚蒼蒼，隠見莓苔舊石床。", "定有飛仙集其下，月明時復度笙篁。"]'),
('c0ee4e8e-3feb-45c6-ae4b-cd57b9f5e073','廬山雜興  其三','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','高松夾道夕陽明，抱葉風蟬引細聲。',32,'全唐诗/poet.song.52000.json','["高松夾道夕陽明，抱葉風蟬引細聲。", "勸爾行人聊駐足，出山無物更能清。"]'),
('9ac8005a-9dca-44d6-b40d-c84227b22bf4','廬山雜興  其四','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','星渚江邊月已生，石橋歸路夜崢嶸。',32,'全唐诗/poet.song.52000.json','["星渚江邊月已生，石橋歸路夜崢嶸。", "西風散入松千樹，翻覆銀河秋浪聲。"]'),
('e6d8c35e-a81e-4ce7-8e70-9ef40b4ea2ba','宿回峰院寄黄擇中察院','釋道潜','宋','宋诗','song-poetry','','[]','秋堂立四壁，物色夜蕭然。',144,'全唐诗/poet.song.52000.json','["秋堂立四壁，物色夜蕭然。", "藜床抱孤影，起坐未成眠。", "曾飈激高梧，萬動接虛警。", "感至情先謝，理冥神預領。", "銅壺漏未央，扶杖起彷徨。", "方塘溢繁荇，冷月下疏篁。", "躑躅步空除，風带褭霜裾。", "泯余契幽獨，悵子隔川途。", "短短袖中書，明發欲誰寄。", "梁上木鯉魚，儻能將此意。", "古亦有相思，吾今何所遺。", "浩歌望雲水，期子與同歸。"]'),
('ece14895-907f-45f3-850c-2eb4921b8f56','寄史院王正仲曾子開二學士','釋道潜','宋','宋诗','song-poetry','','[]','太史久不作，千秋想前人。',120,'全唐诗/poet.song.52000.json','["太史久不作，千秋想前人。", "朝廷理故事，董職須絕倫。", "青錢兩學士，班馬相並鄰。", "婆娑金閨中，婉孌得所親。", "學海揚波瀾，詞林藹芳春。", "青編炳金雘，允顯無曲陳。", "翹翹茂令德，諤諤規縉紳。", "玉堂行見躋，清切凌紫宸。", "野人蹈江海，放浪無邊垠。", "相思邈何許，共此青桂輪。"]'),
('156cfeaa-bc24-467e-9198-235ae025111d','寄東坡昆仲','釋道潜','宋','宋诗','song-poetry','','[]','江南十月天未霜，木梢冉冉猶青蒼。',128,'全唐诗/poet.song.52000.json','["江南十月天未霜，木梢冉冉猶青蒼。", "烟沙篁竹媚兩岸，亭午氣候如春陽。", "吳檣楚柁自紛擾，花鴨鸕鷀殊未忙。", "深灣野浦望不劇，葦間隠隠聞漁桹。", "黄昏無雲桂魄滿，一川秀色傾銀潢。", "何人隔岸弄長笛，吹風渡水聲悲凉。", "蘭臺故人天一方，美景樂事誰相將。", "船窗欹枕夜未央，杳杳孤雲空飛揚。"]'),
('c4786f7a-5c03-4dd2-8444-c2b1fb6f28ab','梅花寄章仲粹法曹','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','蕙死蘭枯驚歲晏，玉蕤初發照溪寒。',64,'全唐诗/poet.song.52000.json','["蕙死蘭枯驚歲晏，玉蕤初發照溪寒。", "從來吳苑牆頭見，不似匡廬谷底看。", "月浸繁枝香冉冉，露浮紅萼曉團團。", "參軍詩格追何遜，應笑山人自考槃。"]'),
('6f32b1e5-35b5-4c06-a79b-b367bdf1a34d','梅花  其一','釋道潜','宋','宋诗','song-poetry','','[]','雲英粲粲笑相重，結子能參鼎鼐功。',32,'全唐诗/poet.song.52000.json','["雲英粲粲笑相重，結子能參鼎鼐功。", "茜杏妖桃緣格俗，含芳不得與君同。"]'),
('bd5934de-0bc7-4804-b2af-49ba7e747f12','梅花  其二','釋道潜','宋','宋诗','song-poetry','','[]','造化推排力自强，非關著意占年芳。',32,'全唐诗/poet.song.52000.json','["造化推排力自强，非關著意占年芳。", "繁霜亂雪虛埋沒，傾國人知有此香。"]'),
('353845ff-4d7e-46bf-9873-6e5261a0d7c0','梅花  其三','釋道潜','宋','宋诗','song-poetry','','[]','枝頭灼灼爛生光，弄日驕寒倚短牆。',32,'全唐诗/poet.song.52000.json','["枝頭灼灼爛生光，弄日驕寒倚短牆。", "欲賦却慚無妙手，使人操筆憶何郎。"]'),
('3e67e5c9-1725-4c2d-a0a4-90075041af3c','寄福州太守孫莘老龍圖','釋道潜','宋','宋诗','song-poetry','','[]','公生自淮海，弱不游群兒。',288,'全唐诗/poet.song.52000.json','["公生自淮海，弱不游群兒。", "良哉白玉質，烱烱無磷緇。", "澡身以道德，餘棄爲文詞。", "端能處庠序，邈有孔孟姿。", "一朝擅高名，卓然動京師。", "餘輝耀天末，燁燁如斗箕。", "校讎芸閣中，精義無參差。", "同時鵷鷺行，半已翔鳳池。", "兩登諫官室，抗疏犯天威。", "揚舲去江海，曠歲成流離。", "朱輪擁苕霅，五馬從合肥。", "編氓仰遺愛，墮淚存豐碑。", "歸來遘風樹，憔悴不展眉。", "藉苫一室中，四壁無重帷。", "南鄰有古剎，而我方棲遲。", "杖藜時過公，泣血聞嗟咨。", "從容勸我坐，一飯常共爲。", "蒸蒸沸古鼎，蔌蔌投園葵。", "客來慵應門，客去知爲誰。", "禮喪事云既，始領吳門麾。", "瓶盂走梁苑，恨不相追隨。", "秋風亟東下，旌旆俄已睽。", "浮川與遵陸，多病亦云疲。", "七閩富名山，空翠相逶迤。"]'),
('1dd0afad-c5bb-4e07-8f68-6bb25e0d6426','聞子由舟及南昌以寄之','釋道潜','宋','宋诗','song-poetry','','[]','高安居士實人龍，五載南遷道愈豐。',64,'全唐诗/poet.song.52000.json','["高安居士實人龍，五載南遷道愈豐。", "域外城池剛自守，人間膏火詎能攻。", "屢嗟江海星霜隔，行喜雲林笑語同。", "五老峰前佳氣象，待君一醉吐長虹。"]'),
('35896b17-29ca-4ea5-b2f6-2924a5a697ca','和子由彭蠡湖遇風雪','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','夫子經濟材，妙質靜而默。',288,'全唐诗/poet.song.52000.json','["夫子經濟材，妙質靜而默。", "當年大廷中，如堵觀射策。", "雄哉賢父兄，一日並輝赫。", "勳業望夔龍，寧論二千石。", "扶摇吝不借，困此垂天翼。", "五載貶筠陽，區區校尋尺。", "鹽車厄驥足，道路行歎惜。", "脫身當歲晏，行李唯典籍。", "高懷久達觀，不見憔悴色。", "悠悠東下船，晚次彭蠡側。", "江風忽崩騰，江水翻且黑。", "飄風斷黄蘆，落雁委砂磧。", "鵝毛飛雪片，滿野來無極。", "龍驤飛萬斛，欲進不可得。", "淹留向汀灣，蕭瑟日將夕。", "黄昏勢漸壯，夜半已堆積。", "魚龍亦悲嘯，凜氣增几席。", "青燈冷不眠，坐漱元和液。", "危檣翻曉鴉，霽日動窗隙。", "搴幃望廬山，萬仞絕寸碧。", "茫茫銀世界，蕩蕩月閫域。", "順流復前趨，百里俄頃刻。", "暫停篙櫓喧，却著登山屐。", "五老笑相迎，千巖委圭璧。"]'),
('11332ddc-1c1e-4974-a091-3a3888d919e9','寄俞秀老清老二居士  其一','釋道潜','宋','宋诗','song-poetry','','[]','風溪雲巘雪消初，鳥變春聲滿屋除。',32,'全唐诗/poet.song.52000.json','["風溪雲巘雪消初，鳥變春聲滿屋除。", "安得故人同蠟屐，石梁斜日看游魚。"]'),
('98a91343-9508-44e7-9072-7641a91722d1','寄俞秀老清老二居士  其二','釋道潜','宋','宋诗','song-poetry','','[]','落星江水接天流，花絮飛時暮雨收。',32,'全唐诗/poet.song.52000.json','["落星江水接天流，花絮飛時暮雨收。", "波底鯉魚東去否，尺書煩汝到楊州。"]'),
('4d4fde75-5a4d-40a7-b438-6bacd5ab6ba2','寄俞秀老清老二居士  其三','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','慚愧君家好弟兄，風流宜與晉人并。',32,'全唐诗/poet.song.52000.json','["慚愧君家好弟兄，風流宜與晉人并。", "青鞋布襪能從我，共入廬山深處行。"]'),
('504c5f80-d8fb-4c05-b146-2ddfdf249376','廬山道中懷子瞻','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','谷口晴雲散曉光，鳥聲呼我渡橫塘。',64,'全唐诗/poet.song.52000.json','["谷口晴雲散曉光，鳥聲呼我渡橫塘。", "輕明獨愛桃花靜，撩亂偏嫌柳絮狂。", "處處叢祠起簫鼓，家家籬落動耕桑。", "去年今日東坡路，拄杖相將探海棠。"]'),
('0b2c79b2-bec9-4f17-87ee-8fa31f8ea064','酬周亨叔主簿見贈','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u6d1e\u5ead\u6e56"]','廬山百里蟠穹蒼，絕頂陰雲常下覆。',176,'全唐诗/poet.song.52000.json','["廬山百里蟠穹蒼，絕頂陰雲常下覆。", "晴日天風忽掃除，翠壁千層開錦繡。", "我來廬山初得君，愛君面有廬山秀。", "長篇險韵使我驚，忽獲風流雲散後。", "氣味清新滿牙頰，如入洞庭嘗橘柚。", "梅子如錢柳絮飛，杜鵑哀號山雨晝。", "念君明當京邑行，馬蹄蹴踏春泥縐。", "黄陂新息道路迥，野飯藜羹須强嗅。", "天街到日夏漸熱，車轂相摩汗如溜。", "丈夫功名非苟取，勸子未用輕藍綬。", "山中五月早歸來，澗底清泠當共漱。"]'),
('2114c324-3e6e-4212-b35b-f68a52e0d87d','訪荆國王公  其一','釋道潜','宋','宋诗','song-poetry','','[]','浩蕩經綸志已行，北山歸老思冥冥。',32,'全唐诗/poet.song.52000.json','["浩蕩經綸志已行，北山歸老思冥冥。", "可妨渡水穿雲客，拄杖芒鞋到戶庭。"]'),
('af1867e8-ea0d-43aa-85bb-63c3773a215a','訪荆國王公  其二','釋道潜','宋','宋诗','song-poetry','','[]','博辯舊聞輕孟子，談經早不愧楊雄。',32,'全唐诗/poet.song.52000.json','["博辯舊聞輕孟子，談經早不愧楊雄。", "惠能伎倆元無有，還許從容廣座中。"]'),
('0c153c64-2826-460a-9d03-06b77369273a','訪荆國王公  其三','釋道潜','宋','宋诗','song-poetry','','[]','苦嫌榮祿早收身，歸與漁樵共隠淪。',32,'全唐诗/poet.song.52000.json','["苦嫌榮祿早收身，歸與漁樵共隠淪。", "白下門西山迤邐，興來長是岸烏巾。"]'),
('1d580aea-c539-489f-a90a-cda08405acda','謁上竺觀音大士','釋道潜','宋','宋诗','song-poetry','','[]','十年江海去飄然，魂夢長依鷲嶺邊。',32,'全唐诗/poet.song.52000.json','["十年江海去飄然，魂夢長依鷲嶺邊。", "月地雲階重到處，殷勤稽首白衣僊。"]'),
('e448bc2c-7f6d-4d8c-a8fe-26188fed0b75','次韵元翁見寄','釋道潜','宋','宋诗','song-poetry','','[]','十載離群歎渺茫，良辰無地可相羊。',64,'全唐诗/poet.song.52000.json','["十載離群歎渺茫，良辰無地可相羊。", "何時却入蓮花社，軟語重焚栢子香。", "藹藹春風摇几席，紛紛啼鳥滿林塘。", "欲憑海燕傳消息，徑入君家舊屋梁。"]'),
('06f367bf-71b9-4c4b-b239-98424cc6a37a','病中四絕句呈劉景文左藏  其一','釋道潜','宋','宋诗','song-poetry','','[]','一室寥寥北嶺隈，午窗孤枕夢初回。',32,'全唐诗/poet.song.52000.json','["一室寥寥北嶺隈，午窗孤枕夢初回。", "無端自是風驚竹，錯認旁人問疾來。"]'),
('f05d5156-07fc-4398-bdc2-d4b6f19e427f','病中四絕句呈劉景文左藏  其二','釋道潜','宋','宋诗','song-poetry','','[]','西風薄木晚颼颼，古屋無人夜更幽。',32,'全唐诗/poet.song.52000.json','["西風薄木晚颼颼，古屋無人夜更幽。", "童子未閑煎藥火，隔窗燈影漫悠悠。"]'),
('457d1a8d-6a88-4d00-945b-99a872765a88','病中四絕句呈劉景文左藏  其三','釋道潜','宋','宋诗','song-poetry','','[]','高梧挂月照床頭，聒砌寒螿似怨秋。',32,'全唐诗/poet.song.52000.json','["高梧挂月照床頭，聒砌寒螿似怨秋。", "我病尚能安靜默，爾曹無事苦啁啾。"]'),
('fbbc634a-f1a2-4fdc-adeb-24d08bdb6b8b','病中四絕句呈劉景文左藏  其四','釋道潜','宋','宋诗','song-poetry','','[]','竹裏鳴鴉曉欲飛，遽褰疏箔望朝暉。',32,'全唐诗/poet.song.52000.json','["竹裏鳴鴉曉欲飛，遽褰疏箔望朝暉。", "莫嫌山色經秋瘦，我亦秋來減带圍。"]'),
('01a2c81b-fe88-4eba-b9dd-1a759d2a98a2','余初入智果院','釋道潜','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','泰山屹天下，四海同仰止。',192,'全唐诗/poet.song.52000.json','["泰山屹天下，四海同仰止。", "我公命世英，突兀等於是。", "胸中廓秋漢，皎絕微雲滓。", "當年事危言，軒冕如脫屣。", "正貴知我希，寧慚不吾以。", "風雲果再符，六翮排空起。", "一昨厭承明，抗章求迤邐。", "餘杭古雄藩，比屋富生齒。", "立談政即成，興不負山水。", "雍容敦末契，訪我頑且鄙。", "大旆輝松門，禽猿亦驚喜。", "森森門下士，左右粲珠履。", "使君道德姿，圭角非所恃。", "軟語如春風，薰然著桃李。", "今朝真勝事，千載足遺美。", "安得筆如椽，磨崖爲公紀。"]'),
('9a5923fd-baf7-4cb8-80b2-c48f08f0ab8c','龍井辯才老師新亭','釋道潜','宋','宋诗','song-poetry','','[]','遠公吾家傑，道妙非壺丘。',120,'全唐诗/poet.song.52000.json','["遠公吾家傑，道妙非壺丘。", "德傾龍象侶，貌蓋江湖秋。", "平生經論學，不爲名相留。", "滔滔若懸瀑，下注萬丈湫。", "昔年謝講事，衆挽不轉頭。", "刳心老巖穴，百念本不浮。", "東南多望士，唯見此老優。", "翰林天下公，方外寔輩流。", "旌旗虎溪路，竟日泉石游。", "衆生病未已，師意可忘憂。"]'),
('b70a4f72-c9c3-4d9e-a722-ff7e73b948dd','次韵蘇仲豫承務寄伯達推官','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','蘇子真豪英，氣貌嚴且重。',96,'全唐诗/poet.song.52000.json','["蘇子真豪英，氣貌嚴且重。", "幼無兒女姿，嗜好百不動。", "唯餘讀書事，乃與古人共。", "文章造深淳，詞力寬不縱。", "樂哉賢父兄，道義日相從。", "昨朝西湖外，目極孤鴻送。", "高帆去百里，山水乏吟弄。", "作詩投置郵，但述鴒原夢。"]'),
('a7d40094-55ea-486d-9db5-ebe588857344','辯才生日','釋道潜','宋','宋诗','song-poetry','','[]','像末真風恐不傳，故生豪傑爲人天。',64,'全唐诗/poet.song.52000.json','["像末真風恐不傳，故生豪傑爲人天。", "慈航橫截三千界，法雨均沾四十年。", "獨鶴精神秋始健，長松根節老彌堅。", "莫將有物觀無象，唾霧冰輪處處圓。"]'),
('1a82e910-71bf-41ab-9de9-70b76d62de61','寄題解頤堂','釋道潜','宋','宋诗','song-poetry','','[]','道人還家今幾時，築室構堂名解頤。',160,'全唐诗/poet.song.52000.json','["道人還家今幾時，築室構堂名解頤。", "尺書三遣要我賦，我獨老矣何能爲。", "塵埃筆研試料理，肝肺枯槁源不滋。", "爲君苦思强抽軋，詞慳氣迫無逶迤。", "東陽自古號多士，文采風流世有之。", "堂成往往獻佳句，羅列四壁皆瑰奇。", "譬如鈞天已九奏，安用擊筑鳴參差。", "又如玉食厭方丈，葵藿欲進旁必嗤。", "他年但約訪君去，借君几席聊偃欹。", "堂中插架足書史，牙籤玉軸當細窺。"]'),
('18da4488-9c5e-444e-b130-325ffbe163cc','送仲豫叔黨二承務赴試春闈','釋道潜','宋','宋诗','song-poetry','','[]','烱烱雙黄鵠，雍容振羽儀。',48,'全唐诗/poet.song.52000.json','["烱烱雙黄鵠，雍容振羽儀。", "風高辭澤國，歲暮及天池。", "文彩非凡近，周旋競陸離。", "明年翔集處，九萬是君期。"]'),
('5685fecc-fb22-45f6-97be-2524b522854f','同蘇文饒主簿西湖夜泛','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','鳳咮山頭暮靄空，月娥飛出廣寒宮。',64,'全唐诗/poet.song.52000.json','["鳳咮山頭暮靄空，月娥飛出廣寒宮。", "初登桂檝橫湖去，似覺銀河有路通。", "掠草飛螢星點點，眠沙宿鷺玉叢叢。", "從來江總文才妙，請付毫端刻畫中。"]'),
('a6434f57-c9fe-410f-97b7-63d7a9d2ecbf','酬錢塘宰王昭叔朝奉','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','令尹胸中萬斛寬，簿書堆案豈相關。',64,'全唐诗/poet.song.52000.json','["令尹胸中萬斛寬，簿書堆案豈相關。", "揮毫手過庖刀疾，訪勝心同止水閑。", "竹日映簷光破碎，雪雲開嶺翠連環。", "自嗟不及匡山遠，坐對淵明祇愧顔。"]'),
('6226e11f-f326-4420-a7a6-164309fc6df6','景文寵示','釋道潜','宋','宋诗','song-poetry','','[]','脫略今山簡，能吟舊子春。',48,'全唐诗/poet.song.52000.json','["脫略今山簡，能吟舊子春。", "偶因尋勝出，不爲採芳人。", "紅紫千葩盡，甘酸萬顆新。", "江雲浮翠壁，靄靄散魚鱗。"]'),
('999e8705-3a26-408c-90f3-5fb0686c1187','夏夜奉懷景文路分','釋道潜','宋','宋诗','song-poetry','','[]','曾櫩霽晚雨，餘響猶滴瀝。',108,'全唐诗/poet.song.52000.json','["曾櫩霽晚雨，餘響猶滴瀝。", "天風吹浮雲，入夜已無迹。", "月波泛脩竹，灧灧流几席。", "蘭膏滅衆炬，凉氣滿四壁。", "蕙烟擢銅爐，暗觸鼻端息。", "藜床但危坐，萬想本空寂。", "肺肝既冷然，紈扇亦暫釋。", "將軍不吾期，樂事空自得。", "願言賦長謠，爲我記此夕。"]'),
('0b104e2c-b911-4d83-a1fb-96d830b6c34a','次韵景文會朱充仁大夫魏敏中朝奉於望湖樓長句','釋道潜','宋','宋诗','song-poetry','','[]','高樓冠浮雲，下瞰百頃湖。',240,'全唐诗/poet.song.52000.json','["高樓冠浮雲，下瞰百頃湖。", "清漪照兩岸，秀色含菰蒲。", "騷人富筆力，領略驚須臾。", "短長隨萬象，肯議鶴與鳬。", "二客各英妙，溫溫古爲徒。", "從公文字飲，所樂非歌呼。", "酒酣挹諸山，高下如迎趨。", "籃輿復迤邐，遠訪飛來孤。", "炎蒸近亭午，天地如大爐。", "石泉飲吾廬，快意猶過屠。", "松門徹九里，始見靈山隅。", "佳名自開皇，籍甚聞中區。", "幽芳不時艷，地勝乃滋濡。", "招提數四海，雄觀宜且無。", "歸途憩壽星，寒碧森萬株。", "蕭騷聒衆響，孰辨笙與竽。", "抬眸矚新榜，蔚蔚氣自殊。", "將軍戀清絕，勸客頹玉壺。", "道人烹露芽，滿盞浮雲腴。", "儻無方外姿，未可同此娛。"]'),
('6aa479e1-6c12-4a99-a68f-59183aaa9cc3','寒食日玉提刑過訪，有詩示怡然并余，余次韵之','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','使君薄珪組，富貴良易足。',192,'全唐诗/poet.song.52000.json','["使君薄珪組，富貴良易足。", "一麾下東南，千里爭拭目。", "援毫賦山水，詞力瀉溪谷。", "勝游便杖屨，聒耳厭絲竹。", "西湖破春冰，曉漲翻晴綠。", "相將二使軺，導從還屏逐。", "後先度巖壑，頡頏追鸞鵠。", "樂事殊未央，酒行宜局促。", "風流俄醉舞，坐客瞻頹玉。", "嵇阮真達生，秦唐謾歌哭。", "斜陽絕湖去，兩槳凌波速。", "却尋元龍居，隠隠隔喬木。", "到門呼主人，展畫滿高屋。", "夕鼓來遠近，雨聲飄斷續。", "籃輿入城市，夾道鬧燈燭。", "盛事在餘杭，他年見圖錄。"]'),
('8a3f789e-8078-443e-b7be-d988485be8c8','別蘇翰林','釋道潜','宋','宋诗','song-poetry','','[]','四海窺人物，其誰似我公。',48,'全唐诗/poet.song.52000.json','["四海窺人物，其誰似我公。", "論交容末契，許國見深衷。", "漸遠吳天月，行披禁殿風。", "玉堂清夜夢，解后過江東。"]'),
('6a8dfc35-0b31-4e12-a7e2-4642d7c1bcad','送景文','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','交游盡四海，厚我乃無幾。',144,'全唐诗/poet.song.52000.json','["交游盡四海，厚我乃無幾。", "劉侯軀七尺，堂堂信英偉。", "中剛冷如鐵，萬事肯料理。", "相逢傾蓋餘，眷眷極終始。", "東南久徹警，將領用儒士。", "三年湖山游，屢得陪屐齒。", "長謠傲雲壑，草木俱披靡。", "詞鋒剉萬象，搜索泣山鬼。", "珠璣溢錦囊，所得真富矣。", "軒冕本儻來，功名徒爾耳。", "一廛聞已卜，視此猶脫屣。", "歲晚匡廬山，高棲踵前軌。"]'),
('f2a586d5-2a83-49fe-9194-ab018e342a2e','贈太守林子中待制','釋道潜','宋','宋诗','song-poetry','','[]','拭目除書下九天，邦人爭賀使君賢。',64,'全唐诗/poet.song.52000.json','["拭目除書下九天，邦人爭賀使君賢。", "風流謝守宣城日，愷悌龔公渤海年。", "終作鹽梅均鼎鼐，且憑觴豆樂山川。", "一門棣萼登臺省，盛事駸駸海內傳。"]'),
('1f126927-bb76-443e-8f21-99dbbcd08fdf','四照閣奉陪辯才老師夜坐懷少游學士','釋道潜','宋','宋诗','song-poetry','','[]','猨鳥投林已寂然，芭蕉過雨小樓前。',64,'全唐诗/poet.song.52000.json','["猨鳥投林已寂然，芭蕉過雨小樓前。", "雲依絕壁中間破，月自遙峰缺處圓。", "照坐不須紅蠟炬，可人唯有蕙爐烟。", "校讎御府圖書客，疇昔還同此夜禪。"]'),
('9f6455c2-3165-4317-9e8a-1292a3a58b15','贈天竺聰道人','釋道潜','宋','宋诗','song-poetry','','[]','完完明月珠，蓄彼萬丈淵。',156,'全唐诗/poet.song.52000.json','["完完明月珠，蓄彼萬丈淵。", "徑寸不可睹，餘輝媚清川。", "道人實有道，膠口默不傳。", "心閑氣自和，眉宇常藹然。", "邦人昔致師，欲以居法筵。", "文移動帥府，禮數端亦虔。", "冥鴻避網羅，矯翼從高騫。", "朅來靈山隅，圓蒲味深禪。", "盛德不自顯，與物同周旋。", "兒曹恃文采，毫末爭醜妍。", "相逢廣坐間，肯顧斯人賢。", "茫茫大化中，浮名暫腥膻。", "吾知道人意，反汝生哀憐。"]'),
('551aafd8-dbf5-4530-9703-66f203c1041f','送僧遊天台','釋道潜','宋','宋诗','song-poetry','','[]','海邊孤起碧千尋，俯仰應酬壯觀心。',64,'全唐诗/poet.song.52000.json','["海邊孤起碧千尋，俯仰應酬壯觀心。", "峭壁斷崖當歲晏，冷雲疏雪上衣襟。", "論懷此日能傾倒，尺素它時嗣好音。", "摘勝窮幽吾老矣，杖藜無復伴登臨。"]'),
('31a4c737-66fe-4100-9f13-fca728e935c2','覽黄子理詩卷','釋道潜','宋','宋诗','song-poetry','','[]','六載南官何所營，百篇翻覆見高情。',64,'全唐诗/poet.song.52000.json','["六載南官何所營，百篇翻覆見高情。", "霜鷗露鵠元非俗，雪竹風松本自清。", "俊逸固宜凌鮑照，優游真已逼淵明。", "微言會有知君者，謾擬鍾嶸試一評。"]'),
('91229bea-1a71-411e-8226-66714614dd1f','梅花寄汝陰蘇太守','釋道潜','宋','宋诗','song-poetry','','[]','湖山摇落歲方悲，又見梅花破玉蕤。',64,'全唐诗/poet.song.52000.json','["湖山摇落歲方悲，又見梅花破玉蕤。", "一樹輕明侵曉岸，數枝清瘦耿疏籬。", "良辰易失空回首，習氣難忘尚有詩。", "所向皆公舊題墨，肯辜魚鳥却來期。"]'),
('4e916b47-5492-4c19-ac19-4c79a45f9bb5','次韵陳敏善秀才見過','釋道潜','宋','宋诗','song-poetry','','[]','投老形骸真木偶，水飲巖栖聊自守。',128,'全唐诗/poet.song.52000.json','["投老形骸真木偶，水飲巖栖聊自守。", "世事浮雲日變遷，我亦何心預臧否。", "故人新自廣陵來，問我詩囊近何有。", "吾言淡薄非橄欖，縱可咀嚼聊能久。", "且開窗戶話平生，湖色山光翠相糾。", "烘簷暖日氣味好，相對蒲團復支肘。", "愛君年少擅才華，詩律清妍無可醜。", "却愁征棹促君還，空聽陽關詞一首。"]'),
('605dd58a-aec0-4841-9ab7-8d391c33aa29','都僧正慈化大師挽詞  其一','釋道潜','宋','宋诗','song-poetry','','[]','領袖吾家事，由來二十春。',48,'全唐诗/poet.song.52000.json','["領袖吾家事，由來二十春。", "虛懷能應物，直氣肯隨人。", "逝水流方遠，臨池墨尚新。", "聲聞雙樹子，不見葉間身。"]'),
('a513cb7c-6eb2-4140-a630-ec6dc3324345','都僧正慈化大師挽詞  其二','釋道潜','宋','宋诗','song-poetry','','[]','平生輕長物，身世等鴻毛。',48,'全唐诗/poet.song.52000.json','["平生輕長物，身世等鴻毛。", "譽出東南早，人驚節義高。", "玩奇唯水石，結客盡英豪。", "來往元無迹，情鍾謾鬰陶。"]'),
('878d1960-5423-48ba-9c0e-edad707d75d7','都僧正慈化大師挽詞  其三','釋道潜','宋','宋诗','song-poetry','','[]','伏枕時無幾，臨分若故常。',48,'全唐诗/poet.song.52000.json','["伏枕時無幾，臨分若故常。", "寸心能烱烱，去路豈茫茫。", "車馬門猶盛，芝蘭室更香。", "獨餘庭下竹，冷韵起悲凉。"]'),
('780965bb-5d75-42ea-9228-8faed591a9d7','次韵吳承老推官觀開西湖','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','偉人謀議不求多，事定紛紛自唯阿。',64,'全唐诗/poet.song.52000.json','["偉人謀議不求多，事定紛紛自唯阿。", "盡放龜魚還淥凈，肯容蕭葦障前坡。", "一朝美事誰能紀，百尺蒼崖尚可磨。", "天上列星當亦喜，月明時下浴晴波。"]'),
('f0c61c24-35f0-43d5-9f4f-e4e869231ab4','都僧正既闕子中待制欲余補其位輒辭以小詩遂獲免','釋道潜','宋','宋诗','song-poetry','','[]','佩德懷恩豈易陳，自嗟麋鹿性難馴。',32,'全唐诗/poet.song.52000.json','["佩德懷恩豈易陳，自嗟麋鹿性難馴。", "流年日月無多子，乞取山林放曠身。"]'),
('68c2b36d-1430-4c0a-9357-c08284fc4a95','送子中待制  其一','釋道潜','宋','宋诗','song-poetry','','[]','翹翹孤鳳凰，安巢本阿閣。',60,'全唐诗/poet.song.52000.json','["翹翹孤鳳凰，安巢本阿閣。", "偶來依澤國，歸興遂淹泊。", "江山迫歲華，草木正摇落。", "霜空肅萬里，纖翳無處著。", "翻然整羽儀，一舉在寥廓。"]'),
('122a6cf6-f3d7-4e30-ad8a-794e68452498','送子中待制  其二','釋道潜','宋','宋诗','song-poetry','','[]','南山有佳木，秀色何葳蕤。',60,'全唐诗/poet.song.52000.json','["南山有佳木，秀色何葳蕤。", "封植不記年，落落今百圍。", "盤根雖自固，烈風無時吹。", "匠手營大厦，衆材得施爲。", "偉哉梁棟姿，取用不可遲。"]'),
('b22b1ad1-37e0-4b7d-8904-0f658df4b02c','送子中待制  其三','釋道潜','宋','宋诗','song-poetry','','[]','平生長樂公，聲華越三紀。',72,'全唐诗/poet.song.52000.json','["平生長樂公，聲華越三紀。", "文章兩京齊，學術游夏比。", "螭頭足未安，符竹已屢徙。", "聯翩開幕府，爛熳樹桃李。", "鋒車入帝鄉，天馬行九軌。", "周旋有程度，駑駕安足擬。"]'),
('d6b739b2-1f29-457f-b201-cb4f39cf9fce','曉發苕溪將次徑山呈通判廖明略學士','釋道潜','宋','宋诗','song-poetry','','[]','明星耿耿出天東，結束籃輿伴我公。',64,'全唐诗/poet.song.52000.json','["明星耿耿出天東，結束籃輿伴我公。", "藹藹梅香侵曉陌，斑斑旗脚轉春風。", "勝游此日塵埃外，回首它年夢寐中。", "絕景小詩難壯觀，當看醉筆吐長虹。"]'),
('f92c5ba3-6521-470c-beb3-32f7e0d60433','次韵王行甫奉議湖上晚歸遇雨','釋道潜','宋','宋诗','song-poetry','','[]','妙齡公子嗜遨嬉，永日湖山未肯歸。',64,'全唐诗/poet.song.52000.json','["妙齡公子嗜遨嬉，永日湖山未肯歸。", "酒幟曉人應慣識，花枝拂帽不須揮。", "輕紈細綺來何處，青蓋朱輪去似飛。", "向晚薄雷催急雨，清寒無奈襲裳衣。"]'),
('fba973a4-1f28-4a94-8989-f151e61df8a7','同曾仲錫通判游天竺諸山','釋道潜','宋','宋诗','song-poetry','','[]','煌煌世胄餘，夫子非碌碌。',192,'全唐诗/poet.song.52000.json','["煌煌世胄餘，夫子非碌碌。", "由腹有詩書，所以能拔俗。", "得官本河朔，瓜期未云促。", "扁舟下東南，逸興追鴻鵠。", "遇勝即徜徉，風餐兼露宿。", "嗟余偶傾蓋，一笑外羈束。", "杖策每過從，相携訪山谷。", "春風披鮮榮，繡錯出林麓。", "松門有時盡，幽興無斷續。", "崖轉聞鍾聲，林疏見華屋。", "銜山餘落景，歸路猶躑躅。", "誰云鄴下歡，往事不可復。", "吾曹二三子，所樂亦云足。", "願公紀新詩，一一能見錄。", "船頭行北歸，囊篋有美玉。", "塵埃京洛人，示與洗心目。"]'),
('9d72e758-a747-4b4d-a331-6ed72f24a6a5','次韵劉韋孟主簿湖上  其一','釋道潜','宋','宋诗','song-poetry','','[]','劉郎詞筆過蘭成，詠遍湖山草木情。',32,'全唐诗/poet.song.52000.json','["劉郎詞筆過蘭成，詠遍湖山草木情。", "祿隠太平真樂事，莫思神武挂冠纓。"]'),
('872f99d9-44cd-4a9c-ab7e-cdab18ca7464','次韵劉韋孟主簿湖上  其二','釋道潜','宋','宋诗','song-poetry','','[]','中流出沒一舟虛，緩檝長謠彼自如。',32,'全唐诗/poet.song.52000.json','["中流出沒一舟虛，緩檝長謠彼自如。", "聞說古來江海上，達人多半寄樵漁。"]'),
('fd2275ca-6de7-4191-8d24-2529e490aa1c','次韵劉韋孟主簿湖上  其三','釋道潜','宋','宋诗','song-poetry','','[]','老葑如雲既卷除，風瀾百頃翠紆餘。',32,'全唐诗/poet.song.52000.json','["老葑如雲既卷除，風瀾百頃翠紆餘。", "奇探險取各爭賦，誰復能名造物初。"]'),
('930a433f-e4d2-4891-ac75-94d7b4b56998','遊苕溪道場山','釋道潜','宋','宋诗','song-poetry','','[]','東風吹雨過城闉，日照河隄柳映津。',64,'全唐诗/poet.song.52000.json','["東風吹雨過城闉，日照河隄柳映津。", "雨槳差差摇燕尾，千山漠漠散魚鱗。", "長緣絕境關幽夢，尚喜茲游及暮春。", "蘭蕙未衰桃李在，蜂喧鳥咽莫愁人。"]'),
('fba3a8f0-7436-4b4c-b1a0-65a97e616a6b','夏夜','釋道潜','宋','宋诗','song-poetry','','[]','松室開孤定，褰幃納夜凉。',24,'全唐诗/poet.song.52000.json','["松室開孤定，褰幃納夜凉。", "嬋娟依翠竹，無語過東牆。"]'),
('18253a90-9687-44c6-a31e-4b9453a42e3a','送蘭花與毛正仲運使  其一','釋道潜','宋','宋诗','song-poetry','','[]','幽姿冷艷匪夭饒，曾伴靈均賦楚騷。',32,'全唐诗/poet.song.52000.json','["幽姿冷艷匪夭饒，曾伴靈均賦楚騷。", "今日移根庭下植，可無佳句與揮毫。"]'),
('971553e2-8112-414b-b002-4178bea0fb74','送蘭花與毛正仲運使  其二','釋道潜','宋','宋诗','song-poetry','','[]','從來託迹喜深林，顯晦那求世所聞。',32,'全唐诗/poet.song.52000.json','["從來託迹喜深林，顯晦那求世所聞。", "偶至華堂奉君子，不隨桃李鬭氤氳。"]'),
('7c0d7513-a161-4e44-b175-7ab18c880e44','夏日竹閣','釋道潜','宋','宋诗','song-poetry','','[]','沈水擢烟青繚繞，風篁傳韵冷蕭騷。',32,'全唐诗/poet.song.52000.json','["沈水擢烟青繚繞，風篁傳韵冷蕭騷。", "楚山竹簟琉璃滑，臥看炎雲檻外高。"]'),
('ad2197c6-1975-4749-b484-c2afba068451','送李仲益赴襄陽幕','釋道潜','宋','宋诗','song-poetry','','[]','襄陽古名都，雄觀壓荆楚。',144,'全唐诗/poet.song.52000.json','["襄陽古名都，雄觀壓荆楚。", "醉公誇文詞，風物粲可數。", "嗟余未歷覽，彷彿已如睹。", "人生游宦間，得此亦佳遇。", "李俊妙天姿，文行兩自負。", "少年志冥鴻，千里輕一舉。", "天風不借便，造物暫淹阻。", "既無負郭田，黽勉依幕府。", "賢哉彼方伯，脫略高韵度。", "寧俾簿書役，朱墨事朝暮。", "爽氣對西山，清談共樽俎。", "試問鹿門翁，遺蹤今在否。"]'),
('fecf6065-1eb7-4e08-ab53-b9ad1c50a6ef','訪勤上人','釋道潜','宋','宋诗','song-poetry','','[]','斷橋蒼壁倚溪斜，赤葉楓林噪晚鴉。',32,'全唐诗/poet.song.52000.json','["斷橋蒼壁倚溪斜，赤葉楓林噪晚鴉。", "可怕嶺雲埋徑路，會尋流水到君家。"]'),
('24bf57a8-e13c-4f21-a673-6c7875f74bfd','答柯山曉上人','釋道潜','宋','宋诗','song-poetry','','[]','風騷古人事，而我豈所長。',120,'全唐诗/poet.song.52000.json','["風騷古人事，而我豈所長。", "兒曹嗜章句，餘習未易忘。", "根源本無有，真若夏潦潢。", "道人氣拔俗，吾黨稱俊良。", "十年依叢林，實以道自將。", "禪餘喜賦詠，妙語逾珪璋。", "世眼獨未識，深叢閟孤芳。", "鋒錐必穎脫，安肯久處囊。", "子宜力自勉，聲問終揚揚。", "吾言豈知子，老大殊荒唐。"]'),
('a5b4f8f5-0df8-4e08-aa72-b089348604a0','送俞伯謨宣德赴辟成都','釋道潜','宋','宋诗','song-poetry','','[]','我生落拓如虛舟，萬里江湖隨演漾。',144,'全唐诗/poet.song.52000.json','["我生落拓如虛舟，萬里江湖隨演漾。", "君今祿仕亦我同，南北悠悠無定向。", "故鄉回首海東頭，兄弟十年官塞上。", "才高質美衆所奇，杞梓豫章非冗長。", "辟書交飛上廟堂，肯使須臾事閑曠。", "秦山崢嶸塹戎虜，自古征人愁悵望。", "劍門棧閣天下危，去馬來車魂欲喪。", "羨君年少勇攀躋，足躡青冥身益壯。", "舊游陳迹想依然，感物懷親情獨愴。"]'),
('e9e73d4d-446e-4634-8ef7-65dc0877c3cd','次韵文饒同自龍井出資國度泛舟以歸北山','釋道潜','宋','宋诗','song-poetry','','[]','踞虎奔犀列萬形，奇觀真已過南屏。',64,'全唐诗/poet.song.52000.json','["踞虎奔犀列萬形，奇觀真已過南屏。", "縈雲細路杳無盡，落石飛泉靜有聲。", "十里平湖初卷葑，一天秋色共揚舲。", "停橈共過孤山寺，寂寂林僧半掩扃。"]'),
('7fd0779e-b288-4b77-b7c0-518ff182217b','陪司馬才仲節推諸君游天竺','釋道潜','宋','宋诗','song-poetry','','[]','西郊久不雨，草木無餘青。',120,'全唐诗/poet.song.52000.json','["西郊久不雨，草木無餘青。", "薄雲弄秋暉，山色時晦冥。", "超然五詞客，文采披華星。", "聯翩過吾廬，車蓋紛滿庭。", "相携訪靈鷲，細路通巖扃。", "攀翻幽桂叢，衣襟襲芳馨。", "絕境異人世，吾詩豈能名。", "諸豪追鄴下，妙語逾瓊英。", "願言一揮寫，樂事良難并。", "高空墮海日，歸驂尚能停。"]'),
('4ba47ac1-4e13-49d0-a4a9-8ae8738bd4eb','呈丞相章公','釋道潜','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','大滌仙翁謝往還，蕭然几席奉清閑。',64,'全唐诗/poet.song.52000.json','["大滌仙翁謝往還，蕭然几席奉清閑。", "胸中舊已吞雲夢，人望從來重泰山。", "書到鍾王方絕學，文非典誥不須攀。", "名言一一皆公語，它日親聞廣坐間。"]'),
('e18af8af-a15d-454c-874f-4a8c286cbd5a','過定林謁荆公畫像  其一','釋道潜','宋','宋诗','song-poetry','','[]','古林蒼藤一徑纏，我公疇昔屢回旋。',32,'全唐诗/poet.song.52000.json','["古林蒼藤一徑纏，我公疇昔屢回旋。", "蕭蕭屋底瞻遺像，傑氣英姿尚凜然。"]'),
('d396507c-f4d8-450c-8d8c-28cffcd786b4','過定林謁荆公畫像  其二','釋道潜','宋','宋诗','song-poetry','','[]','壁間千字走龍蛇，好事何人護絳紗。',32,'全唐诗/poet.song.52000.json','["壁間千字走龍蛇，好事何人護絳紗。", "一讀已能生感慨，暮簷蕭瑟更啼鴉。"]'),
('e2503b7d-1d66-4946-a2d8-ede037279e3f','次韵曾子開侍郎話別  其一','釋道潜','宋','宋诗','song-poetry','','[]','二紀浮游踏世塵，賢愚了了見情真。',32,'全唐诗/poet.song.52000.json','["二紀浮游踏世塵，賢愚了了見情真。", "行藏不昧如公少，細聽名言實可人。"]'),
('56d810ec-4752-4da9-b5ef-f4aa04cfa242','次韵曾子開侍郎話別  其二','釋道潜','宋','宋诗','song-poetry','','[]','抗論儀曹肯折旋，一麾江海去飄然。',32,'全唐诗/poet.song.52000.json','["抗論儀曹肯折旋，一麾江海去飄然。", "他時開府餘杭郡，來酌吾廬石縫泉。"]'),
('b530095c-db6c-4401-a317-825d505821f9','書夢寄妙懿','釋道潜','宋','宋诗','song-poetry','','[]','妙思堂深路屈盤，夜來魂夢忽躋攀。',32,'全唐诗/poet.song.52000.json','["妙思堂深路屈盤，夜來魂夢忽躋攀。", "道人開戶相迎處，宛在脩篁翠霧間。"]'),
('183f748d-6692-4819-993c-bb0ee654b8a1','觀恭師詩書以二絕勉之  其一','釋道潜','宋','宋诗','song-poetry','','[]','吾鄉英秀頗能文，子復區區慕碧雲。',32,'全唐诗/poet.song.52000.json','["吾鄉英秀頗能文，子復區區慕碧雲。", "請用三多爲祖式，他時自與古人群。"]'),
('0260ed04-b672-488c-a49e-1ce13716b5ab','觀恭師詩書以二絕勉之  其二','釋道潜','宋','宋诗','song-poetry','','[]','論書當亦似論兵，軍律非嚴事不成。',32,'全唐诗/poet.song.52000.json','["論書當亦似論兵，軍律非嚴事不成。", "行伍會須同比櫛，出奇方可語縱橫。"]'),
('aedfd5fe-96d0-431a-9357-4b50e1f1015e','過鍾山尋俞清老不遇','釋道潜','宋','宋诗','song-poetry','','[]','霜風薄木韵含悲，歲晚尋君失後期。',32,'全唐诗/poet.song.52000.json','["霜風薄木韵含悲，歲晚尋君失後期。", "夜鶴曉猨驚怨歇，草堂人去已多時。"]'),
('f7130073-77ff-40c4-8edf-5d8f6c140e51','次韵劉伯昌長官見贈','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','劉侯詩格殆天全，初得西湖紀勝篇。',64,'全唐诗/poet.song.52000.json','["劉侯詩格殆天全，初得西湖紀勝篇。", "錦繡爲腸供麗藻，鯨鯢作氣吸長川。", "靜依北牖開樽俎，醉掃寒梢雜雨烟。", "歲晚扁舟東去急，喜君高調重遷延。"]'),
('78e4e618-8206-4b12-a32e-d0bfaf4bf418','次韵法真禪師送曾敬之宣德昆仲','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','昔與乃翁相遇年，始知有子生且賢。',144,'全唐诗/poet.song.52000.json','["昔與乃翁相遇年，始知有子生且賢。", "爾來雙幹已爭秀，屹屹欲上參高天。", "昨朝較蓺偶不售，他日奏賦聞甘泉。", "方今廟堂喜人物，收拾萬彙歸陶甄。", "褭蹄麟趾終一出，輝映左右無餘妍。", "肯學孟生誇得意，一日走遍春風前。", "嗟余投老隠巖谷，形若槁木心灰然。", "扁舟追子僅千里，彷彿夜夢遙相傳。", "西湖風物行歲晏，歸賦梅花趁臘先。"]'),
('a59e974b-3995-41b4-b212-fc411dc8e13d','送文惠師還金華','釋道潜','宋','宋诗','song-poetry','','[]','脫略紛華自妙年，秉心端喜事金僊。',64,'全唐诗/poet.song.52000.json','["脫略紛華自妙年，秉心端喜事金僊。", "終期象馭超三界，不羨鵬程越九天。", "考疏窮經心尚壯，依仁據德節尤堅。", "秋風陡起庭闈念，聊寄脩江一葉船。"]'),
('60b80c12-0cc8-4e61-9f04-3620e6dd61b2','證師聖可桐虛齋','釋道潜','宋','宋诗','song-poetry','','[]','吾聞嶧山桐，猗猗排秀幹。',148,'全唐诗/poet.song.52000.json','["吾聞嶧山桐，猗猗排秀幹。", "栖鸞宿鳳信所奇，衆木紛紛何足算。", "嗚呼，天相彼質，復虛彼心。", "故其聲之隠也無閡，其動也無留。", "有叩而鳴，體佚而休。", "嘉上人之妙齡兮，無適俗之卑韵。", "剛有擬於斯桐兮，廓中虛以受訓。", "異速成之朝榮兮，培益厚而日敏。", "悼像末之寥寥兮，蹇吾道之不振。", "續芳塵於祖席兮，他日非桐虛上人者而復誰何哉。"]'),
('96f8e368-df51-48e8-9e45-615e681541dc','規師方外停雲齋','釋道潜','宋','宋诗','song-poetry','','[]','上人少脫略，出處非拘囚。',60,'全唐诗/poet.song.52000.json','["上人少脫略，出處非拘囚。", "停雲倚空端，舒卷良自由。", "縱之千丈强，斂附拳石幽。", "超遙宇宙間，孰與斯人儔。", "銘詩善摹寫，居士亦風流。"]'),
('2962c815-2c63-49f1-a9e2-4ad680c4d404','卜居智果方外以詩見寄次韵奉酬  其一','釋道潜','宋','宋诗','song-poetry','','[]','偶來湖上緝衡門，桐長脩柯竹有孫。',32,'全唐诗/poet.song.52000.json','["偶來湖上緝衡門，桐長脩柯竹有孫。", "引策每從佳處去，望雲橋下是西村。"]'),
('8bfebe50-659b-4c60-ac41-58ced2748258','卜居智果方外以詩見寄次韵奉酬  其二','釋道潜','宋','宋诗','song-poetry','','[]','青燈殘篆夜寥寥，門外秋風振葦蕭。',32,'全唐诗/poet.song.52000.json','["青燈殘篆夜寥寥，門外秋風振葦蕭。", "慚愧高人能見憶，爲余西望立溪橋。"]'),
('7ff0fdc4-7a63-44ce-a2d4-2c256253f998','次韵周開祖大夫泛湖見訪','釋道潜','宋','宋诗','song-poetry','','[]','漾漾清漪十里間，畫船人似鏡中安。',64,'全唐诗/poet.song.52000.json','["漾漾清漪十里間，畫船人似鏡中安。", "雨催菡萏幽香發，風觸莆萄細浪寒。", "高岸烏紗來靜院，倒揮白羽傍曾欄。", "吟毫所遇無遺景，天乞詞源北海寬。"]'),
('db856c98-8f37-4890-bf5e-bf54ce7842c0','次韵才仲試院夢中書事見寄  其一','釋道潜','宋','宋诗','song-poetry','','[]','夢入秋山知幾層，霜風吹骨正稜稜。',32,'全唐诗/poet.song.52000.json','["夢入秋山知幾層，霜風吹骨正稜稜。", "蒼崖犖确難安足，自說從余授杖藤。"]'),
('f4c52e62-6f62-4a00-9c09-d2bc573e7570','次韵才仲試院夢中書事見寄  其二','釋道潜','宋','宋诗','song-poetry','','[]','朱甍碧瓦礙雲浮，共躡曾梯最上頭。',32,'全唐诗/poet.song.52000.json','["朱甍碧瓦礙雲浮，共躡曾梯最上頭。", "一餉闌干變風雨，凜然毛髮便驚秋。"]'),
('223b5d98-3b58-4a4c-a061-a7aaf64823ab','次韵才仲試院夢中書事見寄  其三','釋道潜','宋','宋诗','song-poetry','','[]','怪獸胡爲出巨津，昂然激水忽翻身。',32,'全唐诗/poet.song.52000.json','["怪獸胡爲出巨津，昂然激水忽翻身。", "魚龍贔屭何妨事，莫作風波謾恐人。"]'),
('d958ceba-8ce7-4669-80ab-b9662740f43e','次韵才仲試院夢中書事見寄  其四','釋道潜','宋','宋诗','song-poetry','','[]','一川脩竹映疏花，川上時聞響釣車。',32,'全唐诗/poet.song.52000.json','["一川脩竹映疏花，川上時聞響釣車。", "似到秦人種桃處，誰知夢斷却還家。"]'),
('79ce202d-7914-427d-848c-bd0521b7c5c0','次韵才仲試院夢中書事見寄  其五','釋道潜','宋','宋诗','song-poetry','','[]','崖根烏蜜已先嘗，從此知君鬢不霜。',32,'全唐诗/poet.song.52000.json','["崖根烏蜜已先嘗，從此知君鬢不霜。", "應笑吾曹事枯槁，山中危坐獨休糧。"]'),
('e1d248f3-a72a-4b0e-99a4-88cfee22f311','贈吳子野先生','釋道潜','宋','宋诗','song-poetry','','[]','麻田老仙心炯炯，少有高風慕箕潁。',96,'全唐诗/poet.song.52000.json','["麻田老仙心炯炯，少有高風慕箕潁。", "枕流漱石三十年，眸子瞭焉神更靜。", "忽然杖策海上來，至人道妙同塵埃。", "達官貴侯競招致，往無所欲誰嫌猜。", "邇來一志從吾黨，跡與孤雲共天壤。", "曹溪有路更攀躋，徑躡毗盧高頂上。"]'),
('38ad87f9-fa11-4470-8169-6e94536bf420','送庠上人','釋道潜','宋','宋诗','song-poetry','','[]','點檢行裝拂與巾，洒然輕別故山春。',32,'全唐诗/poet.song.52000.json','["點檢行裝拂與巾，洒然輕別故山春。", "家家門底長安道，舉目何須更問津。"]'),
('c7f6535a-11d6-48c5-9bb7-99c7e8b8214b','次韵才仲山行','釋道潜','宋','宋诗','song-poetry','','[]','幕府文書一掃空，何妨行樂醉春風。',64,'全唐诗/poet.song.52000.json','["幕府文書一掃空，何妨行樂醉春風。", "想聞笑語千山外，正在烟雲萬疊中。", "哢日鳥聲喧細碎，照溪花影靜玲瓏。", "苦吟只恐凋肝腎，夫子還宜少黜聰。"]'),
('d89a741e-e6d7-420e-a1db-6d18b8ee9eed','與神智師話別','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','昔我年始壯，託身靈鷲峰。',132,'全唐诗/poet.song.52000.json','["昔我年始壯，託身靈鷲峰。", "主人大導師，鼓舞揚真風。", "四方依絳帳，雜遝象與龍。", "嗟余於此時，已識大士蹤。", "紛紛論議場，頭角出群雄。", "如何三十載，慧刃藏其鋒。", "端居肄業地，了不爲世通。", "邇獨念西湖，聿來將誰從。", "情隨山水遠，興與魚鳥同。", "平生方外姿，自在如冥鴻。", "明朝復回首，飄洒一孤篷。"]'),
('e1c9ac11-e417-4fdc-9373-fe6d11c80a81','暉暉堂','釋道潜','宋','宋诗','song-poetry','','[]','堂上何爲絕點埃，堂前翠箒掃空階。',32,'全唐诗/poet.song.52000.json','["堂上何爲絕點埃，堂前翠箒掃空階。", "遙憐薄日暉暉靜，影入高人燕坐懷。"]'),
('096f35f4-ff6d-46c9-8baf-c387bd95457c','次韵嵩陽陳叔易先生見訪  其一','釋道潜','宋','宋诗','song-poetry','','[]','知君挾冊未嘗閑，一志端能事孔顔。',32,'全唐诗/poet.song.52000.json','["知君挾冊未嘗閑，一志端能事孔顔。", "千里扁舟下吳會，眼中收拾只溪山。"]'),
('4bcfa11c-539d-4853-936d-8a9b9ff82342','次韵嵩陽陳叔易先生見訪  其二','釋道潜','宋','宋诗','song-poetry','','[]','枯槁長專一壑間，權豪殊未少低顔。',32,'全唐诗/poet.song.52000.json','["枯槁長專一壑間，權豪殊未少低顔。", "風雲他日超騰去，莫畏移文到北山。"]'),
('14b777e1-647a-41b3-8dfe-5d61db20714c','曉霽','釋道潜','宋','宋诗','song-poetry','','[]','雲擁茅簷水拍渠，曉來新雨過吾廬。',32,'全唐诗/poet.song.52000.json','["雲擁茅簷水拍渠，曉來新雨過吾廬。", "蔫紅宿萼莓苔滿，解事長楊自掃除。"]'),
('5a41cf60-619a-4dbe-92c4-8d4e21097e42','次韵龔堯佐帳勾晨起感懷','釋道潜','宋','宋诗','song-poetry','','[]','造物紛紛自變更，達人何用較前程。',64,'全唐诗/poet.song.52000.json','["造物紛紛自變更，達人何用較前程。", "芭蕉身世榮枯久，胡蝶夢魂來往輕。", "隔屋相驚銅漏盡，開扉猶愛玉繩橫。", "應嫌百吏鳬行進，簿領文書與案平。"]'),
('43d389ac-58ec-44df-9dcd-3cd8e0e2d6dc','遠齋','釋道潜','宋','宋诗','song-poetry','','[]','君不見崑崙之河與天通，源深發遠人莫窮。',147,'全唐诗/poet.song.52000.json','["君不見崑崙之河與天通，源深發遠人莫窮。", "回溪轉壑隨折衝，末勢演溢流于東。", "東溟無旁下無底，浩蕩足以家魚龍。", "嗟哉吾徒雖好學，詎肯著意推所從。", "淵停富滀有若是，孰謂世上無豪雄。", "法師名齋意且遠，張皇幽眇見爾聰。", "西來竺書五千軸，期子歲月加磨礱。", "離騷楚詞亦謾讀，言語黼黻何必工。", "禪餘習氣如未盡，時倚澗石吟松風。"]'),
('8d851909-20de-4407-8dc6-bc871e9200ea','懷仙閣','釋道潜','宋','宋诗','song-poetry','','[]','瀛洲仙人騎皓鶴，珮玉鳴風度寥廓。',96,'全唐诗/poet.song.52000.json','["瀛洲仙人騎皓鶴，珮玉鳴風度寥廓。", "錦溪南望九仙岑，笑指烟霞憩曾閣。", "閣中清絕無纖塵，銅鑪著香夜夢真。", "平明跨鶴出山去，澗草巖花空自春。", "山僧問我入何地，今作玉皇香案吏。", "挾持造化幾時還，搔首臨風聊一喟。"]'),
('3d3ce279-aca7-4828-b65f-b5f8f90cf546','華亭道中','釋道潜','宋','宋诗','song-poetry','','[]','白水茫茫天四空，黄昏小雨濕春風。',32,'全唐诗/poet.song.52000.json','["白水茫茫天四空，黄昏小雨濕春風。", "五更百舌催殘夢，月到官河柳影中。"]'),
('9d363a0f-5e12-4550-983c-0016736e9155','同周元翁著作范明遠祕校西湖夜泛各賦一首','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','薄雲疏雨作還休，白帝撩人巧變秋。',64,'全唐诗/poet.song.52000.json','["薄雲疏雨作還休，白帝撩人巧變秋。", "天地此身均逆旅，江湖幾度共離憂。", "暮聲斷續鐘連磬，夜氣浮沈浦與洲。", "圓嶠方壺吾未羨，敢煩騷客爲冥搜。"]'),
('dc3d8d66-6187-4d3f-9c09-023bf3fd246d','和元翁','釋道潜','宋','宋诗','song-poetry','','[]','高論每逢賢友生，還如講武得奇兵。',64,'全唐诗/poet.song.52000.json','["高論每逢賢友生，還如講武得奇兵。", "了無鄙吝胸中物，尚有風流世外情。", "破海玉蟾初未躍，洒空珠露已先傾。", "回橈轉柂行三鼓，始見波瀾百頃明。"]'),
('dc740a85-105f-43cc-b935-d7ec14b6f3fb','和明遠','釋道潜','宋','宋诗','song-poetry','','[]','二客風神瑩石泉，解衣同緩夜歸船。',64,'全唐诗/poet.song.52000.json','["二客風神瑩石泉，解衣同緩夜歸船。", "已殘巾子峰頭日，猶認吾廬竹外烟。", "水怪有名殊未見，犀燈無事不須然。", "月明幽渚蒹葭靜，珍重沙禽穩睡眠。"]'),
('8ed44dbe-dfb4-4856-a638-a9f798358f38','次韵月上人秋夜見寄','釋道潜','宋','宋诗','song-poetry','','[]','冥鴻振鷺想儀形，數日新秋入夢清。',64,'全唐诗/poet.song.52000.json','["冥鴻振鷺想儀形，數日新秋入夢清。", "丹壑流泉依舊否，碧巖叢桂幾時生。", "風來玉戶凉初集，露泫銀河色漸明。", "黽勉酬君無妙語，夜光魚目愧相并。"]'),
('b84a5323-c93a-4664-a728-a0bc20d10760','送遠上人還金華','釋道潜','宋','宋诗','song-poetry','','[]','千林脫葉送殘秋，一舸南歸興莫留。',64,'全唐诗/poet.song.52000.json','["千林脫葉送殘秋，一舸南歸興莫留。", "富渚江平非白馬，子陵灘穩異黄牛。", "吟懷覽勝宜無倦，才力如君豈易求。", "他日殷勤爲細字，盡傳佳句到東州。"]'),
('6ba308ba-ec0f-4015-845a-1fe973527d10','與愚上人宿天竺  其一','釋道潜','宋','宋诗','song-poetry','','[]','夕陽山氣藹葱葱，路轉松陰複幾重。',32,'全唐诗/poet.song.52000.json','["夕陽山氣藹葱葱，路轉松陰複幾重。", "行過石橋人未見，數聲先聽寺樓鍾。"]'),
('a219fdee-e070-4c4e-b86c-570206aa5476','與愚上人宿天竺  其二','釋道潜','宋','宋诗','song-poetry','','[]','稽留峰北好林泉，珍重幽棲得所便。',32,'全唐诗/poet.song.52000.json','["稽留峰北好林泉，珍重幽棲得所便。", "栢子烟中能宴坐，想無餘習可攀緣。"]'),
('9af8408a-908e-4381-bd88-526d6d769579','與愚上人宿天竺  其三','釋道潜','宋','宋诗','song-poetry','','[]','霜壓簾櫳露泫條，銀河影轉斗垂杓。',32,'全唐诗/poet.song.52000.json','["霜壓簾櫳露泫條，銀河影轉斗垂杓。", "清言共失三更夢，錯恨芙蓉漏易消。"]'),
('6c6bed93-97cd-40e5-b439-b7d091d2086e','晨起','釋道潜','宋','宋诗','song-poetry','','[]','猿鶴驚呼曉，樓鐘動翠微。',24,'全唐诗/poet.song.52000.json','["猿鶴驚呼曉，樓鐘動翠微。", "楓林墮清月，疏影亂人衣。"]'),
('6a7f4b7b-f99f-48f8-8ba8-53900cf07a13','喜不群不疑見訪','釋道潜','宋','宋诗','song-poetry','','[]','鵲啅庭梧喜滿懷，懸知二子下崔嵬。',32,'全唐诗/poet.song.52000.json','["鵲啅庭梧喜滿懷，懸知二子下崔嵬。", "山中爽氣知多少，半逐風流杖屨來。"]'),
('b1714a94-090d-42f7-856a-cc535fa9b53c','送桐江明上人之都下','釋道潜','宋','宋诗','song-poetry','','[]','窈窕孤雲下翠岑，帝鄉閑去本無心。',32,'全唐诗/poet.song.52000.json','["窈窕孤雲下翠岑，帝鄉閑去本無心。", "紅塵滿眼急回首，莫遣空山鶴怨深。"]'),
('75cfb0ee-38e1-4c86-8cea-3772fc5f4350','送定上人還會稽','釋道潜','宋','宋诗','song-poetry','','[]','西風警群木，蕭瑟散秋聲。',48,'全唐诗/poet.song.52000.json','["西風警群木，蕭瑟散秋聲。", "病客有歸思，孤雲無戀情。", "月當千里共，人恨四難并。", "苦學誰如子，它年在一鳴。"]'),
('64b23b76-969d-4904-bece-b2354f8ba49f','次韵劉蔡仲秀才雪後登竹閣  其一','釋道潜','宋','宋诗','song-poetry','','[]','檻前君子舊虛心，雪後相看意更深。',32,'全唐诗/poet.song.52000.json','["檻前君子舊虛心，雪後相看意更深。", "晴日暖風催鳥語，翠梢高處囀柔音。"]'),
('7907310f-0f56-4d1d-a634-3f85500e2a72','次韵劉蔡仲秀才雪後登竹閣  其二','釋道潜','宋','宋诗','song-poetry','','[]','君看楚嶠聳巑岏，圭壁千層間翠嵐。',32,'全唐诗/poet.song.52000.json','["君看楚嶠聳巑岏，圭壁千層間翠嵐。", "山後一峰尤秀拔，依稀還落剡溪南。"]'),
('c3542416-1188-404c-86c1-ecc54a24d3b1','次韵黄仲閔主簿見訪游寶雲諸寺','釋道潜','宋','宋诗','song-poetry','','[]','吾廬附曾阿，松竹蔚行路。',132,'全唐诗/poet.song.52000.json','["吾廬附曾阿，松竹蔚行路。", "平生土木軀，羞爲折腰具。", "蓼蟲甘苦澀，雖死那求遇。", "黄香諸父賢，傾蓋如有素。", "相將山水行，所適得佳趣。", "觀臺深且靚，縞壁懸清句。", "雲巢倚空端，下覽宜細顧。", "樓臺霽雪初，碧瓦塵未涴。", "籃輿指頹景，長挹還辭去。", "怳如山陰集，俛仰已成故。", "重來竟何時，相望碧雲暮。"]'),
('97d12c56-2c31-4ffe-947b-677a95bbf6ce','蘇世美夫人挽辭','釋道潜','宋','宋诗','song-poetry','','[]','夫子剛中早數奇，閨門高節聳當時。',64,'全唐诗/poet.song.52000.json','["夫子剛中早數奇，閨門高節聳當時。", "淵明晚欲歸三徑，德曜能從賦五噫。", "不見萊衣華髮事，空驚薤露昔人悲。", "故知造物酬陰施，玉立諸郎富白眉。"]'),
('920a3f01-f26f-42c9-8f80-ada3973f53b3','重居夜坐懷蘇伯達昆仲','釋道潜','宋','宋诗','song-poetry','','[]','狂風吹林聲怒號，隔垣洶洶如秋濤。',64,'全唐诗/poet.song.52000.json','["狂風吹林聲怒號，隔垣洶洶如秋濤。", "夜闌稍覺群動息，星斗挂簷霜月高。", "東鄰書生勤且勞，粲然文采真鳳毛。", "遙想下帷應未寢，短檠相對課離騷。"]'),
('9c6889dd-088f-4ab3-940c-a3559704b54b','慕容居士雙柟軒','釋道潜','宋','宋诗','song-poetry','','[]','陽羨溪山名浙右，氤氳淑氣無時有。',131,'全唐诗/poet.song.52000.json','["陽羨溪山名浙右，氤氳淑氣無時有。", "遂令比屋慕弦歌，甲第殊科爭捷手。", "先生讀書三十年，數奇不偶真可憐。", "閉門陋巷聊自隠，簞瓢屢空心晏然。", "南軒前頭兩佳木，先生撫玩長不足。", "尤愛薰風五月初，白銀開花光照屋。", "故人解后相逢遇，指點婆娑索新句。", "君不見少陵杜叟有長吟，莫作凡材等閑賦。"]'),
('17c49495-b02d-4832-ae6c-76005318b658','次韵蘇端明定武雪浪齋','釋道潜','宋','宋诗','song-poetry','','[]','孔明氣宇白玉溫，忠義勇决踰王尊。',160,'全唐诗/poet.song.52000.json','["孔明氣宇白玉溫，忠義勇决踰王尊。", "葛巾羽扇傳號令，塞垣徹警無塵昏。", "良辰往往挾將佐，射鵰走馬循烟村。", "歸來飲酒坐堂上，賓從如雲填戟門。", "一朝郡圃得奇石，雪浪觸眼驚神魂。", "旁求蒼珉琢巨斛，偃然臥土知無根。", "三牛曳歸置階圯，錯磨不許留纖痕。", "興來作詩寄臺閣，雄詞妙筆爭考論。", "將軍今謫窮海外，會見羲娥窺覆盆。", "殷勤寄語朔方客，佳致勿毀宜長存。"]'),
('91f4c1cd-06e4-4cee-8387-065dcad8a446','無爲堂','釋道潜','宋','宋诗','song-poetry','','[]','無爲豈不動，無念非刳心。',72,'全唐诗/poet.song.52000.json','["無爲豈不動，無念非刳心。", "至人均道妙，與物相浮沉。", "青銅一寸明，萬象了自分。", "何須苦機械，擾擾亂沖襟。", "晴窗馥烟篆，衣裓蒙餘薰。", "超然曠士懷，所得踰古今。"]'),
('57248e93-5e36-4a33-ad00-17837cb6bee3','示法穎','釋道潜','宋','宋诗','song-poetry','','[]','兒曹汝既識薰蕕，卓犖應須力自修。',64,'全唐诗/poet.song.52000.json','["兒曹汝既識薰蕕，卓犖應須力自修。", "一志徑從齊客語，萬端無受楚人咻。", "卑飛燕雀宜深遠，高舉鸞凰可並游。", "莫負謫仙當日語，十年名譽滿東州。"]'),
('5b3b3a6b-7363-476f-aafc-c48f1698a41b','清聚軒','釋道潜','宋','宋诗','song-poetry','','[]','之子吟懷欲稱情，故穿幽沼滀清泠。',32,'全唐诗/poet.song.52000.json','["之子吟懷欲稱情，故穿幽沼滀清泠。", "儻逢來客議深淺，但道淵源通北溟。"]'),
('07f38ebd-036f-42c8-a6e5-74dd1b81b3c8','次韵曉師見別欲游京洛','釋道潜','宋','宋诗','song-poetry','','[]','春波漲南浦，霽色媚澄鮮。',96,'全唐诗/poet.song.52000.json','["春波漲南浦，霽色媚澄鮮。", "扁舟駕兩槳，行矣子所便。", "岸花開迤邐，紅紫交相妍。", "詩情發浩蕩，輸瀉萬壑淵。", "清新逼庾信，雅健追樊川。", "相儔得鴻鵠，翔集固超然。", "衣裓暫塵土，它時洗雲泉。", "幽姿復烱烱，不羨玉池蓮。"]'),
('dd9f81e0-ad3c-44ec-bc61-db8efb4ef1e2','游徑山懷司馬才仲','釋道潜','宋','宋诗','song-poetry','','[]','柔桑蔽野麥初齊，布穀催耕雨一犂。',64,'全唐诗/poet.song.52000.json','["柔桑蔽野麥初齊，布穀催耕雨一犂。", "略彴時橫溪上下，薔薇間發水東西。", "重尋勝處追前賞，無復斯人手共携。", "回首春風增感慨，綿綿黄鳥更悲啼。"]'),
('01dd46b5-dc01-4039-b7b0-b9e8a56133ac','雲巢  其一','釋道潜','宋','宋诗','song-poetry','','[]','環湖相望百招提，高棟曾軒亦屢躋。',32,'全唐诗/poet.song.52000.json','["環湖相望百招提，高棟曾軒亦屢躋。", "未若道人基構勝，闌干清與白雲齊。"]'),
('0bf35857-b5af-498d-b261-fb020895355d','雲巢  其二','釋道潜','宋','宋诗','song-poetry','','[]','九江秀色可攬結，謫仙愛彼巢雲松。',32,'全唐诗/poet.song.52000.json','["九江秀色可攬結，謫仙愛彼巢雲松。", "寂寞風流三百載，此軒奇觀躡前蹤。"]'),
('6835a353-a8cd-4c62-b0bc-eb5b8641064d','雲巢  其三','釋道潜','宋','宋诗','song-poetry','','[]','碧瓦朱甍冠翠微，鬰葱佳氣繚窗扉。',32,'全唐诗/poet.song.52000.json','["碧瓦朱甍冠翠微，鬰葱佳氣繚窗扉。", "人間塵土紛阡陌，不到藜床燕坐衣。"]'),
('312d0a35-d491-4229-8d04-5592ffaf0180','清明日湖上呈秦少章主簿','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','水邊花霧曉氤氳，春入西湖兩岸深。',64,'全唐诗/poet.song.52000.json','["水邊花霧曉氤氳，春入西湖兩岸深。", "冶葉倡條他自媚，朽株枯木我何心。", "鞦韆索轉朱樓角，博塞聲喧碧柳陰。", "年少故人方感慨，未應從俗强浮沉。"]'),
('ea752a09-2f2c-4315-8bed-6ac97af22e26','送誠無上人還洞山文禪師席下','釋道潜','宋','宋诗','song-poetry','','[]','上人妙齒遺樊籠，嗜好豈與稠人同。',160,'全唐诗/poet.song.52000.json','["上人妙齒遺樊籠，嗜好豈與稠人同。", "巖棲水飲有餘裕，期以至道超鴻蒙。", "少林人亡僅千載，末路鼓舞誰爲雄。", "江西老褐真望士，蟻趨雲合爭所從。", "羨君伏役事且久，誠專志苦迷春冬。", "心珠磨錯稍精瑩，彷彿水月含沖融。", "去歲扁舟下吳會，溪山勝踐情所鍾。", "芒鞋竹杖霜露入，始知節物徂秋風。", "朝來興盡挽不住，翻然又逐南征鴻。", "它年相逢定廬岳，與子終老巢雲松。"]'),
('3873027a-8d50-45e4-b0ca-52c398d89ec3','燕默堂','釋道潜','宋','宋诗','song-poetry','','[]','萬彙乾坤裏，誰何識道真。',48,'全唐诗/poet.song.52000.json','["萬彙乾坤裏，誰何識道真。", "喧卑憎末俗，燕默羨高人。", "漏轉芙蓉永，香銷栢子頻。", "他年揮玉麈，堂上挹芳塵。"]'),
('9c274fc9-52e4-4e07-bcca-f2bebc6d0dbe','送嚴上人還永嘉','釋道潜','宋','宋诗','song-poetry','','[]','道人出處孤鴻儔，詎肯低回受羈絆。',96,'全唐诗/poet.song.52000.json','["道人出處孤鴻儔，詎肯低回受羈絆。", "飄風轉日歷九州，不羨騎鯨游汗漫。", "我生與君幾相逢，窮幽摘勝時乃同。", "胸中妙道未容扣，又引高興辭秋風。", "君家住在孤嶼側，此別何時見顔色。", "欲識相思一寸心，冷月依依挂空碧。"]'),
('f80d7ad1-a1df-4891-aba4-eadbd5829b59','吳門獄中懷北山舊隠  其一','釋道潜','宋','宋诗','song-poetry','','[]','江湖堂北是吾廬，繚繞杉篁蔚有餘。',32,'全唐诗/poet.song.52000.json','["江湖堂北是吾廬，繚繞杉篁蔚有餘。", "欲問山中近消息，鱗鴻不寄獄中書。"]'),
('c00d7388-f1e6-4133-8a37-cc9dc556af69','吳門獄中懷北山舊隠  其二','釋道潜','宋','宋诗','song-poetry','','[]','誅茅投老卜栖遲，雲雨相翻豈易知。',32,'全唐诗/poet.song.52000.json','["誅茅投老卜栖遲，雲雨相翻豈易知。", "夜鶴曉猿休悵望，回車復路可無時。"]'),
('d06d0b9b-d6bf-4cb7-8405-8b0a4124cc7e','吳門獄中懷北山舊隠  其三','釋道潜','宋','宋诗','song-poetry','','[]','數畝檀欒古道邊，亭亭氣慨上參天。',32,'全唐诗/poet.song.52000.json','["數畝檀欒古道邊，亭亭氣慨上參天。", "未應霜雪能摧抑，不用行人歎可憐。"]'),
('6a2fb035-29b4-4129-ba4e-917467352444','吳門獄中懷北山舊隠  其四','釋道潜','宋','宋诗','song-poetry','','[]','東崦扶疏一樹梅，繁英辜負歲時開。',32,'全唐诗/poet.song.52000.json','["東崦扶疏一樹梅，繁英辜負歲時開。", "殷勤寄語蘭兼蕙，它日春風我亦來。"]'),
('16220051-b750-4981-a115-c3f8aae69630','吳門獄中懷北山舊隠  其五','釋道潜','宋','宋诗','song-poetry','','[]','甘冷宜茶石縫泉，得名初自玉堂仙。',32,'全唐诗/poet.song.52000.json','["甘冷宜茶石縫泉，得名初自玉堂仙。", "蒼苔滓穢聊疏治，照月涵星復粲然。"]'),
('26bddfbf-4cf1-4895-96c7-6a9ade40a0ba','吳門獄中懷北山舊隠  其六','釋道潜','宋','宋诗','song-poetry','','[]','一徑緣雲入壽星，竹間窈窕見疏櫺。',32,'全唐诗/poet.song.52000.json','["一徑緣雲入壽星，竹間窈窕見疏櫺。", "闌干數曲觀臺上，幽草靚花常滿庭。"]'),
('db2816a4-45e3-4129-a359-5b65e99abaa5','吳門有懷錢塘何彥時仙尉  其一','釋道潜','宋','宋诗','song-poetry','','[]','英妙何郎藴德光，不隨人世事炎凉。',32,'全唐诗/poet.song.52000.json','["英妙何郎藴德光，不隨人世事炎凉。", "麒麟步武開天上，他日青雲道路長。"]'),
('9dc6ba79-f68b-441a-a0c1-c7be1050d5cc','吳門有懷錢塘何彥時仙尉  其二','釋道潜','宋','宋诗','song-poetry','','[]','英游閣前官柳行，柔枝嫋嫋弄鵝黄。',32,'全唐诗/poet.song.52000.json','["英游閣前官柳行，柔枝嫋嫋弄鵝黄。", "多情春色還依舊，獨有離人天一方。"]'),
('533e3547-ad34-4602-b171-f121294c0b7e','吳門有懷錢塘何彥時仙尉  其三','釋道潜','宋','宋诗','song-poetry','','[]','湖岸茸茸細草生，芳洲杜若想縱橫。',32,'全唐诗/poet.song.52000.json','["湖岸茸茸細草生，芳洲杜若想縱橫。", "去年問柳尋花地，誰伴穿雲渡水行。"]'),
('c326ccd2-42ca-4a71-80cd-87d6c27d2259','劉咸臨秀才挽詞  其一','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','劉子江南英，韵勝不友俗。',84,'全唐诗/poet.song.52000.json','["劉子江南英，韵勝不友俗。", "閉門誦詩書，戶外無來躅。", "昔我寄匡山，巖扉屏幽獨。", "君聞跨蹇馿，迢迢訪深谷。", "忘懷去畦畛，結好比松竹。", "浮雲事忽空，逝水難再復。", "徒有篋中文，千秋成鬼錄。"]'),
('0824cb52-5e2e-4534-b24c-eb2801b97612','劉咸臨秀才挽詞  其二','釋道潜','宋','宋诗','song-poetry','','[]','異材擢陽阿，秀色方蔚然。',60,'全唐诗/poet.song.52000.json','["異材擢陽阿，秀色方蔚然。", "侵尋掩衆阜，屹屹上造天。", "驚飈忽摧殞，中道虛棄捐。", "顔淵古稱夭，道德今獨妍。", "何求擁腫爲，無用徒永年。"]'),
('ab1858d9-c332-41b6-8123-3985f8652792','劉咸臨秀才挽詞  其三','釋道潜','宋','宋诗','song-poetry','','[]','平生本家學，耻作干時語。',72,'全唐诗/poet.song.52000.json','["平生本家學，耻作干時語。", "著書以愚名，綽欲慕前古。", "紛紛詆迂闊，默默君自許。", "弱齡詠風騷，其詞哀以苦。", "先生歎奇作，壽達終難與。", "果爲冥冥游，一往不可睹。"]'),
('5e61c7d8-bbf9-4a9b-9e6f-f0fe2adabc51','劉咸臨秀才挽詞  其四','釋道潜','宋','宋诗','song-poetry','','[]','吾希李長吉，異代不得友。',96,'全唐诗/poet.song.52000.json','["吾希李長吉，異代不得友。", "頼餘錦囊篇，把玩時在手。", "斯人君並駕，未易較先後。", "肝脾裹陽秋，落筆粲瓊玖。", "當年邂逅初，宛在三峽右。", "相携石橋行，下瞰冰雪溜。", "音容俄永隔，山月空依舊。", "銘詩得黄香，知子垂不朽。"]'),
('1c4568aa-c673-49c8-b8d0-2e83e9967331','贈霍山人','釋道潜','宋','宋诗','song-poetry','','[]','先生少年喜武事，三略六韜曾徧閱。',208,'全唐诗/poet.song.52000.json','["先生少年喜武事，三略六韜曾徧閱。", "胸中雲夢吞八九，氣勝萬夫真勇决。", "防邊伊昔從都護，欲取功名繼前烈。", "臂弓腰箭事戎裝，遠出砂場恣游獵。", "擒狐射雁狂且逸，不覺歸途迷夜雪。", "敗官遭譴失所志，回首飄然辭魏闕。", "挾持妙術當生涯，放浪江湖閑歲月。", "尋常得錢即沽酒，笑與妻奴同飲啜。", "樂天知命了無憂，奕奕紅顔浮兩頰。", "春風浩蕩魯城邊，稠花亂蕊爭紛妍。", "方將與君共携手，騁懷游目相回旋。", "興來別我汶陽去，黄鵠一舉難留連。", "村橋野店醉斜日，路人誰識地行仙。"]'),
('46acb78f-14d5-48c2-b447-39d9f42a45ec','送劉不已推官罷奉符尉入都注擬','釋道潜','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','少年讀書破萬卷，河朔聲名壓諸彥。',160,'全唐诗/poet.song.52000.json','["少年讀書破萬卷，河朔聲名壓諸彥。", "詞場百戰功不成，晚得青衫非所願。", "白頭况有北堂親，斗祿强須甘冗賤。", "三年一尉泰山下，簿領區區事弓箭。", "追窮寇盜走山谷，肯爲風霜辭怯懦。", "要功冀賞本無心，脫去僅能逃所譴。", "草枯蓬斷歲將徂，結束行裝抵京縣。", "達官貴吏急賢材，一鶚君須預論薦。", "投竿舍築去作相，邂逅風雲一朝變。", "造物於人自有時，未足爲君生忿怨。"]'),
('ae769bd6-f5c1-4281-a9fc-c4918f2c5aea','過彭城觀陳傳道知錄所藏東坡公畫','釋道潜','宋','宋诗','song-poetry','','[]','枯株瘦石兩相望，南北悠悠徑路長。',32,'全唐诗/poet.song.52000.json','["枯株瘦石兩相望，南北悠悠徑路長。", "卷盡平岡三百里，風枝雨葉更飄揚。"]'),
('68369bef-5096-4db1-8725-30519618dd75','淮上觀水','釋道潜','宋','宋诗','song-poetry','','[]','桐柏崑崙日夜傾，投溪注壑本無情。',32,'全唐诗/poet.song.52000.json','["桐柏崑崙日夜傾，投溪注壑本無情。", "乍爲含垢千尋濁，不作矜人一掬清。"]'),
('63cec9a3-eaa9-49ee-8940-35c578ea3d31','戲書誠師秋景小屏','釋道潜','宋','宋诗','song-poetry','','[]','黄蘆敗葦兩三叢，彷彿江湖在眼中。',32,'全唐诗/poet.song.52000.json','["黄蘆敗葦兩三叢，彷彿江湖在眼中。", "雁鴨驚呼緣底事，一時昂首立秋風。"]'),
('53acd45a-19b6-4f3d-a864-71b2ec89ca39','過韞秀堂觀仲豫二詩因次其韵  其一','釋道潜','宋','宋诗','song-poetry','','[]','箕南斗北各殊方，誰信相思去夢長。',32,'全唐诗/poet.song.52000.json','["箕南斗北各殊方，誰信相思去夢長。", "蓬斷草枯當歲晏，寥寥空對蕙爐香。"]'),
('8acc4555-f502-45fc-9560-297c888cd4b5','過韞秀堂觀仲豫二詩因次其韵  其二','釋道潜','宋','宋诗','song-poetry','','[]','荆溪一別十年餘，流竄何嘗定所居。',32,'全唐诗/poet.song.52000.json','["荆溪一別十年餘，流竄何嘗定所居。", "等與山河同幻質，更將三界作蘧廬。"]'),
('aee8dc6f-e116-46a1-96ac-b1bec31f1ce3','次韵聰師見寄  其一','釋道潜','宋','宋诗','song-poetry','','[]','三年東魯貶，閉戶實超然。',48,'全唐诗/poet.song.52000.json','["三年東魯貶，閉戶實超然。", "靜極通幽眇，神游豈間焉。", "獨全霜後操，未異火中蓮。", "不似沈湘客，徒懷忿與悁。"]'),
('3825ee6a-eaf3-4c22-86d3-c06a0d47577d','次韵聰師見寄  其二','釋道潜','宋','宋诗','song-poetry','','[]','夙學誰知子，源流務所滋。',48,'全唐诗/poet.song.52000.json','["夙學誰知子，源流務所滋。", "風騷追五柳，禪寂擬長髭。", "桂魄元昭晰，浮雲自蔽虧。", "險夷終一節，吾以古爲師。"]'),
('26fa8caf-a46f-44a9-81c4-89ce22b422e2','次韵升師見招  其一','釋道潜','宋','宋诗','song-poetry','','[]','老去年光知幾尋，無端華髮苦相侵。',64,'全唐诗/poet.song.52000.json','["老去年光知幾尋，無端華髮苦相侵。", "獨憐碧眼平生舊，未改青松一寸心。", "欲扣禪關當歲晏，肯愁溪路隔雲深。", "相逢試探梅花信，應有香鬚擢碎金。"]'),
('b6a2557e-2c64-40c9-8505-904372c19417','次韵升師見招  其二','釋道潜','宋','宋诗','song-poetry','','[]','兒童牋管已能操，書乏吟窗幾兔毫。',64,'全唐诗/poet.song.52000.json','["兒童牋管已能操，書乏吟窗幾兔毫。", "文囿垣牆增漸廣，詞林枝葉勢方高。", "嗟余舊喜論周誥，晚歲無心諷楚騷。", "羨子得時勤述作，宛如秋浦湧雲濤。"]'),
('ca8b2313-0a51-4053-a2da-bf895fd28ae4','殘菊','釋道潜','宋','宋诗','song-poetry','','[]','霜摧露殞萬枝空，叢菊鮮鮮尚見容。',32,'全唐诗/poet.song.52000.json','["霜摧露殞萬枝空，叢菊鮮鮮尚見容。", "細蕊冷香聊自媚，無心引蝶更勾蜂。"]'),
('0bc38fa7-d2f1-45b3-87a9-dde67b54edcd','滌軒','釋道潜','宋','宋诗','song-poetry','','[]','隔雲穿竇引涓涓，噴玉跳珠亦可憐。',32,'全唐诗/poet.song.52000.json','["隔雲穿竇引涓涓，噴玉跳珠亦可憐。", "心垢本無何用滌，戲將萧洒度流年。"]'),
('21b610c7-18fd-4366-b9b9-153dd4afce4c','千頃廨院觀司馬才仲遺墨次韵','釋道潜','宋','宋诗','song-poetry','','[]','濛濛春雨暗村橋，竹裏禽啼婆餠焦。',64,'全唐诗/poet.song.52000.json','["濛濛春雨暗村橋，竹裏禽啼婆餠焦。", "度谷倦聞車軋軋，穿林愁聽馬蕭蕭。", "細窺陳迹僧坊靜，默想風流鄙吝消。", "浮魄沉魂今已矣，無人爲作楚詞招。"]'),
('8bd8350d-cc29-43bb-9965-15126f11703c','唐昌王悅道桃竹軒','釋道潜','宋','宋诗','song-poetry','','[]','餘杭門西山迤邐，屹屹千峰插天起。',112,'全唐诗/poet.song.52000.json','["餘杭門西山迤邐，屹屹千峰插天起。", "窮幽摘勝過三邑，隨處雲林皆可喜。", "邇來杖策到君家，始覺溪山逢骨髓。", "爭流萬壑會目前，競秀千巖對窗几。", "丹楓洗雨秋霽餘，白鳥出沒嵐光裏。", "主人韵勝無塵埃，翠竹紅桃相映栽。", "良辰樽俎憑誰共，友月朋雲自往來。"]'),
('eb44500e-cb40-4d0b-b561-7f67b2aca4bc','溪上','釋道潜','宋','宋诗','song-poetry','','[]','紅蓼叢邊雙鷺飛，波痕翻動碧琉璃。',32,'全唐诗/poet.song.52000.json','["紅蓼叢邊雙鷺飛，波痕翻動碧琉璃。", "須臾相趁却回首，斜立垂楊烟外枝。"]'),
('1453e3eb-8e87-4117-98d0-9d103ec3bbe0','聽盛道人琴  其一','釋道潜','宋','宋诗','song-poetry','','[]','陰雲收雨閣曾簷，寂寂西風不動簾。',32,'全唐诗/poet.song.52000.json','["陰雲收雨閣曾簷，寂寂西風不動簾。", "燒盡夜堂紅蠟炬，高山流水聽無厭。"]'),
('555fb91e-eaca-42e6-9bd9-f5628e499c33','聽盛道人琴  其二','釋道潜','宋','宋诗','song-poetry','','[]','有客浮游不定家，玉琴三尺當生涯。',32,'全唐诗/poet.song.52000.json','["有客浮游不定家，玉琴三尺當生涯。", "從來正始無人會，掉首高歌烏帽斜。"]'),
('8882f818-e5fc-406b-88af-743b1b0e5091','千頃山圓鏡堂呈應禪師','釋道潜','宋','宋诗','song-poetry','','[]','茲山嵯峨冠天下，一徑縈雲行兩舍。',208,'全唐诗/poet.song.52000.json','["茲山嵯峨冠天下，一徑縈雲行兩舍。", "始窮絕頂見招提，碧閣丹樓屹如畫。", "門前池水滀蜿蜒，座上風雷驚晝夜。", "峨眉五臺誇壯觀，品目真不此爲亞。", "偉哉南師非世人，開荒闢土初椎輪。", "寥寥相望三百載，廢興一一難具陳。", "丹丘大士來鼓舞，氣象煥發重增新。", "投金輸贐走南北，法雨所被無涯津。", "虛堂選勝得佳處，隆簷巨棟成逡巡。", "窗扉洞達舒兩目，異景錯出羅蓁蓁。", "朝雲夜月常萬頃，寒光炯炯如鎔銀。", "堂中隠几人何似，湛若玉毛懸秋旻。", "牓名圓鏡示來客，庶使方寸無緇磷。"]'),
('5ffb68ff-26de-43d3-a4ea-c9c49f5b96aa','沈道原養浩堂','釋道潜','宋','宋诗','song-poetry','','[]','塵勞萬計日紛紛，未礙堂中養浩心。',64,'全唐诗/poet.song.52000.json','["塵勞萬計日紛紛，未礙堂中養浩心。", "花草暗香來屋角，溪山爽氣入衣襟。", "樽中白酒無時有，篋裏清詩不廢吟。", "夜夜鄰家助幽致，數聲羌管弄微音。"]'),
('d93412a7-0c0e-4ac7-ab8d-91342ac4ac16','宣上人玉淵堂','釋道潜','宋','宋诗','song-poetry','','[]','玉淵閟蒼崖，源深杳難測。',92,'全唐诗/poet.song.52000.json','["玉淵閟蒼崖，源深杳難測。", "但見涓涓附籜龍，宛轉來投小池側。", "小池方折餘兩尋，蛙黽不游苔不侵。", "青天無雲落寒影，沈柔見底空人心。", "妙哉支公營小築，氣象蕭然真不俗。", "夜吟朝講度流年，何用崢嶸誇傑屋。"]'),
('fbf7a9af-1bb4-4f52-9ceb-407b6c279669','與定師話別六言  其一','釋道潜','宋','宋诗','song-poetry','','[]','客有來從東越，示余滿把瓊瑶。',28,'全唐诗/poet.song.52000.json','["客有來從東越，示余滿把瓊瑶。", "萬壑千巖鍾秀，故知多士翹翹。"]'),
('431827fb-e521-4bce-b1b2-d1e745569660','與定師話別六言  其二','釋道潜','宋','宋诗','song-poetry','','[]','雪解松筠振色，氣回蘭蕙含芳。',28,'全唐诗/poet.song.52000.json','["雪解松筠振色，氣回蘭蕙含芳。", "興動剡溪吟客，夢先歸鳥飛翔。"]'),
('c7288e13-2971-4346-b94e-34010b4d490f','與定師話別六言  其三','釋道潜','宋','宋诗','song-poetry','','[]','出海濤雷方震，橫江雪陣如山。',28,'全唐诗/poet.song.52000.json','["出海濤雷方震，橫江雪陣如山。", "一葉舟輕飛燕，飄然掠水東還。"]'),
('40d72b78-e524-46bd-9446-f91823d2f93f','與定師話別六言  其四','釋道潜','宋','宋诗','song-poetry','','[]','鳳咮山含暮靄，西陵月破黄昏。',28,'全唐诗/poet.song.52000.json','["鳳咮山含暮靄，西陵月破黄昏。", "慣作江湖離別，未應當此銷魂。"]'),
('5ed226f2-6a52-4b23-8be8-62de7a95db84','慧覺孜師綠筠軒','釋道潜','宋','宋诗','song-poetry','','[]','綠筠蕭蕭含爽籟，幽姿冷落人難愛。',160,'全唐诗/poet.song.52000.json','["綠筠蕭蕭含爽籟，幽姿冷落人難愛。", "壁間但有謫仙詞，聲名自到江湖外。", "當年創軒非壯觀，局促簾櫳日虧蔽。", "一朝經畫有底難，推倒牆頭了無礙。", "坐挹西南十里山，彩翠浮空屹相對。", "開池鑿圃增氣象，佳致真爲一方最。", "鳥聲鳴春春漸融，蘭芽蕙出初蒙茸。", "我來正值新雨定，弄日吹香聞座中。", "主人散策邀我步，池南池北聊從容。", "會待龍孫添夏蔭，借君此地眠清風。"]'),
('84223c54-f918-45f6-917a-5b90e6a9c50e','夏夜智果懷武康令毛澤民','釋道潜','宋','宋诗','song-poetry','','[]','暮磬寥寥殷上方，籠紗朱火影微茫。',64,'全唐诗/poet.song.52000.json','["暮磬寥寥殷上方，籠紗朱火影微茫。", "窗虛竹凈雨初闋，雲潤星輝夜更凉。", "落枕松聲驚瑟瑟，撲簾香霧靄蒼蒼。", "遙憐散髮東堂老，正臥風漪六尺床。"]'),
('666c12e2-b59a-4ec2-b060-c0e2c9df946a','寄宗室趙伯言朝請','釋道潜','宋','宋诗','song-poetry','','[]','趙侯天人裔，雅韵能拔俗。',168,'全唐诗/poet.song.52000.json','["趙侯天人裔，雅韵能拔俗。", "豈意江湖間，解后識眉目。", "高談爲余傾，落落如轉轂。", "端無貴富驕，但有文字欲。", "交游多望士，頡頏爭馳逐。", "艱難風義高，迹與古人續。", "銅章領劇邑，宛在江之曲。", "鳴弦陶永日，了不事鞭扑。", "新詩擬建安，簡遠詞不縟。", "錦囊有餘棄，示我僅盈軸。", "持還故山棲，把玩時反覆。", "美哉韶濩音，鏘然落巖谷。", "嗟余真淺陋，學海無一掬。", "仰君東溟深，短綆不可觸。"]'),
('edfe7d19-6c9d-45f7-bb4c-107d6f4f1d0f','讀東坡居士南遷詩','釋道潜','宋','宋诗','song-poetry','','[]','居士胸中真曠夷，南行萬里尚能詩。',64,'全唐诗/poet.song.52000.json','["居士胸中真曠夷，南行萬里尚能詩。", "牢籠天地詞方壯，彈壓山川氣未衰。", "忠義凜然剛不負，瘴烟雖苦力何施。", "往來慣酌曹溪水，一滴還應契祖師。"]'),
('dfbd4864-b1b5-40f0-a372-595c70e233e5','讀聞復詩卷','釋道潜','宋','宋诗','song-poetry','','[]','詩律久已廢，宏綱誰與操。',48,'全唐诗/poet.song.52000.json','["詩律久已廢，宏綱誰與操。", "斷弦那慮續，吾黨有英髦。", "氣穩侔彭澤，詞幽近楚騷。", "未輸湯從事，獨詫碧雲高。"]'),
('a6637b2e-6a3d-4f95-896f-dbadadcdd15d','次韵聞復廬山見懷','釋道潜','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','匡廬三載恣徜徉，肯憚衣裘弊雪霜。',64,'全唐诗/poet.song.52000.json','["匡廬三載恣徜徉，肯憚衣裘弊雪霜。", "學徹死生追粲忍，力窮騷雅陋齊梁。", "心源素與秋潭靜，定水寧同夏潦潢。", "邂逅逢余舊題墨，蘚封苔駮不成行。"]'),
('357585eb-fae5-4890-9016-079f65877d78','夏日寄愚坦二上人','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','仙潭從古水雲鄉，不羨西湖六月凉。',64,'全唐诗/poet.song.52000.json','["仙潭從古水雲鄉，不羨西湖六月凉。", "支港官河通市井，採菱拾翠有舟航。", "觚稜迥與星辰接，鐵鳳疑參鸛鶴翔。", "九夏登臨輸二子，一時摹寫付詩囊。"]'),
('780b8ccc-e33d-4895-bd58-b3a66d21755a','次韵聞復西湖夏日六言  其一','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','山水初無今古，人間自有沈浮。',28,'全唐诗/poet.song.52000.json','["山水初無今古，人間自有沈浮。", "試問行歌野老，桑麻用事何憂。"]'),
('649c2f8f-7ee3-44f0-8150-1fa26f0ba297','次韵聞復西湖夏日六言  其二','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','老葑年來席卷，吳儂舊恨彌申。',28,'全唐诗/poet.song.52000.json','["老葑年來席卷，吳儂舊恨彌申。", "昨夜馮夷鼓吹，遨嬉抵徹諸鄰。"]'),
('02cfd9ba-0b45-4685-aad0-f94440cebd4e','次韵聞復西湖夏日六言  其三','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','夜深一碧萬頃，彷彿明河接天。',28,'全唐诗/poet.song.52000.json','["夜深一碧萬頃，彷彿明河接天。", "岸曲風篁成韵，絕勝細管危弦。"]'),
('c1b84820-b8af-49cb-b11e-eb1d983a2492','次韵聞復西湖夏日六言  其四','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖清淺可泛，湍險豈類瞿塘。',28,'全唐诗/poet.song.52000.json','["西湖清淺可泛，湍險豈類瞿塘。", "隨處菰蒲蓮芡，櫛風沐雨尤香。"]'),
('db0f15fe-3044-4e1b-8b64-9ff2f3fd28a5','次韵聞復西湖夏日六言  其五','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','南窗寄傲一榻，午帳風來卷舒。',28,'全唐诗/poet.song.52000.json','["南窗寄傲一榻，午帳風來卷舒。", "懶躡子雲陳迹，解嘲更續成書。"]'),
('bcbe4b58-b5ca-4e5a-9e51-ddb7e330d44a','次韵聞復西湖夏日六言  其六','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','燒空火雲萬丈，氣焰信可流金。',28,'全唐诗/poet.song.52000.json','["燒空火雲萬丈，氣焰信可流金。", "嗟爾龜魚得計，適然游泳滋深。"]'),
('14461bbf-0ec6-4069-a532-a3fb47476dcf','次韵聞復西湖夏日六言  其七','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','櫟杜侵階美蔭，鳴蟬託質初凉。',28,'全唐诗/poet.song.52000.json','["櫟杜侵階美蔭，鳴蟬託質初凉。", "薰風正被草木，莫作秋聲感傷。"]'),
('7a0029ec-210f-40d0-ae25-970c935b74dc','次韵聞復西湖夏日六言  其八','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','柱礎爭流餘潤，油雲忽改山容。',28,'全唐诗/poet.song.52000.json','["柱礎爭流餘潤，油雲忽改山容。", "定有盲風怪雨，曉來已聽鼉龍。"]'),
('a1ff3673-ac39-4a2e-b4cd-d38f9bda537e','次韵聞復西湖夏日六言  其九','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湖光宛同玉鏡，隄柳閟若房櫳。',28,'全唐诗/poet.song.52000.json','["湖光宛同玉鏡，隄柳閟若房櫳。", "六月行人過此，未輸仙客壺中。"]'),
('54c1ed9e-9f01-45db-9919-616995787ea2','次韵聞復西湖夏日六言  其一○','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','河漢斗杓橫七，重城漏鼓傳三。',28,'全唐诗/poet.song.52000.json','["河漢斗杓橫七，重城漏鼓傳三。", "露鶴一聲何許，嘎然震響空巖。"]'),
('798d269d-976b-4507-8d4b-16d12193eb4e','夏夜偶興','釋道潜','宋','宋诗','song-poetry','','[]','微陽墮曾巘，歸翼投空林。',108,'全唐诗/poet.song.52000.json','["微陽墮曾巘，歸翼投空林。", "龕燈閟古殿，梵唄無餘音。", "眷茲石壁下，徐風散沖襟。", "缺月如斷環，依微挂松陰。", "清暉婉相屬，永夜諧吾心。", "空生大覺中，一漚示浮沉。", "此身漚中客，冥觀無古今。", "昔我嬰世故，紛紛那重陳。", "且求華胥夢，胡蝶相追尋。"]'),
('2ea2f14d-82c8-4193-975f-9357769c8326','次韵古上人湖上步月','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','尋常西湖月，雲霧多襲明。',120,'全唐诗/poet.song.52000.json','["尋常西湖月，雲霧多襲明。", "茲宵實昭晰，似慰詩人情。", "低昂見列宿，戢曜非光熒。", "起余二三子，微詠哦新聲。", "杖藜山前去，鷄犬寂不鳴。", "蘭皋宿鷺群，回首時自驚。", "君看南北山，氣象真崢嶸。", "參差烟樹叢，一一含餘清。", "上人江南秀，邂逅意所傾。", "夜闌勸復路，浩興殊未盈。"]'),
('575686c7-7820-4871-8cb0-8eedb199935a','臨江月上人','釋道潜','宋','宋诗','song-poetry','','[]','能仁說教滿竺乾，流入中國餘五千。',208,'全唐诗/poet.song.52000.json','["能仁說教滿竺乾，流入中國餘五千。", "於中妙經爲最勝，顗師所解尤通玄。", "化行吳會連海壖，紛紛得法如雲烟。", "見聞讀誦又其次，隨類譬率無間焉。", "嗚呼上人志且堅，善邀佛子同法筵。", "妙香炷爐馥旃檀，十科勸進追昔賢。", "旁行貝葉軸似椽，卷舒朝暮往復旋。", "利根微種聊窮研，魚兔一獲忘蹄筌。", "自餘區區顧未然，瀾翻口舌如湧泉。", "外物交錯心匪緣，功成一朝脫愛纏。", "曄如紅蕖濯清淵，俯仰千聖遽可肩。", "茫茫苦海旁無邊，不有舟栰誰能先。", "烏蟾疾馳如走丸，咨爾佛子無睡眠。"]'),
('479e27bd-d686-45ef-8520-35376013814d','琅琊山茶仙亭呈曾子開侍郎','釋道潜','宋','宋诗','song-poetry','','[]','滁山雖僻左，謫宦皆名臣。',192,'全唐诗/poet.song.52000.json','["滁山雖僻左，謫宦皆名臣。", "後先聞數公，卓然皆鳳麟。", "憶昨紹聖初，譴公俾省循。", "盛德忘怨悱，虛懷隨屈信。", "政成思覽眺，興與烟霞親。", "後車載鄒枚，主客驚路人。", "逶迤度山谷，導從屏所陳。", "漁樵許爭席，解后全天真。", "泠泠庶子泉，味壓康王珍。", "團團小圓月，色冠閩山春。", "白足相與飯，溪毛擷青芹。", "熊魚得兼美，樂事無涯津。", "花瓷勸引滿，疏瀹貫百神。", "危亭倚巖阿，榜額獨未新。", "牧之擅風流，茶仙誇絕倫。", "相望三百載，公能嗣芳塵。"]'),
('856e6d46-4527-447e-a581-9ff648265da8','送錢持正主簿西歸','釋道潜','宋','宋诗','song-poetry','','[]','蘭陵號多士，君實名家孫。',108,'全唐诗/poet.song.52000.json','["蘭陵號多士，君實名家孫。", "高才縻管庫，枳棘棲鴛鸞。", "一旦謝朱墨，超然整歸軒。", "迎秋餞伏初，炎威尚歊煩。", "松陵接苕霅，迤邐皆清源。", "舟子宜夜泛，蘋風生夢魂。", "回塘官柳行，千樹如雲屯。", "明河挂柳外，凉月低金盆。", "茲行信有得，它日爲余言。"]'),
('7118127e-180b-4034-a0a0-ac32af4cbc9d','寄子開內翰','釋道潜','宋','宋诗','song-poetry','','[]','天將有作會雲龍，一德君臣邂逅同。',64,'全唐诗/poet.song.52000.json','["天將有作會雲龍，一德君臣邂逅同。", "表率衣冠真領袖，羽儀臺閣舊家風。", "詞林豈獨專周誥，衮職深期補舜聰。", "四海滯淹公可棄，盡收鳬雁集庭中。"]'),
('4d3497cb-fc2b-410a-ab69-eb6665e383d0','贈潜照月師','釋道潜','宋','宋诗','song-poetry','','[]','吳興上人心志苦，筆研十年耕學圃。',176,'全唐诗/poet.song.52000.json','["吳興上人心志苦，筆研十年耕學圃。", "形癯骨瘦神獨清，耿若霜鷗立秋浦。", "錦囊新詩殊汗漫，妙語間發猶稽古。", "銖鋤冗長更磨揉，激濁疏清導靈府。", "自然韵勝遺島可，遠跂淵明追步武。", "瓶盂勸子適四方，莫學匏瓜甘墮窳。", "崇山廣澤徧游覽，始信憑高極天宇。", "蓺成技進蔚文采，楚楚華身竟何補。", "茫乎三界同傳舍，而我與君俱逆旅。", "不如回首依老褐，妙精明心求許與。", "鳴蟬委蛻藁壤餘，脫略秋風即高舉。"]'),
('b3dc33b7-cda4-44d8-a6fe-eff035db835d','垂慈堂木樨花','釋道潜','宋','宋诗','song-poetry','','[]','堂下高花屹兩株，繁英碎萼巧連茹。',64,'全唐诗/poet.song.52000.json','["堂下高花屹兩株，繁英碎萼巧連茹。", "猛香匪占春園盛，清烈仍分里巷餘。", "長抱秋蟾滋夜氣，偶摇風露墮階除。", "根盤厚地知方壯，封植何人考厥初。"]'),
('d7086475-7d7b-4a24-8c7a-9ff01fd77595','次韵關子容晚霽  其一','釋道潜','宋','宋诗','song-poetry','','[]','小院回廊明霽霞，疏簾未捲尚橫斜。',32,'全唐诗/poet.song.52000.json','["小院回廊明霽霞，疏簾未捲尚橫斜。", "應憐碧砌無塵滓，石竹紅薇靚有花。"]'),
('8d0d96cf-7ad1-467f-88f0-4b0469985d09','次韵關子容晚霽  其二','釋道潜','宋','宋诗','song-poetry','','[]','飛簾初遣雨師回，獨上江城百尺臺。',32,'全唐诗/poet.song.52000.json','["飛簾初遣雨師回，獨上江城百尺臺。", "萬景橫前方領略，越山仍欲送青來。"]'),
('31ff564e-0b28-46a2-a9e7-1926689f4aa2','再和湖上晚歸  其一','釋道潜','宋','宋诗','song-poetry','','[]','漾舟歸路興何賒，水樹低凉一道斜。',32,'全唐诗/poet.song.52000.json','["漾舟歸路興何賒，水樹低凉一道斜。", "菱蔓蒹葭都卷盡，芙蓉炯炯獨開花。"]'),
('8b7411e9-e235-400a-bb9c-148c94125ce3','再和湖上晚歸  其二','釋道潜','宋','宋诗','song-poetry','','[]','雲披霧卷仰昭回，試望翻經古石臺。',32,'全唐诗/poet.song.52000.json','["雲披霧卷仰昭回，試望翻經古石臺。", "應有秋香生桂樹，吹風肯傍暮船來。"]'),
('0fd1f8a4-16ea-492d-9ea8-9e86922cfa04','次韵子容同聖功見過  其一','釋道潜','宋','宋诗','song-poetry','','[]','檀欒小徑閟陰陰，解鞅停驂步更深。',32,'全唐诗/poet.song.52000.json','["檀欒小徑閟陰陰，解鞅停驂步更深。", "知我山栖久牢落，故留佳句比南金。"]'),
('c4056b98-3544-4c64-a34c-3cbdabb09ca2','次韵子容同聖功見過  其二','釋道潜','宋','宋诗','song-poetry','','[]','桃李君家世布陰，棣華雍穆義還深。',32,'全唐诗/poet.song.52000.json','["桃李君家世布陰，棣華雍穆義還深。", "浮雲百變何須怪，張耳陳餘舊斷金。"]'),
('edf49c5e-9815-47dc-a47b-bba13e96f956','續許元裕夢中作  其一','釋道潜','宋','宋诗','song-poetry','','[]','北窗支枕夢幽微，隠隠神明發暗機。',32,'全唐诗/poet.song.52000.json','["北窗支枕夢幽微，隠隠神明發暗機。", "未可病中驚老去，會須花底喚春歸。"]'),
('496828ec-c738-4d0c-bff1-e95407173d29','續許元裕夢中作  其二','釋道潜','宋','宋诗','song-poetry','','[]','琉璃雖破彩雲飛，演慶高門未易衰。',32,'全唐诗/poet.song.52000.json','["琉璃雖破彩雲飛，演慶高門未易衰。", "既有嘉祥能兆夢，定須他日産熊羆。"]'),
('fa354ed4-9c09-46f1-86a4-6e0f53f25d33','次韵聞復湖上秋日六言  其一','釋道潜','宋','宋诗','song-poetry','','[]','澤畔蒹葭蕭瑟，露華落日珠浮。',28,'全唐诗/poet.song.52000.json','["澤畔蒹葭蕭瑟，露華落日珠浮。", "撫事少陵多感，萬端獨立懷憂。"]'),
('5b34fa8e-ea1b-4b43-b633-5fbad0399c5d','次韵聞復湖上秋日六言  其二','釋道潜','宋','宋诗','song-poetry','','[]','禪餘偶登絕巘，據石聊爲欠申。',28,'全唐诗/poet.song.52000.json','["禪餘偶登絕巘，據石聊爲欠申。", "眼界謾分畦畛，誰知大道無鄰。"]'),
('20d98d6a-267c-4091-82d3-f969729cb7c9','次韵聞復湖上秋日六言  其三','釋道潜','宋','宋诗','song-poetry','','[]','楚客當年何苦，愁懷繚轉非舒。',28,'全唐诗/poet.song.52000.json','["楚客當年何苦，愁懷繚轉非舒。", "頼有管城公子，離騷萬恨能書。"]'),
('ed5b340a-1096-4ce1-b044-2f952203ba0b','次韵聞復湖上秋日六言  其四','釋道潜','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖發揮有素，最盛唯誇樂天。',28,'全唐诗/poet.song.52000.json','["西湖發揮有素，最盛唯誇樂天。", "遺愛到今不朽，長隄一道如弦。"]'),
('25da9dfb-4368-4694-9f56-c8ec0a2e0ef6','次韵聞復湖上秋日六言  其五','釋道潜','宋','宋诗','song-poetry','','[]','處士尚餘陳迹，斷碑橫臥林塘。',28,'全唐诗/poet.song.52000.json','["處士尚餘陳迹，斷碑橫臥林塘。", "婉約梅花秀句，騷人萬古傳香。"]'),
('43ad5aa7-2913-44c7-9909-392ef1e68c26','次韵聞復湖上秋日六言  其六','釋道潜','宋','宋诗','song-poetry','','[]','草蔓行將潰茂，菊英稍稍敷金。',28,'全唐诗/poet.song.52000.json','["草蔓行將潰茂，菊英稍稍敷金。", "南浦愁窺去燕，海山莽蒼雲深。"]'),
('dcef48e6-e953-42e7-9e97-58bedba55c6b','次韵聞復湖上秋日六言  其七','釋道潜','宋','宋诗','song-poetry','','[]','江城秋至幾日，風物斗覺凄凉。',28,'全唐诗/poet.song.52000.json','["江城秋至幾日，風物斗覺凄凉。", "鄰女機絲何有，夜聞促織悲傷。"]'),
('a0f074ca-1202-425f-98c4-6bc11ce2ab64','次韵聞復湖上秋日六言  其八','釋道潜','宋','宋诗','song-poetry','','[]','人物年來衰謝，背繩追曲周容。',28,'全唐诗/poet.song.52000.json','["人物年來衰謝，背繩追曲周容。", "嗟爾得時蝘蜓，故能嘲哂龜龍。"]'),
('6e1d78cc-2b52-4c21-9cd5-7e0b86053b1d','次韵聞復湖上秋日六言  其九','釋道潜','宋','宋诗','song-poetry','','[]','凉月娟娟清媚，舒光巧入簾櫳。',28,'全唐诗/poet.song.52000.json','["凉月娟娟清媚，舒光巧入簾櫳。", "萬籟聲同比竹，細窺一一空中。"]'),
('b388140e-766d-45f2-a3a0-4bd3320b2498','次韵聞復湖上秋日六言  其一○','釋道潜','宋','宋诗','song-poetry','','[]','可怪狙公巧黠，猶迷暮四朝三。',28,'全唐诗/poet.song.52000.json','["可怪狙公巧黠，猶迷暮四朝三。", "老我身如枯枿，兀然不動幽巖。"]'),
('97c14f1e-0c91-4722-b55f-f1e0939c9280','觀宗室趙明發使君所畫訪戴圖并二小詩因次其韵  其一','釋道潜','宋','宋诗','song-poetry','','[]','水石追摩詰，風騷類小山。',24,'全唐诗/poet.song.52000.json','["水石追摩詰，風騷類小山。", "每來窺二妙，戀戀欲忘還。"]'),
('52c6de67-e2c8-4d05-a112-57b3f1f2e6cc','觀宗室趙明發使君所畫訪戴圖并二小詩因次其韵  其二','釋道潜','宋','宋诗','song-poetry','','[]','巉絕千峰玉，清妍五字詩。',24,'全唐诗/poet.song.52000.json','["巉絕千峰玉，清妍五字詩。", "胸中盤爽氣，彷彿幾人知。"]'),
('0f781c0a-b702-4276-9de5-d04301460815','次韵樓試可承議見招','釋道潜','宋','宋诗','song-poetry','','[]','東州羈旅迹誰親，夫子端能給我貧。',64,'全唐诗/poet.song.52000.json','["東州羈旅迹誰親，夫子端能給我貧。", "默識松筠霜後操，靜看桃李夢中春。", "嵩陽勝絕高天下，縣令風流邁古人。", "待得芳菲開爛熳，去隨行樂後車塵。"]'),
('d10604ae-62ba-4ba9-8778-af6f4854a0e2','次韵秦少游學士  其一','釋道潜','宋','宋诗','song-poetry','','[]','數幅生綃上，形容萬態心。',24,'全唐诗/poet.song.52000.json','["數幅生綃上，形容萬態心。", "坐窺天下勝，何用遠登臨。"]'),
('020375f0-7c94-4aa8-a1c9-be5fe03248b3','次韵秦少游學士  其二','釋道潜','宋','宋诗','song-poetry','','[]','漠漠雲披岫，班斑雨弄晴。',24,'全唐诗/poet.song.52000.json','["漠漠雲披岫，班斑雨弄晴。", "橫江舟一葉，注目使人驚。"]'),
('0889e817-9ce4-41a0-9db1-6ad7c417feca','次韵秦少游學士  其三','釋道潜','宋','宋诗','song-poetry','','[]','陽秋閟肝膈，無處見微茫。',24,'全唐诗/poet.song.52000.json','["陽秋閟肝膈，無處見微茫。", "時作丹青戲，風流冠帝鄉。"]'),
('e4634a48-85b9-427e-ade0-c6d960df3145','次韵秦少游學士  其四','釋道潜','宋','宋诗','song-poetry','','[]','參差山接野，渺莽水連空。',24,'全唐诗/poet.song.52000.json','["參差山接野，渺莽水連空。", "笠釣沙頭客，真宜避世翁。"]'),
('a207e502-f7c3-49ac-8228-1bb161a33daa','春陰','釋道潜','宋','宋诗','song-poetry','','[]','浮雲易作雨無端，未放春泥十日乾。',32,'全唐诗/poet.song.52000.json','["浮雲易作雨無端，未放春泥十日乾。", "須信杏園憔悴煞，從來花骨不禁寒。"]'),
('4d3b2ada-aacc-4f41-97c0-1106defae834','次韵伯言明發登西樓望桃花  其一','釋道潜','宋','宋诗','song-poetry','','[]','江南梅子已生仁，京國桃花始放春。',32,'全唐诗/poet.song.52000.json','["江南梅子已生仁，京國桃花始放春。", "氣候不齊雖可恨，一枝猶得見牆闉。"]'),
('62b73d24-ca0e-45b1-acc7-496017ee98a4','次韵伯言明發登西樓望桃花  其二','釋道潜','宋','宋诗','song-poetry','','[]','小樓西望那人家，出屋香梢幾樹花。',32,'全唐诗/poet.song.52000.json','["小樓西望那人家，出屋香梢幾樹花。", "只恐東風能作惡，亂紅如雨墮窗紗。"]'),
('21b95b85-ee4e-4f9f-89e9-098f393c5feb','送伯言赴姑蘇上幕','釋道潜','宋','宋诗','song-poetry','','[]','都城公子海，賢否良難會。',132,'全唐诗/poet.song.52000.json','["都城公子海，賢否良難會。", "從容翰墨場，班班知所詣。", "超然三四公，詞學昔人配。", "源流出蘇黄，汲引功豈細。", "斯人固才華，氣節復遠邁。", "一官從幕府，未覺簿書礙。", "投刃却鳬行，岸巾依物外。", "凝香久寂寞，清絕今可繼。", "初辭廣陌塵，笑鼓春江枻。", "楚岫與吳山，相望挹空際。", "莫唱渭城歌，臨流增歎喟。"]'),
('a1e48bcb-51df-4129-98e7-e767f809e309','贈歐陽季默承議','釋道潜','宋','宋诗','song-poetry','','[]','先公跨箕尾，摇曳旋天關。',144,'全唐诗/poet.song.52000.json','["先公跨箕尾，摇曳旋天關。", "於今二紀餘，肯復來人間。", "時時對遺編，彷彿窺一斑。", "夢寐思見之，何從暫追攀。", "邇來都城裏，忽睹庭中蘭。", "方寸實驚喜，典刑斯可觀。", "抱疴一榻上，骨瘦清琅玕。", "爲余設幽几，氣貌徐以寬。", "微詞落玉麈，文彩真孔鸞。", "棣華惜未識，妙譽聞朝端。", "先公德未泯，四海共仰歎。", "願言付百世，清風嗣門闌。"]'),
('a3f7080b-d13f-47b1-a7fb-32286fd99c4e','次韵劉延中廷直見贈','釋道潜','宋','宋诗','song-poetry','','[]','劉郎世胄子，苦學窮淵源。',144,'全唐诗/poet.song.52000.json','["劉郎世胄子，苦學窮淵源。", "羞爲一掬清，欲效千丈渾。", "君看長鯨質，澗壑豈所存。", "操觚妙述作，斧鑿無纖痕。", "鍾牙不世出，審音誰復論。", "鵷鶵理勁翮，雲漢思孤鶱。", "上追鸞皇游，下棄燕雀喧。", "建安誇七子，壯氣君可吞。", "九衢苦昏霾，槐陰蔽重門。", "良辰爲我飯，滿案餘芳蓀。", "軟語夜達旦，未覺罷神魂。", "須知名教樂，不羨富貴尊。"]'),
('3a32a87c-5620-4ce4-9d1e-c9bfe205c4cd','酬劉巨載舍人見贈所畫山水扇','釋道潜','宋','宋诗','song-poetry','','[]','冰紈玉粉凈無塵，墨妙扶疏更絕倫。',32,'全唐诗/poet.song.52000.json','["冰紈玉粉凈無塵，墨妙扶疏更絕倫。", "試問揮毫底人物，不言從可識天真。"]'),
('4d613d56-5407-4552-89f0-56ba0861ff77','觀明發畫李賀高軒過圖','釋道潜','宋','宋诗','song-poetry','','[]','唐年茂宗枝，時平多俊良。',216,'全唐诗/poet.song.52000.json','["唐年茂宗枝，時平多俊良。", "長吉尤震曜，春林擢孤芳。", "退之於孔門，屹屹真棟梁。", "筆力障百川，風瀾息其狂。", "破衣繫麻鞋，右顧生輝光。", "一朝與湜輩，命駕驚煌煌。", "賀初爲兒童，隨父事迎將。", "須臾命賦詩，英氣加激昂。", "長安衆詞客，聲問爭推揚。", "風流垂異代，尚想古錦囊。", "君今亦宗英，韵勝斯人方。", "少年肯事事，苦學志獨强。", "風騷擬屈宋，妙處相頡頏。", "丹青出戲弄，配古猶擅場。", "形容示往事，彷彿如在旁。", "一徑入幽遠，古垣繚林莊。", "平橋跨淥水，叢薄含葱蒼。", "晴窗爲披拂，佳興杳難忘。"]'),
('983d66bc-29ff-4a32-9c94-a76ca654f5a7','次韵東坡居士過嶺','釋道潜','宋','宋诗','song-poetry','','[]','一時遷客盡難堪，二老高懷默自甘。',64,'全唐诗/poet.song.52000.json','["一時遷客盡難堪，二老高懷默自甘。", "造物定知還嶺北，暮年寧許喪天南。", "安排拄杖尋廬阜，斗藪征衣洗瘴嵐。", "他日相逢長夜語，殘燈飛燼落毿毿。"]'),
('4c2a64c2-e77a-441c-ac5e-dd8cbafdff8b','次韵代嶺上老人答','釋道潜','宋','宋诗','song-poetry','','[]','閑持箕箒掃崔嵬，夾道松陰盡我栽。',32,'全唐诗/poet.song.52000.json','["閑持箕箒掃崔嵬，夾道松陰盡我栽。", "人去人歸真一笑，壞空成住互輪回。"]'),
('5c41e762-87fc-461c-80dd-d63920db8a3c','次韵子由侍郎書事二首  其一','釋道潜','宋','宋诗','song-poetry','','[]','七年依嶺外，遇物即防閑。',48,'全唐诗/poet.song.52000.json','["七年依嶺外，遇物即防閑。", "宿負初償畢，他生豈復還。", "飄飄疑鶴骨，奕奕藹童顔。", "自許喬松壽，玄機密鎖關。"]'),
('ab9a06b2-2099-47c5-a0f7-6c90cab8ac64','次韵子由侍郎書事二首  其二','釋道潜','宋','宋诗','song-poetry','','[]','直材不易得，於國實長城。',48,'全唐诗/poet.song.52000.json','["直材不易得，於國實長城。", "造父還能御，驊騮豈憚行。", "買田鄰少室，爲計老餘生。", "居士來何晚，江淮遣候迎。"]'),
('ff14d6ad-7bad-4260-b473-7d96286766b6','次韵試可見訪峻極遇雨','釋道潜','宋','宋诗','song-poetry','','[]','都城塵土倦茫茫，獨喜西來策甚長。',64,'全唐诗/poet.song.52000.json','["都城塵土倦茫茫，獨喜西來策甚長。", "避暑禪房依亢爽，可人溪雨作清凉。", "飛蚊斗絕簷間鬧，乳燕時拳砌下篁。", "縣令風流真晉客，談餘玉麈自揮揚。"]'),
('3dbb74c9-db3f-4494-b93e-3f6be26f6533','揖仙亭','釋道潜','宋','宋诗','song-poetry','','[]','崧陽古令尹，製錦誇妙手。',120,'全唐诗/poet.song.52000.json','["崧陽古令尹，製錦誇妙手。", "鳴弦對高堂，坐使風俗厚。", "政成思考槃，觴豆宴賓友。", "開亭面緱嶺，佳致昔未有。", "雲烟靄葱曨，青壁冠星斗。", "王子果真仙，揖君千載後。", "鸞車駐縹緲，彷彿容暫偶。", "天風吹簫笙，凄響落戶牖。", "紛紛驚坐客，往往爲回首。", "相顧勿復言，且進杯中酒。"]'),
('54a73229-dcf2-4562-b8db-f5607a5c77f0','次韵試可同遊法王嶽寺','釋道潜','宋','宋诗','song-poetry','','[]','兩山脩徑盡榛蕪，謾詫當年幸翠輿。',64,'全唐诗/poet.song.52000.json','["兩山脩徑盡榛蕪，謾詫當年幸翠輿。", "空睹宸文藏寶構，不逢衲子話真如。", "林深想見靈根茂，地勝宜多隠者居。", "凉月照人歸路好，傍溪嘉樹影扶疏。"]'),
('6fd6bf07-baae-41a7-9e05-2c2eef4eaacd','次韵試可喜雨','釋道潜','宋','宋诗','song-poetry','','[]','東阡北陌久黄埃，天遣神龍詎用媒。',64,'全唐诗/poet.song.52000.json','["東阡北陌久黄埃，天遣神龍詎用媒。", "雲似濤頭山半起，雨如銀竹望中來。", "奔輸澗谷時頹岸，噴激龜魚或曝腮。", "民物有秋真可喜，池蓮從此更須栽。"]'),
('5ff4594d-d9e9-426c-be1a-b5a4f63a2629','峻極夏夜','釋道潜','宋','宋诗','song-poetry','','[]','廣庭無凡株，鬰鬰兩佳樹。',120,'全唐诗/poet.song.52000.json','["廣庭無凡株，鬰鬰兩佳樹。", "扶疏饒美蔭，盤錯根本固。", "朝披葉底風，夜泫衣上露。", "禪餘自循繞，百匝未忍住。", "月華中天來，左右發暉素。", "清景非人間，泠然洗吾慮。", "緬彼大梁下，炎蒸毒朝暮。", "朱門曉未開，馬足已馳騖。", "摧眉事權要，幸彼一盼顧。", "素標插君頭，擾擾獨不悟。"]'),
('cbb28183-83d7-4e70-8632-c322be2531bb','觀宗室曹夫人畫  其一','釋道潜','宋','宋诗','song-poetry','','[]','野水平林眇不窮，雪翻鷗鷺點晴空。',32,'全唐诗/poet.song.52000.json','["野水平林眇不窮，雪翻鷗鷺點晴空。", "洞房豈識江湖趣，意象冥將造化同。"]'),
('fd1dd5a0-61ad-4a57-941f-e125a0826075','觀宗室曹夫人畫  其二','釋道潜','宋','宋诗','song-poetry','','[]','華屋生知世胄榮，誰教天付與多能。',32,'全唐诗/poet.song.52000.json','["華屋生知世胄榮，誰教天付與多能。", "西風白草牛羊晚，隠見橫岡一兩層。"]'),
('0e348d0a-46fb-4408-900e-43c6314d1783','觀宗室曹夫人畫  其三','釋道潜','宋','宋诗','song-poetry','','[]','臨平山下藕花洲，旁引官河一带流。',32,'全唐诗/poet.song.52000.json','["臨平山下藕花洲，旁引官河一带流。", "雨棹風帆有無處，筆端須與細冥搜。"]'),
('59ed308a-8d0e-433f-a8b0-b25da40a6cf1','次韵陽翟尉黄天選見寄','釋道潜','宋','宋诗','song-poetry','','[]','寓形宇宙間，佚我方以老。',240,'全唐诗/poet.song.52000.json','["寓形宇宙間，佚我方以老。", "流光安足恃，百歲同過鳥。", "頃余嬰網羅，文彩緣自表。", "自古山林人，何曾識機巧。", "但記寒巖翁，論心秋月皎。", "黄香十年舊，學術參衆妙。", "虛懷養天和，肯徇奔走鬧。", "官居職事理，晨起何用早。", "桐陰滿西齋，叱吏供洒掃。", "眷余東南來，野飯煮芹藻。", "先生既清尚，令尹亦高蹈。", "相將古寺行，軟語頹晚照。", "公家有畸人，虛緣能自葆。", "卜築嵩山陽，行當從結好。", "山中饒勝境，一覽未易了。", "何時命巾車，共陟雲外嶠。", "翻愁筋力疲，不隨追勇踔。", "公詩擬南山，雄拔千丈峭。", "形容逼天真，解后適其要。", "藩籬吾未窺，敢議窮閫奧。"]'),
('6014b253-e941-40fe-a7a5-66abd79bd6b0','次韵試可嶽祠祭土宿齋','釋道潜','宋','宋诗','song-poetry','','[]','神祠齋館臥耽耽，五鼓星河屢起瞻。',64,'全唐诗/poet.song.52000.json','["神祠齋館臥耽耽，五鼓星河屢起瞻。", "劍珮森森趨帝右，衣冠肅肅奉宸嚴。", "風傳遠壑松千樹，人擁回廊月一簾。", "四嶽旌幢初會散，晨烏聲動廟竿尖。"]'),
('09134ef4-3633-44cb-9cdb-dbf8fbab32ac','贈宗室德强團練','釋道潜','宋','宋诗','song-poetry','','[]','造物賦象質，於余頗能名。',192,'全唐诗/poet.song.52000.json','["造物賦象質，於余頗能名。", "瓊瑶琢其骨，沖和擅其清。", "公生華屋貴，好學從妙齡。", "才高豈容遏，卓然以文鳴。", "厚德滋善養，雍容無暫矜。", "區區草茅人，未必真爾能。", "家藏三萬軸，插架連屋楹。", "牙籤示題目，探賾手不停。", "微言固澹泊，嗜好如飴餳。", "祖宗開鴻基，累聖致太平。", "詵詵既蕃衍，綽綽亦見稱。", "裕陵喜人物，教率從典刑。", "聯翩試文藝，議論參公卿。", "公材實杞梓，落落非杉檉。", "願言勤著書，會當補朝廷。", "他時樹勳業，彜鼎信可銘。"]'),
('e2449dfe-5a97-45d6-9584-e792848c9504','秋聲','釋道潜','宋','宋诗','song-poetry','','[]','古槐花落小中庭，夜半風來捲葉鳴。',32,'全唐诗/poet.song.52000.json','["古槐花落小中庭，夜半風來捲葉鳴。", "潁水先生如尚在，呼兒應問此何聲。"]'),
('fcd1ba47-8f2d-4c7c-adec-db20e654a0ce','次韵天選寄逍遙庵黄居士','釋道潜','宋','宋诗','song-poetry','','[]','收得詞場舉子身，拂衣高臥傍嶙峋。',64,'全唐诗/poet.song.52000.json','["收得詞場舉子身，拂衣高臥傍嶙峋。", "休言白日壺中勝，且看紅顔鏡裏春。", "富貴群爭雖有路，山林獨往豈無人。", "恐君未識陶彭澤，故約籃輿訪采真。"]'),
('b1db50bd-1d27-4abb-a77e-96fe52703dfd','次韵試可同謁子晉祠  其一','釋道潜','宋','宋诗','song-poetry','','[]','古栢連岡三萬株，朝烟破日翠扶疏。',32,'全唐诗/poet.song.52000.json','["古栢連岡三萬株，朝烟破日翠扶疏。", "投鞭下馬得幽徑，共謁賓天帝子居。"]'),
('acb4926a-668d-454e-9c59-e4aa40670729','次韵試可同謁子晉祠  其二','釋道潜','宋','宋诗','song-poetry','','[]','遺榮少海猛無雙，便逐浮丘出帝鄉。',32,'全唐诗/poet.song.52000.json','["遺榮少海猛無雙，便逐浮丘出帝鄉。", "可笑而今居富貴，亦思高舉上蒼蒼。"]'),
('a4ac0d79-a70a-44e4-8915-2281ab9d733c','哭少游學士  其一','釋道潜','宋','宋诗','song-poetry','','[]','江左有豪英，超驤世無倫。',228,'全唐诗/poet.song.52000.json','["江左有豪英，超驤世無倫。", "妙齡已述作，識造窮天人。", "儒林老先生，相與爲友賓。", "客來叩治亂，亹亹披霜筠。", "波瀾與枝葉，猶足誇後塵。", "青衫入仕初，十手爭扶輪。", "孤嘲可敵衆，志鬰不得信。", "造物念流落，薦收付洪鈞。", "干將不許就，中晝如有神。", "七年投炎荒，日與山鬼鄰。", "妻孥各異土，相望同參辰。", "秋風吹黄茅，八月瘴霧新。", "回車嬰重癘，惸惸無與親。", "中原尚杳隔，墳隴懷棘薪。", "凄凉浯水頭，魂逝歸無因。", "精爽竟了了，挽章見情真。", "流傳到京闕，悲讀聞縉紳。", "斯人儻不亡，光華國之珍。", "彼蒼未易曉，三歎鼻酸辛。"]'),
('f4f41738-6084-4498-a56b-dafebb08083e','哭少游學士  其二','釋道潜','宋','宋诗','song-poetry','','[]','念子少年日，豪氣吞九州。',144,'全唐诗/poet.song.52000.json','["念子少年日，豪氣吞九州。", "讀書知穾奧，游刃無全牛。", "當時所獻策，考致第一流。", "論高追賈誼，氣勝凌馬周。", "勝理非空文，灼可資廟謀。", "危根易摇動，謂子不好脩。", "嗚呼一齊人，柰彼衆楚咻。", "孔門餘四科，士豈一律求。", "區區事屠釣，崛起爲公侯。", "數奇信有命，君亦忘怨尤。", "平生所著書，字字鏗琳球。", "子道决不泯，千載傳芳猷。"]'),
('3db74287-3701-46aa-85ea-8e86358c29e1','哭少游學士  其三','釋道潜','宋','宋诗','song-poetry','','[]','瓶盂客京口，彷彿熙寧末。',192,'全唐诗/poet.song.52000.json','["瓶盂客京口，彷彿熙寧末。", "君方駕扁舟，歸來自苕霅。", "中泠忽相值，傾蓋忘楚越。", "禪揮龐老鋒，辯鼓子貢舌。", "連宵極名談，江閣倚清絕。", "扣檻出黿鼉，時取一笑發。", "邗溝介淮海，濟濟多俊傑。", "良辰苦招要，結好從此設。", "堂堂紫髯翁，道德冠前烈。", "風流廣文先，烱烱事脩潔。", "老禪魁叢林，冠蓋趨雜遝。", "三豪相繼往，墓木葉屢脫。", "子今復云亡，枯棋愈殘缺。", "相逢舊好間，悲詫那忍說。", "明年東下船，繫纜竹西月。", "茗奠蜀岡南，彈指當永訣。"]');
